'use strict';(function(){const indexCfg={cache:true};indexCfg.doc={id:'id',field:['title','content'],store:['title','href','section'],};const index=FlexSearch.create('balance',indexCfg);window.bookSearchIndex=index;index.add({'id':0,'href':'/docs/others/protocal/http/','title':"HTTP 协议",'section':"Protocal",'content':"http 协议 #  "});index.add({'id':1,'href':'/docs/others/protocal/rtsp/','title':"RTSP 协议",'section':"Protocal",'content':"RTSP 协议 #    RTSP RFC 协议 RTSP RFC 协议中文版\n 简介 #  rtsp 是一个tcp//ip协议中的应用层协议。\n#  "});index.add({'id':2,'href':'/docs/open_sources/retrofit/base/','title':"Retrofit - 大致流程源码解析",'section':"Retrofit",'content':"通过实际例子来分析阅读源码 #   Retrofit 的使用 可以看 这里\n 栗子 #  我们先举一个例子。这是我们定义的\npublic interface GitHubService { @GET(\u0026#34;users/{user}/repos\u0026#34;) Call\u0026lt;List\u0026lt;Repo\u0026gt;\u0026gt; listRepos(@Path(\u0026#34;user\u0026#34;) String user); } 这是我们常用的一个配置，添加了gson的转化器，和Rxjava的calladapter。\nRetrofit 将会提供一个 GitHubService 的实现\nRetrofit retrofit = new Retrofit.Builder() .addConverterFactory(GsonConverterFactory.create()) .addCallAdapterFactory(RxJavaCallAdapterFactory.creat()) .baseUrl(\u0026#34;https://api.github.com/\u0026#34;) .build(); GitHubService service = retrofit.create(GitHubService.class); GitHubService 提供的每一个 Call 都将提供 同步或者异步的api请求去请求http\nCall\u0026lt;List\u0026lt;Repo\u0026gt;\u0026gt; repos = service.listRepos(\u0026#34;octocat\u0026#34;);  到这里我就会疑惑retrofit自动生成的实例是什么样子的。我们点进去查看retrofit的create方法看一下\n 源码解析第一步-获取call #  create() #  public \u0026lt;T\u0026gt; T create(final Class\u0026lt;T\u0026gt; service)\npublic \u0026lt;T\u0026gt; T create(final Class\u0026lt;T\u0026gt; service) { validateServiceInterface(service); return (T) Proxy.newProxyInstance( service.getClassLoader(), new Class\u0026lt;?\u0026gt;[] {service}, new InvocationHandler() { private final Platform platform = Platform.get(); private final Object[] emptyArgs = new Object[0]; @Override public @Nullable Object invoke(Object proxy, Method method, @Nullable Object[] args) throws Throwable { // If the method is a method from Object then defer to normal invocation.  if (method.getDeclaringClass() == Object.class) { return method.invoke(this, args); } args = args != null ? args : emptyArgs; return platform.isDefaultMethod(method) ? platform.invokeDefaultMethod(method, service, proxy, args) : loadServiceMethod(method).invoke(args); } }); } 很明显这是一个动态代理。具体可以看 这里 所谓动态代理就是指方法被调用的时候都会回调到InvocationHandler方法里面。\n这段代码中的platform我们之后 再聊，先来看loadServiceMethod方法。\nServiceMethod -\u0026gt; loadServiceMethod #  ServiceMethod\u0026lt;?\u0026gt; loadServiceMethod(Method method) { // 做缓存，避免多次创建ServiceMethod，造成不必要的浪费。  ServiceMethod\u0026lt;?\u0026gt; result = serviceMethodCache.get(method); if (result != null) return result; synchronized (serviceMethodCache) { result = serviceMethodCache.get(method); if (result == null) { // 别的代码都是 缓存代码，关键点在这里  result = ServiceMethod.parseAnnotations(this, method); serviceMethodCache.put(method, result); } } return result; } 这是一个DCL的缓存形式，所以，我们需要关注的是 ServiceMethod.parseAnnotations里面内容。\nServiceMethod -\u0026gt; parseAnnotations #  abstract class ServiceMethod\u0026lt;T\u0026gt; { static \u0026lt;T\u0026gt; ServiceMethod\u0026lt;T\u0026gt; parseAnnotations(Retrofit retrofit, Method method) { RequestFactory requestFactory = RequestFactory.parseAnnotations(retrofit, method); Type returnType = method.getGenericReturnType(); if (Utils.hasUnresolvableType(returnType)) { throw methodError(method, \u0026#34;Method return type must not include a type variable or wildcard: %s\u0026#34;, returnType); } if (returnType == void.class) { throw methodError(method, \u0026#34;Service methods cannot return void.\u0026#34;); } return HttpServiceMethod.parseAnnotations(retrofit, method, requestFactory); } abstract @Nullable T invoke(Object[] args); } 这是一个虚类的定义，而 HttpServiceMethod 是他的一个实现类，我们先来看看HttpServiceMethod中parseAnnotations的实现\nHttpServiceMethod -\u0026gt; parseAnnotations #   这里我们先不考虑kotlin中suspend 方法的实现逻辑，只考虑纯Java的实现\n static \u0026lt;ResponseT, ReturnT\u0026gt; HttpServiceMethod\u0026lt;ResponseT, ReturnT\u0026gt; parseAnnotations( Retrofit retrofit, Method method, RequestFactory requestFactory) { boolean isKotlinSuspendFunction = requestFactory.isKotlinSuspendFunction; boolean continuationWantsResponse = false; boolean continuationBodyNullable = false; // 1.获取当前方法的所有注解  Annotation[] annotations = method.getAnnotations(); Type adapterType; if (isKotlinSuspendFunction) { /**/ } else { adapterType = method.getGenericReturnType(); } // 2.根据方法的返回值，创建一个一个call的适配器，其中包含了  CallAdapter\u0026lt;ResponseT, ReturnT\u0026gt; callAdapter = createCallAdapter(retrofit, method, adapterType, annotations); Type responseType = callAdapter.responseType(); if (responseType == okhttp3.Response.class) { throw methodError(method, \u0026#34;\u0026#39;\u0026#34; + getRawType(responseType).getName() + \u0026#34;\u0026#39; is not a valid response body type. Did you mean ResponseBody?\u0026#34;); } if (responseType == Response.class) { throw methodError(method, \u0026#34;Response must include generic type (e.g., Response\u0026lt;String\u0026gt;)\u0026#34;); } // TODO support Unit for Kotlin?  if (requestFactory.httpMethod.equals(\u0026#34;HEAD\u0026#34;) \u0026amp;\u0026amp; !Void.class.equals(responseType)) { throw methodError(method, \u0026#34;HEAD method must use Void as response type.\u0026#34;); } // 3.创建一个返回值的转化器  Converter\u0026lt;ResponseBody, ResponseT\u0026gt; responseConverter = createResponseConverter(retrofit, method, responseType); // 4.创建一个CallAdapted 的类  okhttp3.Call.Factory callFactory = retrofit.callFactory; if (!isKotlinSuspendFunction) { return new CallAdapted\u0026lt;\u0026gt;(requestFactory, callFactory, responseConverter, callAdapter); /**/ } 这里介绍了基础的注解的解析方式。大致分为以下几步\n  根据method的返回值创建calladapter，从这里我们看到retrofit在这里定义了两条规则\n 不支持返回值是 单纯的 okhttp3.Response 可以是ResponseBody 也可以是okhttp3.Response\u0026lt;T\u0026gt; 如果这个method的请求是HEAD的那么必须是void的返回值。从这里的注解也可以看到这里不支持kotlin的Unit    根据返回类型创建responseConverter，将返回值转化为需要的类型\n  获取callFactory,赋值地方在这里。其实就是传入了OkHttpClient\npublic Builder client(OkHttpClient client) { return callFactory(checkNotNull(client, \u0026#34;client == null\u0026#34;)); } public Builder callFactory(okhttp3.Call.Factory factory) { this.callFactory = checkNotNull(factory, \u0026#34;factory == null\u0026#34;); return this; }   创建一个内部实现类并返回，我们在不考虑kotin的情况下查看CallAdapted的实现\n  CallAdapted #  static final class CallAdapted\u0026lt;ResponseT, ReturnT\u0026gt; extends HttpServiceMethod\u0026lt;ResponseT, ReturnT\u0026gt; { private final CallAdapter\u0026lt;ResponseT, ReturnT\u0026gt; callAdapter; CallAdapted( RequestFactory requestFactory, okhttp3.Call.Factory callFactory, Converter\u0026lt;ResponseBody, ResponseT\u0026gt; responseConverter, CallAdapter\u0026lt;ResponseT, ReturnT\u0026gt; callAdapter) { super(requestFactory, callFactory, responseConverter); this.callAdapter = callAdapter; } @Override protected ReturnT adapt(Call\u0026lt;ResponseT\u0026gt; call, Object[] args) { return callAdapter.adapt(call); } } 这里很简单主要是调用基本所有的逻辑都是在HttpServiceMethod中实现的。\n回到第一步的create\nloadServiceMethod(method).invoke(args) 我们来看invoke的实现也就是HttpServiceMethod的invoke的实现\nHttpServiceMethod -\u0026gt; invoke #  @Override final @Nullable ReturnT invoke(Object[] args) { Call\u0026lt;ResponseT\u0026gt; call = new OkHttpCall\u0026lt;\u0026gt;(requestFactory, args, callFactory, responseConverter); return adapt(call, args); } protected abstract @Nullable ReturnT adapt(Call\u0026lt;ResponseT\u0026gt; call, Object[] args); 这理顺这里面的逻辑就是CallAdapter.adapt(OkHttpCall)。\nCallAdapter由我们在创建retrofit的时候传入\nRetrofit retrofit = new Retrofit.Builder() .addConverterFactory(GsonConverterFactory.create()) .addCallAdapterFactory(RxJavaCallAdapterFactory.create()) .baseUrl(\u0026#34;https://api.github.com/\u0026#34;) .build(); 当然我们也可以看下默认的实现DefaultCallAdapterFactory\nfinal class DefaultCallAdapterFactory extends CallAdapter.Factory { private final @Nullable Executor callbackExecutor; DefaultCallAdapterFactory(@Nullable Executor callbackExecutor) { this.callbackExecutor = callbackExecutor; } @Override public @Nullable CallAdapter\u0026lt;?, ?\u0026gt; get( Type returnType, Annotation[] annotations, Retrofit retrofit) { if (getRawType(returnType) != Call.class) { return null; } if (!(returnType instanceof ParameterizedType)) { throw new IllegalArgumentException( \u0026#34;Call return type must be parameterized as Call\u0026lt;Foo\u0026gt; or Call\u0026lt;? extends Foo\u0026gt;\u0026#34;); } final Type responseType = Utils.getParameterUpperBound(0, (ParameterizedType) returnType); final Executor executor = Utils.isAnnotationPresent(annotations, SkipCallbackExecutor.class) ? null : callbackExecutor; return new CallAdapter\u0026lt;Object, Call\u0026lt;?\u0026gt;\u0026gt;() { @Override public Type responseType() { return responseType; } @Override public Call\u0026lt;Object\u0026gt; adapt(Call\u0026lt;Object\u0026gt; call) { return executor == null ? call : new ExecutorCallbackCall\u0026lt;\u0026gt;(executor, call); } }; } static final class ExecutorCallbackCall\u0026lt;T\u0026gt; implements Call\u0026lt;T\u0026gt; { /**/ } } 其中的重点是public CallAdapter\u0026lt;?, ?\u0026gt; get(Type,Annotation[],Retrofit)具体代码我们就不讲解了，主要就是做一些检查，然后返回一个能返回ExecutorCallbackCall的callAdapter\nExecutorCallbackCall #  static final class ExecutorCallbackCall\u0026lt;T\u0026gt; implements Call\u0026lt;T\u0026gt; { final Executor callbackExecutor; final Call\u0026lt;T\u0026gt; delegate; ExecutorCallbackCall(Executor callbackExecutor, Call\u0026lt;T\u0026gt; delegate) { this.callbackExecutor = callbackExecutor; this.delegate = delegate; } @Override public void enqueue(final Callback\u0026lt;T\u0026gt; callback) { Objects.requireNonNull(callback, \u0026#34;callback == null\u0026#34;); delegate.enqueue( new Callback\u0026lt;T\u0026gt;() { @Override public void onResponse(Call\u0026lt;T\u0026gt; call, final Response\u0026lt;T\u0026gt; response) { callbackExecutor.execute( () -\u0026gt; { if (delegate.isCanceled()) { // Emulate OkHttp\u0026#39;s behavior of throwing/delivering an IOException on  // cancellation.  callback.onFailure(ExecutorCallbackCall.this, new IOException(\u0026#34;Canceled\u0026#34;)); } else { callback.onResponse(ExecutorCallbackCall.this, response); } }); } @Override public void onFailure(Call\u0026lt;T\u0026gt; call, final Throwable t) { callbackExecutor.execute(() -\u0026gt; callback.onFailure(ExecutorCallbackCall.this, t)); } }); } /**/ @SuppressWarnings(\u0026#34;CloneDoesntCallSuperClone\u0026#34;) // Performing deep clone.  @Override public Call\u0026lt;T\u0026gt; clone() { return new ExecutorCallbackCall\u0026lt;\u0026gt;(callbackExecutor, delegate.clone()); } /**/ } 这里面的delegate 就是之前我们说的okHttpCall。从enqueue方法就能看出，其实这个CallAdapter的默认实现就是用线程池来执行okHttpCall的enqueue\n第一步小结 #  流程图 #  返回call的流程\n mermaid.initialize({ \"flowchart\": { \"useMaxWidth\":true }, \"theme\": \"default\" } ) sequenceDiagram Proxy-ServiceMethod: loadServiceMethod() ServiceMethod-ServiceMethod: parseAnnotations() ServiceMethod-HttpServiceMethod: parseAnnotations() HttpServiceMethod-+CallAdapter:createCallAdapter() CallAdapter---HttpServiceMethod:createCallAdapter() HttpServiceMethod-+Converter:createResponseConverter() Converter---HttpServiceMethod:createResponseConverter() HttpServiceMethod-CallAdapted:new CallAdapted() CallAdapted-ServiceMethod:return CallAdapted-ExecutorCallbackCall:enqueue ExecutorCallbackCall-Proxy:delegate 描述 #  主要通过解析注解，将我们传入的各个adapter注入到okhttpcall中。\n源码解析第二步 enqueue #  OkHttpCall -\u0026gt; enqueue #  @Override public void enqueue(final Callback\u0026lt;T\u0026gt; callback) { Objects.requireNonNull(callback, \u0026#34;callback == null\u0026#34;); okhttp3.Call call; Throwable failure; /**/ call.enqueue( new okhttp3.Callback() { @Override public void onResponse(okhttp3.Call call, okhttp3.Response rawResponse) { Response\u0026lt;T\u0026gt; response; try { response = parseResponse(rawResponse); } catch (Throwable e) { throwIfFatal(e); callFailure(e); return; } try { callback.onResponse(OkHttpCall.this, response); } catch (Throwable t) { throwIfFatal(t); t.printStackTrace(); // TODO this is not great  } } @Override public void onFailure(okhttp3.Call call, IOException e) { callFailure(e); } private void callFailure(Throwable e) { try { callback.onFailure(OkHttpCall.this, e); } catch (Throwable t) { throwIfFatal(t); t.printStackTrace(); // TODO this is not great  } } }); } 这里的重点当然是response = parseResponse(rawResponse); rawResponse:okHttpCall传入一个request创建出一个rawresponse。 你可以认为下面的方法中rawResponse 里面只有request相关内容以及一个经过请求之后返回的内容\nOkHttpCall -\u0026gt; parseResponse #  Response\u0026lt;T\u0026gt; parseResponse(okhttp3.Response rawResponse) throws IOException { ResponseBody rawBody = rawResponse.body(); // Remove the body\u0026#39;s source (the only stateful object) so we can pass the response along.  rawResponse = rawResponse .newBuilder() .body(new NoContentResponseBody(rawBody.contentType(), rawBody.contentLength())) .build(); int code = rawResponse.code(); if (code \u0026lt; 200 || code \u0026gt;= 300) { try { // Buffer the entire body to avoid future I/O.  ResponseBody bufferedBody = Utils.buffer(rawBody); return Response.error(bufferedBody, rawResponse); } finally { rawBody.close(); } } if (code == 204 || code == 205) { rawBody.close(); return Response.success(null, rawResponse); } ExceptionCatchingResponseBody catchingBody = new ExceptionCatchingResponseBody(rawBody); try { T body = responseConverter.convert(catchingBody); return Response.success(body, rawResponse); } catch (RuntimeException e) { // If the underlying source threw an exception, propagate that rather than indicating it was  // a runtime exception.  catchingBody.throwIfCaught(); throw e; } } 总结一下\n 获取contenttype和长度创建responsebody 根据httpcode的值进行处理 如果code为200则使用responseConverter对结果进行转化并返回  responseConverter -\u0026gt; convert #  responseConverter 由创建okhttpcall的时候传入。 看这里就是传入Converter的地方\n//retrofit -\u0026gt; Build public Retrofit build() { /**/ // Make a defensive copy of the converters.  List\u0026lt;Converter.Factory\u0026gt; converterFactories = new ArrayList\u0026lt;\u0026gt;( 1 + this.converterFactories.size() + platform.defaultConverterFactoriesSize()); converterFactories.add(new BuiltInConverters()); converterFactories.addAll(this.converterFactories); //根据是否用java8编译添加OptionalConverterFactory  converterFactories.addAll(platform.defaultConverterFactories()); return new Retrofit( callFactory, baseUrl, unmodifiableList(converterFactories), unmodifiableList(callAdapterFactories), callbackExecutor, validateEagerly); } 如果是json的返回值我们一般添加GsonConverterFactory\nGsonConverterFactory #  public final class GsonConverterFactory extends Converter.Factory { /** * Create an instance using a default {@link Gson} instance for conversion. Encoding to JSON and * decoding from JSON (when no charset is specified by a header) will use UTF-8. */ public static GsonConverterFactory create() { return create(new Gson()); } /** * Create an instance using {@code gson} for conversion. Encoding to JSON and decoding from JSON * (when no charset is specified by a header) will use UTF-8. */ @SuppressWarnings(\u0026#34;ConstantConditions\u0026#34;) // Guarding public API nullability.  public static GsonConverterFactory create(Gson gson) { if (gson == null) throw new NullPointerException(\u0026#34;gson == null\u0026#34;); return new GsonConverterFactory(gson); } private final Gson gson; private GsonConverterFactory(Gson gson) { this.gson = gson; } @Override public Converter\u0026lt;ResponseBody, ?\u0026gt; responseBodyConverter( Type type, Annotation[] annotations, Retrofit retrofit) { TypeAdapter\u0026lt;?\u0026gt; adapter = gson.getAdapter(TypeToken.get(type)); return new GsonResponseBodyConverter\u0026lt;\u0026gt;(gson, adapter); } @Override public Converter\u0026lt;?, RequestBody\u0026gt; requestBodyConverter( Type type, Annotation[] parameterAnnotations, Annotation[] methodAnnotations, Retrofit retrofit) { TypeAdapter\u0026lt;?\u0026gt; adapter = gson.getAdapter(TypeToken.get(type)); return new GsonRequestBodyConverter\u0026lt;\u0026gt;(gson, adapter); } } 我们前面提到的responseConverter.convert(catchingBody); 就是 GsonResponseBodyConverter\nGsonResponseBodyConverter #  final class GsonResponseBodyConverter\u0026lt;T\u0026gt; implements Converter\u0026lt;ResponseBody, T\u0026gt; { private final Gson gson; private final TypeAdapter\u0026lt;T\u0026gt; adapter; GsonResponseBodyConverter(Gson gson, TypeAdapter\u0026lt;T\u0026gt; adapter) { this.gson = gson; this.adapter = adapter; } @Override public T convert(ResponseBody value) throws IOException { JsonReader jsonReader = gson.newJsonReader(value.charStream()); try { T result = adapter.read(jsonReader); if (jsonReader.peek() != JsonToken.END_DOCUMENT) { throw new JsonIOException(\u0026#34;JSON document was not fully consumed.\u0026#34;); } return result; } finally { value.close(); } } } 这里就是soeasy 利用了gson的解析功能呢。\n"});index.add({'id':3,'href':'/docs/open_sources/retrofit/use/','title':"如何使用",'section':"Retrofit",'content':"Retrofit 如何使用，官方文档部分翻译。 #  A type-safe HTTP client for Android and Java\n 官方文档\n介绍 #  retrofit 可以通过简单的注释将复杂的http 请求转化成java接口的亚子。 比如下面的：\npublic interface GitHubService { @GET(\u0026#34;users/{user}/repos\u0026#34;) Call\u0026lt;List\u0026lt;Repo\u0026gt;\u0026gt; listRepos(@Path(\u0026#34;user\u0026#34;) String user); } Retrofit通过create方法将会自动生成一个GitHubService接口的实现\nRetrofit retrofit = new Retrofit.Builder() .baseUrl(\u0026#34;https://api.github.com/\u0026#34;) .build(); GitHubService service = retrofit.create(GitHubService.class); 被创建出来的GitHubService 提供的每一个 Call 都将提供同步或者异步的方式去向远端服务器发送http请求\nCall\u0026lt;List\u0026lt;Repo\u0026gt;\u0026gt; repos = service.listRepos(\u0026#34;octocat\u0026#34;); 我们使用注解来描述一个http请求，包括以下部分\n url以及请求参数，支持替换 类体自动转化成 request body 支持多模块的 request body 和文件上传  api定义 #  在一个接口的方法上添加注解和参数上添加注解就已经足够描述一个接口将会被如何处理\n请求方式 #  每一个方法都有一个 HTTP 的注解，用来表明请求方式和相对请求路径。有这些HTTP的请求方式: HTTP, GET, POST, PUT, PATCH, DELETE, OPTIONS 和 HEAD. url是定义在注解中的。\n@GET(\u0026quot;users/list\u0026quot;) 你也可以同样定义请求参数到url中\n@GET(\u0026quot;users/list?sort=desc\u0026quot;) URL #  Retrofit支持请求URL可以动态的替换部分内容。需要被替换的部分必须被 { 和 } 包裹住。同时替换的参数必须添加*@Path* 注解。比如这样：\n@GET(\u0026quot;group/{id}/users\u0026quot;) Call\u0026lt;List\u0026lt;User\u0026gt;\u0026gt; groupList(@Path(\u0026quot;id\u0026quot;) int groupId); 当然其他还是和正常的一样，比如可以添加 query\n@GET(\u0026quot;group/{id}/users\u0026quot;) Call\u0026lt;List\u0026lt;User\u0026gt;\u0026gt; groupList(@Path(\u0026quot;id\u0026quot;) int groupId, @Query(\u0026quot;sort\u0026quot;) String sort); 如果你的请求有复杂的请求参数，那么你可以使用*@QueryMap* 。\n@GET(\u0026quot;group/{id}/users\u0026quot;) Call\u0026lt;List\u0026lt;User\u0026gt;\u0026gt; groupList(@Path(\u0026quot;id\u0026quot;) int groupId, @QueryMap Map\u0026lt;String, String\u0026gt; options); 请求体 #  允许通过 @Body 注解，来讲一个类转化为请求体\n@POST(\u0026quot;users/new\u0026quot;) Call\u0026lt;User\u0026gt; createUser(@Body User user); 这个类，将会通过在retrofit实例化的时候传入的转化器转化为请求体，如果没有设置转化器，那么只允许设置requestbody。\n表单和多模块表单 #  retrofit 也支持表单的提交 表单数据可以通过*@FormUrlEncoded* 标签来定，通过 *@Field* 标记一个key-value的键值对。\n@FormUrlEncoded @POST(\u0026quot;user/edit\u0026quot;) Call\u0026lt;User\u0026gt; updateUser(@Field(\u0026quot;first_name\u0026quot;) String first, @Field(\u0026quot;last_name\u0026quot;) String last); Multipart 请求添加 @Multipart 注解。每个part 通过 @Part 注解来标记。\n@Multipart @PUT(\u0026quot;user/photo\u0026quot;) Call\u0026lt;User\u0026gt; updateUser(@Part(\u0026quot;photo\u0026quot;) RequestBody photo, @Part(\u0026quot;description\u0026quot;) RequestBody description); 请求头 #  你可以通过*@Headers* 注解来设置静态的请求头。\n@Headers(\u0026quot;Cache-Control: max-age=640000\u0026quot;) @GET(\u0026quot;widget/list\u0026quot;) Call\u0026lt;List\u0026lt;Widget\u0026gt;\u0026gt; widgetList(); @Headers({ \u0026quot;Accept: application/vnd.github.v3.full+json\u0026quot;, \u0026quot;User-Agent: Retrofit-Sample-App\u0026quot; }) @GET(\u0026quot;users/{username}\u0026quot;) Call\u0026lt;User\u0026gt; getUser(@Path(\u0026quot;username\u0026quot;) String username); 注意 请求头们不会相互覆盖，所有同名的请求头都将会包含在请求中。\n一个请求头可以动态的通过*@Header* 注解进行更新，只需要添加*@Header* 注解的参数到方法中。如果这个参数为空，那么这个请求头将会被忽略。\n@GET(\u0026quot;user\u0026quot;) Call\u0026lt;User\u0026gt; getUser(@Header(\u0026quot;Authorization\u0026quot;) String authorization) 与请求参数map相同，你也可以有请求头map\n@GET(\u0026quot;user\u0026quot;) Call\u0026lt;User\u0026gt; getUser(@HeaderMap Map\u0026lt;String, String\u0026gt; headers) 请求头可以在指定特定的拦截器中添加到每个请求中。 interceptor.\n同步 VS. 异步 #  返回值 Call 的实例可以被同步或者异步的执行。每一个实例只能被调用一次，但是可以通过clone方法创建一个新的实例。 在Android平台上，回调将会在主线程上执行，在JVM上，会调将会发生在发起请求的那个线程上。\nRetrofit 的配置 #  Retrofit是一个用于将你的api转化成可执行方法的实例的类。默认情况下，Retrofit 将会给你一个合理的配置，但是你可以自定义。\n转化器 #  默认情况下，Retrofit 只会将http的body转化成OkHttp中的ResponseBody，当然也只接受RequestBody作为@Body 注解的类型。\n这有一些受欢迎的转化器可供读者使用。\n Gson: com.squareup.retrofit2:converter-gson Jackson: com.squareup.retrofit2:converter-jackson Moshi: com.squareup.retrofit2:converter-moshi Protobuf: com.squareup.retrofit2:converter-protobuf Wire: com.squareup.retrofit2:converter-wire Simple XML: com.squareup.retrofit2:converter-simplexml JAXB: com.squareup.retrofit2:converter-jaxb Scalars (primitives, boxed, and String): com.squareup.retrofit2:converter-scalars  这是一个使用gson的例子。 使用GsonConverterFactory 创建了一个GitHubService接口的实例，其中用了gson来做序列化的工具。\nRetrofit retrofit = new Retrofit.Builder() .baseUrl(\u0026quot;https://api.github.com/\u0026quot;) .addConverterFactory(GsonConverterFactory.create()) .build(); GitHubService service = retrofit.create(GitHubService.class); 引用方式 #  implementation 'com.squareup.retrofit2:retrofit:(insert latest version)' 混淆文件 #  # Retrofit does reflection on generic parameters. InnerClasses is required to use Signature and # EnclosingMethod is required to use InnerClasses. -keepattributes Signature, InnerClasses, EnclosingMethod # Retrofit does reflection on method and parameter annotations. -keepattributes RuntimeVisibleAnnotations, RuntimeVisibleParameterAnnotations # Retain service method parameters when optimizing. -keepclassmembers,allowshrinking,allowobfuscation interface * { @retrofit2.http.* \u0026lt;methods\u0026gt;; } # Ignore annotation used for build tooling. -dontwarn org.codehaus.mojo.animal_sniffer.IgnoreJRERequirement # Ignore JSR 305 annotations for embedding nullability information. -dontwarn javax.annotation.** # Guarded by a NoClassDefFoundError try/catch and only used when on the classpath. -dontwarn kotlin.Unit # Top-level functions that can only be used by Kotlin. -dontwarn retrofit2.KotlinExtensions -dontwarn retrofit2.KotlinExtensions$* # With R8 full mode, it sees no subtypes of Retrofit interfaces since they are created with a Proxy # and replaces all potential values with null. Explicitly keeping the interfaces prevents this. -if interface * { @retrofit2.http.* \u0026lt;methods\u0026gt;; } -keep,allowobfuscation interface \u0026lt;1\u0026gt; "});index.add({'id':4,'href':'/docs/java/%E7%BD%91%E7%BB%9C%E9%80%9A%E8%AE%AF/io/','title':"BIO,NIO,AIO",'section':"网络通讯",'content':"网络通信基本常识 #    课外阅读-bio 与nio的区别 课外阅读-bio 与nio的区别2 课外阅读-bio 与nio的区别2\n 基础知识 #   socket 短连接 长  三种io #   bio nio AIO  bio #  面向流的io方式\n什么是bio #  举个栗子：BIO #  ExecutorService executor = Excutors.newFixedThreadPollExecutor(100);//线程池  ServerSocket serverSocket = new ServerSocket(); serverSocket.bind(8088); while(!Thread.currentThread.isInturrupted()){//主线程死循环等待新连接到来  Socket socket = serverSocket.accept(); executor.submit(new ConnectIOnHandler(socket));//为新的连接创建新的线程 } class ConnectIOnHandler extends Thread{ private Socket socket; public ConnectIOnHandler(Socket socket){ this.socket = socket; } public void run(){ while(!Thread.currentThread.isInturrupted()\u0026amp;\u0026amp;!socket.isClosed()){死循环处理读写事件 String someThing = socket.read()....//读取数据  if(someThing!=null){ ......//处理数据  socket.write()....//写数据  } } } } 相较于 nio 优点在于交互数据的效率更高 缺点就是在处理多路流的时候由于一个线程处理一个输入从而导致多路流的涉及到多线程处理。多线程又是一个消耗巨大的内容，特别在jvm的模型中 java的线程与进程相似。\n"});index.add({'id':5,'href':'/docs/java/%E7%BD%91%E7%BB%9C%E9%80%9A%E8%AE%AF/nio/','title':"BIO,NIO,AIO",'section':"网络通讯",'content':"网络通信基本常识 #    课外阅读-bio 与nio的区别 课外阅读-bio 与nio的区别2 课外阅读-bio 与nio的区别2\n 基础知识 #   socket 短连接 长  11 #  读写是否需要双开线程\nnio #  io 多路复用，面向缓冲区\n什么是nio #   io 多路复用 channel  serversocketchannel socketchannel   selector selectionkey  op_accept op_connect op_read op_write  为什么op_write 事件很少注册 （只有极少数才会注册写事件，因为写事件在发送buffer有空闲时就会触发）     socket buffer  bytebuffer #   客户端传输数据和接收数据需要用两个bytebuffer 直接内存 推上分配  "});index.add({'id':6,'href':'/docs/open_sources/glide/with/','title':"Glide 生命周期",'section':"Glide 基础",'content':"Glide with #  "});index.add({'id':7,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/jmm/','title':"JMM",'section':"多线程",'content':"java memory model 现代计算机原理 cpu 多级缓存模型\n  工作内存和主内存是抽象概念\n  虚拟机中每个线程有一个工作内存，只有一个主内存\n  count++ 这个操作 在jmm中是怎么工作的\n  每个线程只允许操作自己线程的工作内存不能操作主内存和别的线程的工作内存\n  jmm 导致的并发安全问题 #  "});index.add({'id':8,'href':'/docs/java/%E7%BD%91%E7%BB%9C%E9%80%9A%E8%AE%AF/tcp_3_4/','title':"TCP 三次握手、四次挥手",'section':"网络通讯",'content':"TCP 的三次握手、四次挥手 #  三次握手 #  由于tcp 是有具有数据排序超时重传的功能，所以需要交换服务器和客户端的序列号的起始值。\nSYN：Synchronize Sequence Numbers ACK：Acknowledge character  mermaid.initialize({ \"flowchart\": { \"useMaxWidth\":true }, \"theme\": \"default\" } ) sequenceDiagram Note left of Client: SYN_SENT activate Client Client-Server: SYN=1, seq = 12345（请求建立连接） deactivate Client activate Server Note right of Server: SYN_RCVD Server-Client: SYN=1,ACK=1,ack=12346,seq=45678(响应请求连接请求，并发送服务器的连接请求) deactivate Server activate Client Note left of Client: ESTABLISHED Client-Server: ACK=1,ack=45679(收到服务器发送的连接请求，并响应) deactivate Client activate Server Note right of Server: ESTABLISHED deactivate Server 为什么是三次握手，而不是四次握手，不是二次握手 #  这是有效建立连接必需步骤：双端需要交换序列号值起始值 的所需要的最小次数。  三次握手的漏洞 #   syn 宏泛攻击（ddos的一种） 虚假的发起syn的请求，（第一次握手），服务器返回第二次握手，并且等待。这将会大量消耗服务器资源。（超时的时间一般都是分钟级别的） syn 宏泛攻击 解决方案  无效连接监控释放 新起一个线程轮询服务器的连接，将无效的连接释放。 延缓tcb分配方法 防火墙 组织无效的请求发送到服务器     课外阅读 #   网络嗅探 原始套接字（直接抓起网卡中的数据，越过网络层传输层） tcpdump websocket：应用层协议（《HTML5 WebSocket权威指南》）  四次挥手 #    第一次挥手：客户端发送关闭请求 第二次挥手：服务端响应客户端关闭请求 第三次挥手：服务端关闭请求 第四次挥手：客户端发送关闭确认请求   sequenceDiagram Note left of 主动关闭方: FIN_WAIT_1(close主动关闭) Note right of 被动关闭方: CLOSE_WAIT activate 主动关闭方 主动关闭方-被动关闭方: FIN=1, seq = 12345（请求关闭连接） deactivate 主动关闭方 activate 被动关闭方 被动关闭方-主动关闭方: ACK=1,seq=12346(确认收到请求，并发送服务器的连接请求) deactivate 被动关闭方 activate 主动关闭方 Note left of 主动关闭方: FIN_WAIT_2 被动关闭方-主动关闭方 : FIN=1,seq=45678(确认收到请求，并发送服务器的连接请求) activate 被动关闭方 Note right of 被动关闭方: CLOSE deactivate 主动关闭方 deactivate 被动关闭方 activate 主动关闭方 主动关闭方-被动关闭方: ACK=1, seq = 45679（请求关闭连接） activate 被动关闭方 Note left of 主动关闭方: TIME_WAITING（2*MSL） deactivate 主动关闭方 Note right of 被动关闭方: CLOSED deactivate 被动关闭方  MSL: 最长报文段的寿命。一个ip报文数据在网络中能存活的最长时间。（RFC的协议定义中，是两分钟。常规定义时间是30秒）（1分钟~4分钟）  为什么是四次挥手 #  这是因为tcp是全双工的，所以连接双方都需要和对方明确不会再有数据发送  为什么第2步和第3步 不合并发送 #  可以合并发送，这不是硬性要求，这是rfc文档定义的规则，当被动关闭方收到fin的报文，并且自己也没有数据要发送的时候，就可以将第二步和第三步合并发送。但是如果被动关闭方还有别的数据需要发送，那么就需要将两个步骤分开  为什么主动发送关闭端 需要一个TIME_WAITING 状态 #   确保可以对被动关闭方发送的fin报文进行响应：预防fin报文的ack报文丢失，从而导致服务器重发了fin报文，但是客户端无法ack。 确保服务器延迟发送的数据不会错误的发送到别的端口上：因为存在端口冲突，当主动发送方关闭了tcp连接的时候端口号可能被别的程序得到，从而导致被动关闭方延迟发送或者还在网络中的数据包被错误的发送的新开的程序端口上。   keepalive 协议中定义了75分钟 #  需要应用层定义心跳机制\n"});index.add({'id':9,'href':'/docs/java/%E7%BD%91%E7%BB%9C%E9%80%9A%E8%AE%AF/tcp_ip/','title':"tcp 分段与ip 分片",'section':"网络通讯",'content':"TCP/IP详解\u0026ndash;TCP的分段和IP的分片 #    转载\n 分组可以发生在运输层和网络层，运输层中的TCP会分段，网络层中的IP会分片。IP层的分片更多的是为运输层的UDP服务的，由于TCP自己会避免IP的分片，所以使用TCP传输在IP层都不会发生分片的现象。 我们在学习TCP/IP协议时都知道，TCP报文段如果很长的话，会在发送时发生分段，在接受时进行重组， 同样IP数据报在长度超过一定值时也会发生分片，在接收端再将分片重组。\nTCP #  我们先来看两个与TCP报文段分段和IP数据报分片密切相关的概念。\nMTU（最大传输单元） #  MTU前面已经说过了，是链路层中的网络对数据帧的一个限制，依然以以太网为例，MTU为1500个字节。一个IP数据报在以太网中传输，如果它的长度大于该MTU值，就要进行分片传输，使得每片数据报的长度小于MTU。分片传输的IP数据报不一定按序到达，但IP首部中的信息能让这些数据报片按序组装 （标识 标志 偏移等信息进行重组合 卷2 有讲） 。 IP数据报的分片与重组是在网络层进完成的。  MSS（最大分段大小） #  MSS是TCP里的一个概念（首部的选项字段中）。MSS是TCP数据包每次能够传输的最大数据分段，TCP报文段的长度大于MSS时，要进行分段传输。TCP协议在建立连接的时候通常要协商双方的MSS值，每一方都有用于通告它期望接收的MSS选项（MSS选项只出现在SYN报文段中，即TCP三次握手的前两次）。MSS的值一般为MTU值减去两个首部大小（需要减去IP数据包包头的大小20Bytes和TCP数据段的包头20Bytes）所以如果用链路层以太网，MSS的值往往为1460。 而Internet上标准的MTU（最小的MTU，链路层网络为x2.5时）为576，那么如果不设置，则MSS的默认值就为536个字节。很多时候，MSS的值最好取512的倍数。TCP报文段的分段与重组是在运输层完成的。\n到了这里有一个问题自然就明了了，TCP分段的原因是MSS，IP分片的原因是MTU，由于一直有MSS\u0026lt;=MTU，很明显，分段后的每一段TCP报文段再加上IP首部后的长度不可能超过MTU，因此也就不需要在网络层进行IP分片了。因此TCP报文段很少会发生IP分片的情况。\n UDP #  再来看UDP数据报，由于UDP数据报不会自己进行分段，因此当长度超过了MTU时，会在网络层进行IP分片。同样，ICMP（在网络层中）同样会出现IP分片情况。 在TCP/IP分层中，数据链路层用MTU（Maximum Transmission Unit，最大传输单元）来限制所能传输的数据包大小，MTU是指一次传送的数据最大长度，不包括数据链路层数据帧的帧头，如以太网的MTU为1500字节，实际上数据帧的最大长度为1518 = 6+6+2+4+1500 字节，其中以太网数据帧的帧头为6+6+2字节。  当发送的IP数据报的大小超过了MTU时，IP层就需要对数据进行分片，否则数据将无法发送成功。\n分片传输的IP数据报不一定按序到达，但IP首部中的信息能让这些数据报片按序组装。IP数据报的分片与重组是在网络层进完成的\n划重点 #   TCP分段产生原因是MSS.（最大分段大小） IP分片由网络层完成，也在网络层进行重组； TCP分段是在传输层完成，并在传输层进行重组. //透明性 到了这里有一个问题自然就明了了，TCP分段的原因是MSS，IP分片的原因是MTU，由于一直有MSS\u0026lt;=MTU，很明显，分段后的每一段TCP报文段再加上IP首部后的长度不可能超过MTU，因此也就不需要在网络层进行IP分片了。因此TCP报文段很少会发生IP分片的情况。 若数据过大，只会在传输层进行数据分段，到了IP层就不用分片。 而我们常提到的 IP分片是由于UDP传输协议造成的，因为UDP传输协议并未限定传输数据报的大小。   UDP不会分段，就由IP来分片。 TCP会分段，当然就不用IP来分片了！ #  为什么要避免UDP数据报在IP层分片呢 #  在网络编程中，我们要避免出现IP分片，那么为什么要避免呢？ 原因是IP层是没有超时重传机制的，如果IP层对一个数据包进行了分片，只要有一个分片丢失了，只能依赖于传输层进行重传，结果是所有的分片都要重传一遍，这个代价有点大。 由此可见，IP分片会大大降低传输层传送数据的成功率，所以我们要避免IP分片。 对于UDP包，我们需要在应用层去限制每个包的大小，一般不要超过1472字节，即以太网MTU（1500—UDP首部（8）—IP首部（20）。 对于TCP数据，应用层就不需要考虑这个问题了，因为传输层已经帮我们做了。在建立连接的三次握手的过程中，连接双方会相互通告MSS（Maximum Segment Size，最大报文段长度），MSS一般是MTU—IP首部（20）—TCP首部（20），每次发送的TCP数据都不会超过双方MSS的最小值，所以就保证了IP数据报不会超过MTU，避免了IP分片。  udp中一个包大小究竟为多大合适 #  在进行UDP编程的时候,我们最容易想到的问题就是,一次发送多少bytes好？\n当然，这个没有唯一答案，相对于不同的系统,不同的要求,其得到的答案是不一样的，我这里仅对像ICQ一类的发送聊天消息的情况作分析，对于其他情况，你或许也能得到一点帮助。\n域网环境下，建议将UDP数据控制在1472字节以下\n以太网(Ethernet)数据帧的长度必须在46-1500字节之间,这是由以太网的物理特性决定的，这个1500字节被称为链路层的MTU(最大传输单元)。 但这并不是指链路层的长度被限制在1500字节，其实这个MTU指的是链路层的数据区，并不包括链路层的首部和尾部的18个字节。 所以，事实上这个1500字节就是网络层IP数据报的长度限制。因为IP数据报的首部为20字节，所以IP数据报的数据区长度最大为1480字节。而这个1480字节就是用来放TCP传来的TCP报文段或UDP传来的UDP数据报的。 又因为UDP数据报的首部8字节，所以UDP数据报的数据区最大长度为1472字节。这个1472字节就是我们可以使用的字节数。当我们发送的UDP数据大于1472的时候会怎样呢？ 这也就是说IP数据报大于1500字节，大于MTU，这个时候发送方IP层就需要分片(fragmentation)。把数据报分成若干片，使每一片都小于MTU，而接收方IP层则需要进行数据报的重组。这样就会多做许多事情，而更严重的是，由于UDP的特性，当某一片数据传送中丢失时，接收方无法重组数据报，将导致丢弃整个UDP数据报。因此，在普通的局域网环境下，我建议将UDP的数据控制在1472字节以下为好。\n Internet编程时，建议将UDP数据控制在548字节以下\n进行Internet编程时则不同，因为Internet上的路由器可能会将MTU设为不同的值。如果我们假定MTU为1500来发送数据，而途经的某个网络的MTU值小于1500字节，那么系统将会使用一系列的机制来调整MTU值，使数据报能够顺利到达目的地，这样就会做许多不必要的操作。 鉴于Internet上的标准MTU值为576字节，所以我建议在进行Internet的UDP编程时， 最好将UDP的数据长度控件在548字节(576-8-20)以内。\n "});index.add({'id':10,'href':'/docs/java/%E7%BD%91%E7%BB%9C%E9%80%9A%E8%AE%AF/%E5%8D%8F%E8%AE%AE/','title':"网络协议",'section':"网络通讯",'content':"网络协议 #    RFC 协议官方文档\n 网络分层 #  OSI 分层模型 ISO 组织讨论的架构，分层更加详细，理想化学、术化，现实中使用TCP\\IP模型更多\n mermaid.initialize({ \"flowchart\": { \"useMaxWidth\":true }, \"theme\": \"default\" } ) graph TD 应用层--表示层; 表示层--会话层; 会话层--传输层; 传输层--网络层; 网络层--数据链路层; 数据链路层--物理层;  TCP\\IP 分层模型 IEEE 组织开发，更贴近现实\ngraph TD; 应用层[\"应用层：包括OSI模型中的应用层、表示层、传输层\"]--传输层; 传输层--网络层; 网络层--D[\"链路层：包括OSI模型中的数据链路层、物理层\"];  分层说明  应用层：为应用提供服务 表示层（TCP\\IP协议中包含在应用层中）：数据格式转化，数据加密 会话层（TCP\\IP协议中包含在应用层中）：建立、管理、维护会话 传输层：建立、管理、 维护端对端的连接 网络层：IP地址以及路由选择 数据链路层（TCP\\IP协议中包含在数据层中）：提供介质访问和链路管理 物理层（TCP\\IP协议中包含在数据层中）：物理传输  问题： 移动通信的3g、4g在哪个层次？ \u0026ndash; 链路层   TCP\\IP协议族模型中有哪些具体协议 #  包括但不限于\n   概念模型 功能 包含的协议     应用层 文件传输、电子邮件、文件服务、虚拟终端 TFTP、HTTP、FTP、SNMP、SMTP、DNS、Telnet   应用层 数据格式化、代码转化、数据加密 没有   应用层 解除或者建立与别的节点的连接 没有   传输层 提供段对端的接口 TCP、UDP   网络层 为数据包提供路由 IP、ICMP、RIP、OSPF、BGP、IGMP   链路层 传输有地址的帧以及错误检测功能 SLIP、CSLIP、PPP、ARP、RARP、MTU   链路层 以二进制为数据形式在物理媒体上传输数据 ISO2110、IEEE802、IEEE802.2    TCP\\IP协议族中的主要概念 #  以太网协议中，规定了同一个局域网中的主机与另一个主机通信需要需要知道对方的mac地址。\n传输层主要协议TCP 、 UDP #   TCP：面向连接的 可靠的流协议 UDP：面向无连接的 不可靠的协议  IP地址、Mac地址 #   ip 在原地址与目标地址之间传递数据包 mac地址制造商制作的时候写入，是网络设备的唯一标识 网络层还有icmp 控制报文协议、igmp internet组管理协议等 链路层 arp （地址解析协议）和 rarp（反向地址转化协议） arp 地址解析协议 通过ip转化为mac地址  端口号 称为程序地址 #  客户端程序一般情况下不需要端口号，操作系统将会帮忙分配端口号。一般都是分配49152 ~ 65535这些没有人用的端口号\nTCP概述 #  网络协议为什么要分包 #  包：全能性术语 帧：数据链路层中包的单位 片：IP数据中的单位 段：TCP数据流中的信息 消息：是指应用协议中的数据和单位\n 数据链路层对ip层有长度限制：MTU（以以太网为例，MTU=1500字节 ip层算上首部 对上层限制：MSS MSS的值一般为MTU值减去两个首部大小（需要减去IP数据包包头的大小20Bytes和TCP数据段的包头20Bytes）  TCP的基本特性 #    面向连接\n 只能端对端 （udp 既能端对端，也能广播，组播）    可靠性\n 怎么保证可靠性  超时重传。超过一定时间没有收到应答确认就认为数据包丢掉了，重新发送 应答确认      数据排序\n发送的时候按照顺序发送，接受的时候也有可能不按照顺序接受\n 物理连接：真实的链路连接 虚拟连接：在三次握手之后也可以认为两端建立了连接 三次握手\n  所以tcp数据包有按照数据排序功能\n  流量控制\n 滑动窗口： 接受端和发送端有可能存在处理速度不同的问题存在，所以会有一个协商机制存在。在报文的响应中，数据接收方将下次能接受的数据发送给数据发送方。来协商这个发送的数据    全双工 每一端都可以成为数据接受方，也可以成为数据发送方，并且可以同时发送。\n  RTT（往返时延） RTO（重传超时）（动态调整）\n   扩展阅读 TCP 粘包问题 扩展阅读 tcp_ip\n "});index.add({'id':11,'href':'/docs/java/%E7%BD%91%E7%BB%9C%E9%80%9A%E8%AE%AF/question/','title':"网络协议 相关问题",'section':"网络通讯",'content':"网络协议 相关问题 #  一次完整的http 请求的过程 #  dns 域名解析 #   本地浏览器缓存 操作系统缓存 dns 服务器   三次握手 建立tcp 连接 #  客户端发起http请求 #  服务器响应http请求 #  客户端解析http请求，并请求html代码中的资源 #  客户端渲染展示内容 #  关闭tcp连接（1.0） #   1.1 keep_alive 2.0 io 多路复用 3 udt，不再使用tcp  DNS 劫持 #  HTTP劫持 #  "});index.add({'id':12,'href':'/docs/java/%E7%BD%91%E7%BB%9C%E9%80%9A%E8%AE%AF/%E9%9D%A2%E8%AF%95/','title':"面试题",'section':"网络通讯",'content':"https://www.cnblogs.com/lh03061238/p/12215367.html\n  tcp 三次握手\n  tcp 为什么三次握手\n  tcp 四次挥手\n  tcp 为什么会有 time_waiting 状态\n  ddos 攻击 syn 洪水攻击\n ddos 带宽性攻击：利用大量合理的请求，抢占服务器资源导致正常用户无法访问服务器 ddos 联通性攻击： syn 洪水攻击：连通性请求    哪些情况比较适合udp实现 允许丢包的情况存在。\n 多播 直播、视频  如果需要保证可靠性，需要应用层来保证可靠性的实现\n  http 和https 的区别\n 明文 端口 加密 安全    https 多出的步骤 #    tcp 粘包拆包\n 消息头加消息体 消息定长 特殊的分割符    序列化\n  c10K问题\n  select poll epoll 课外阅读\n  水平触发和边缘触发\n  直接内存\n  零拷贝 减少了不必要的内存内容的拷贝就可以称为广义上的拷贝 现代硬盘都有dma 传统拷贝 4次拷贝 4次切换上下文 mmap 3次拷贝 2次切换上下文 pipe 2次拷贝 2次切换上下文 sendfile filechannel\n  时间局部性原理\n  空间局部性原理\n  "});index.add({'id':13,'href':'/posts/brew/','title':"Brew 的镜像更换",'section':"随笔",'content':"  转载\n 你可能有过这样糟糕的经历，当你满心欢喜的敲下 “brew install 应用名称”，静静的等待安装结果的时候，Homebrew在 Updating Homebrew卡死了。\n Homebrew是一款Mac OS平台下的软件包管理工具，拥有安装、卸载、更新、查看、搜索等很多实用的功能。简单的一条指令，就可以实现包管理，而不用你关心各种依赖和文件路径的情况，十分方便快捷。\n使用 阿里云 的 Homebrew 镜像源进行加速 #  如果你没有更换过镜像源，执行 brew 命令安装应用的时候，跟以下 3 个仓库地址有关：\n brew.git homebrew-core.git homebrew-bottles  通过以下操作将这 3 个仓库地址全部替换为 阿里云 提供的地址\n更换 brew.git #  cd \u0026quot;$(brew --repo)\u0026quot; git remote set-url origin https://mirrors.aliyun.com/homebrew/brew.git 更换 homebrew-core.git #  cd \u0026quot;$(brew --repo)/Library/Taps/homebrew/homebrew-core\u0026quot; git remote set-url origin https://mirrors.aliyun.com/homebrew/homebrew-core.git  执行上面两个命令之后请执行 brew update\n 更换 homebrew-bottles #  如果你使用zsh那么\necho 'export HOMEBREW_BOTTLE_DOMAIN=https://mirrors.aliyun.com/homebrew/homebrew-bottles' \u0026gt;\u0026gt; ~/.zshrc source ~/.zshrc 如果你使用 bash。 那么\necho 'export HOMEBREW_BOTTLE_DOMAIN=https://mirrors.aliyun.com/homebrew/homebrew-bottles' \u0026gt;\u0026gt; ~/.bash_profile source ~/.bash_profile "});index.add({'id':14,'href':'/posts/%E7%85%B2%E4%BB%94%E9%A5%AD/','title':"煲仔饭",'section':"随笔",'content':"煲仔饭 #   过完年，老婆抱怨过年期间都没有在家吃到什么好吃的，为了安抚老婆大人，赶紧自学了这一道简单实用的煲仔饭。\n  作为程序员，做菜就要拿出一个最优解，以最快的速度，最少的投入得到最好吃的佳肴。\n 腊肠煲仔饭 #  准备材料 #   好吃的大米（两大碗的量） 一个电饭煲 好吃的一根腊肠，切成片 一把香菇，切成片 来点喜欢吃的蔬菜，我这一次用的是青椒，切成小段 生抽、老抽、糖、盐、辣椒 一瓶可乐  最优步骤 #   把未泡发的香菇直接切片 把切好的香菇直接用开水泡发，泡发的开水留着当煮饭的水 主线程（就是你自己）挂起大约半小时，这时候可以去干别的，比如来一把王者荣耀 打完一把王者荣耀之后，开始处理腊肠，切片。淘米洗米，把香菇捞出，泡香菇的开水倒入电饭煲。再加水直到水量在平时烧饭的一半左右即可不要多加。（如果不小心多加了，焖一会会好吃点，别问我为什么知道这个^_^）（这些水量是包含泡香菇的水的，至于怎么做~~~您不需要我教吧） 如果你的腊肠比较咸，可以在最开始就把腊肠放到电饭煲里和饭一起煮。（当然也可以不管三七二十一从最开始就把腊肠丢进去） 开始煮饭之后，准备别的食材，把蔬菜洗净切成小段，辣椒切成小端 拿出一个碗，倒入5勺生抽和一勺老抽，倒入一勺糖，盐看情况加，如果不够味道可以加点盐。 主线程挂起，直到饭呈半粥状，加入香菇，搅拌均匀。 主线程再次挂起，等待饭到快熟的时候加入蔬菜，搅拌均匀。 主线程再次挂起，等待饭煮熟 饭熟了之后，拿出锅，倒上少量油，加入辣椒段，爆香一会提升辣味。再将之前准备好的调料全部倒入锅中 等调料沸腾之后，将调料直接倒入电饭煲，搅拌均匀，盛出装到碗里。 把可乐倒入饮水的大杯中，加入冰块。 香喷喷的煲仔饭加冰阔乐就完成了  "});index.add({'id':15,'href':'/posts/%E9%9D%A2%E8%AF%95%E9%A2%98%E5%90%88%E9%9B%86/','title':"面试题合集",'section':"随笔",'content':"面试题合集 #   可能遇到额面试题，这是一个整理后的集合，后续继续更新\n 简历涉及到的问题 #  RTSP #   我的介绍\nTCP、ip、udp、socket #   TCP、ip\nVLC #  []\nrandomaccessfile #  [断电续传]\nhttp 断点续传 #  http 协议 请求用Range: bytes=0-9999 返回里包含 Content-Range: bytes=0-9999/22400 0-9999 请求0到9999的数据 22400 为文件总大小 [断电续传] https://www.cnblogs.com/findumars/p/5745345.html Last-Modified Etag If-Range\nMVP #  conetent provider #  camera service、evs #  yuvimage #  yuv image 内存泄露\nmedia store #  kotlin #  kotlin协程 #  android。mk #  Android相关问题 #  Handler #   Handler、Looper、MessageQueue MessageQueue的数据结构是什么？ 为什么用这个数据结构 如何在子线程中创建Handler Handler Post的原理 异步屏障 主线程的Looper 不允许退出 handlerCallback优先于handle message  Activity 相关 #   启动模式 taskAffinity 生命周期 Activity启动流程  fragment #     service #   进行保活的方式 启动方式   view 布局优化 #   viewstub include merge  广播 #   动态广播 静态广播 粘性广播 本地广播  provider #  Android事件分发机制 #  view的绘制流程 #  Activity Window、DecorView、ViewRoot #  AsyncTask #  binder 流程 #   aidl binder 流程 为什么要采用binder binder的优势 进程通信方式  AMS、PMS、WMS #  ANR #   为什么会产生ANR 如何定位ANR 如何避免ANR  内存泄漏 #   什么情况下会内存泄漏 哪些情况下容易内存泄漏  屏幕分辨率 #   dp px dpi sp  Android 缓存机制 #   lrucache  性能优化 #  内存优化 #   gc 算法 gc root 分析工具  ui优化 #  电量优化 #  ui卡顿 #  MVC MVP MVVM #  gradle #  Rxjava #  OKhttp #  retrofit #  glide #  Java #  HTTP #  TCP、IP、UDP #  数据结构 #   hashmap 链表 堆 查找算法 内存模型 JVM gc 类加载过程 反射 多线程 threadlocal 多线程aqs 多线程 线程池  设计模式 #  JAVA 引用 #  泛型 #  final 、finnaly、finalize #  sync 和lock的区别 #  "});index.add({'id':16,'href':'/docs/android/camera/camera/','title':"android camera 相关知识",'section':"Camera",'content':"Android Camera #   工作中开发了一个相机应用，在开发过程中由于和evs框架冲突，导致经常发生打开camera失败。因此写下这篇文章，来简单的分析一下camera底层的内容\n相机 CameraX\n Camera2 #    camera 官方例子\n    Sample Description     CameraXBasic Demonstrates how to use CameraX APIs.   CameraXTfLite Demonstrates how to use TfLite with CameraX APIs.   Camera2Basic Demostrates capturing JPEG, RAW and DEPTH images, e.g. unprocessed pixel data directly from the camera sensor.   Camera2SlowMotion Demostrates capturing high-speed video in a constrained camera capture session.   Camera2Video Demonstrates recording video using the Camera2 API and MediaRecorder.   HdrViewfinder Demonstrates use of RenderScript to display a live HDR feed from camera frames using Camera2 API.    我们是为了分析camera底层的原理，所以我们来分析Camera2Basic的内容\nCamera2Basic #   流程图 - 预览  mermaid.initialize({ \"flowchart\": { \"useMaxWidth\":true }, \"theme\": \"default\" } ) sequenceDiagram participant cm As CameraManager participant cd As CameraDevice participant ccs As CameraCaptureSession cm-cd: openCamera(cameraId, callback) cd-ccs: createCaptureSession(List of Surface, StateCallback) cd-CaptureRequest: createCaptureRequest(CameraDevice.TEMPLATE_STILL_CAPTURE).apply { addTarget(imageReader.surface) } CaptureRequest-ccs: build() ccs-ccs:setRepeatingRequest(CaptureRequest, callback)  解释  CameraManager 调用 openCamera(cameraId, callback) 获取一个cameradevice的对象实例。cameraid 为一个常量可以通过CameraManager.getCameraIdList() 获取 打开成功将会回调在callback 中获取到CameraDevice 使用CameraDevice 创建一个CaptureSession。传入接受数据的Textureview的surface 成功后，可以发起获取画面的请求setRepeatingRequest    #  "});index.add({'id':17,'href':'/docs/android/framework/androidvm/','title':"android vm",'section':"Framework",'content':" Java vm 基于栈的虚拟机，每一个运行的线程，都有一个独立的栈，每一个方法调用都会产生一个栈帧。当前线程运行的方法的栈帧在当前虚拟机栈的栈顶。所有的运算都通过栈帧中的操作数栈来炒作。 每一个栈帧中包含 本地变量表，操作数栈，动态链接，返回地址。 Android vm 基于寄存器的虚拟机，取消了操作数栈。本地变量表使用虚拟的寄存器来代替，相应的字节码指令也将会变少，减少了数据在操作数栈和本地变量表中的移动。相当于将操作数栈和本地变量表合并在寄存器中。   dalvik\n  jit 即时编译\n  dalvik与 art的区别\n dalvik：解释执行dex字节码，结合jit将部分热点代码即时进行编译或者优化成本地机器码。 art：安装的时候将dex 代码转化成本地机器码    dalvik与 art的 安装的区别\n dalvik 是通过 dexopt 将apk中的dex文件提取放到存储中 art 是通过dex2oat 将dex文件提取出来 编译成当前设备的机器码 aot （预编译）    art的进化，从Android N 开始使用混编\n 安装的时候将dex放到本地。 先运行的时候先使用jit做一个编译，并且将编译的部分保存到profile。 当空闲的时候将profile文件中保存的代码进行oat编译成本地代码。 运行时查找本地代码，如果有就还是用本地代码 如果没有则使用jit编译并且保存到profile    类加载机制\n ClassLoader  BootClassLoader // 加载基础的framework中的类 BaseDexClassLoader // 加载apk中的dex的类，中间有一个 dexpathlist  PathClassLoader // Android apk的类加载机制 DexClassLoader // 动态加载其他的dex文件        PathClassLoader 源码解析\n 双亲委派机制  优先是由parent classloader 来进行加载，如果parent classloader 加载失败，再由自己进行加载。如果失败抛出classnotfoundexception      热修复等问题遇到 机器码怎么办？\n"});index.add({'id':18,'href':'/docs/android/framework/start/','title':"系统启动流程",'section':"Framework",'content':"系统启动流程 正确的阅读方式：\n 先整体了解大概流程 然后再阅读具体的代码流程 看完代码之后再看细节的逻辑  "});index.add({'id':19,'href':'/docs/android/','title':"Android",'section':"Docs",'content':"Android #   framework handler view  "});index.add({'id':20,'href':'/docs/android/android_studio/maven_sdk/','title':"创建并上传mavenSdk",'section':"Android Studio",'content':"maven 上传 sdk的正确打开方式 #  概念明确并区分 #   公司级自建maven:公司内部创建的maven（具体内容询问公司的开发） mavenLocal:本地电脑中创建的本地仓库（{user}/.m2/repository/） jcenter、google、maven等: 外部开源的仓库，大部分的依赖都是从这些外部开源的仓库中下载的。  repositories { maven {url \u0026#39;https://maven.aliyun.com/repository/public/\u0026#39;} mavenLocal() google() jcenter() maven {url \u0026#39;http://{company.ip}/nexus/content/repositories/thirdparty/\u0026#39;} maven {url \u0026#39;http://{company.ip}/nexus/content/repositories/snapshots/\u0026#39;} } 一般的maven仓库如果使用nexus的方式搭建会有如下几个重要的仓库\n snapshots （快照库） releases （release库） thirdparty（第三方库） public（公开库）  pom 文件 #   这是一个retrofit的pom文件\n从这里我们可以看到几个关键的点\n\u0026lt;groupId\u0026gt;com.squareup.retrofit2\u0026lt;/groupId\u0026gt; \u0026lt;artifactId\u0026gt;retrofit\u0026lt;/artifactId\u0026gt; \u0026lt;version\u0026gt;2.9.0\u0026lt;/version\u0026gt; \u0026lt;dependencies\u0026gt; \u0026lt;dependency\u0026gt; \u0026lt;groupId\u0026gt;com.squareup.okhttp3\u0026lt;/groupId\u0026gt; \u0026lt;artifactId\u0026gt;okhttp\u0026lt;/artifactId\u0026gt; \u0026lt;version\u0026gt;3.14.9\u0026lt;/version\u0026gt; \u0026lt;scope\u0026gt;compile\u0026lt;/scope\u0026gt; \u0026lt;/dependency\u0026gt; \u0026lt;/dependencies\u0026gt;  一个maven的依赖可以定义他需要的依赖 相应的groupId artifactId version 等等信息都是定义在pom文件中的。  可以说 pom文件就是maven的灵魂\nAndroid中的aar #  我们假设当前的module为AModule，他依赖于BModule。 当我们运行AModule的assemble task之后，将会在build目录得到一个aar。 这个aar中只包括这些内容\n AModule中包含的所有java、kotlin代码 AModule中的aidl文件 AModule中的res资源文件 AModule中自动生成的那些java或者class 代码  这些内容中不包含BModule的代码。\n所以这就意味着如果我们只能上传这个AModule中的代码，AModule所依赖的BModule的代码是无法编译进AModule的aar中的，因为会有一个BModule的aar存在\n所以我们需要做的是尽量将sdk的代码合并到一个module。那么确实无法做到这一点该怎么办呢？ 这里介绍两种方法：\n  fat-aar。一个gradle 插件将依赖module的代码强行合并进本module。（但是不推荐） 将BModule的aar 也上传到仓库中。这样我们就可以通过引入依赖的依赖的方式来将BModule引入。  我们接下来的讨论的就是（将BModule的aar 也上传到仓库中）的这种方式。\n如何将一个module的aar 上传到maven #  配置maven账号 #  项目的local.properties添加\nmaven.username=xxx maven.password=xxx 添加代码 #   添加plugin maven-publish 添加上传相关task  Properties properties = new Properties() def localPropertiesFile = new File(\u0026#39;../local.properties\u0026#39;) if (null != localPropertiesFile \u0026amp;\u0026amp; localPropertiesFile.exists()) { properties.load(localPropertiesFile.newDataInputStream()) } afterEvaluate { publishing { publications { // Creates a Maven publication called \u0026#34;release\u0026#34;.  release(MavenPublication) { // Applies the component for the release build variant.  from components.release artifact androidJavadocsJar artifact androidSourcesJar pom { name = \u0026#34;{maven name}\u0026#34; description = \u0026#34;{this is a maven}\u0026#34; developers { // 这个模块可以缺省  developer { id = \u0026#34;{id}\u0026#34; name = \u0026#34;{developer.name}\u0026#34; email = \u0026#34;{developer.name}\u0026#34; } } } // You can then customize attributes of the publication as shown below.  // implementation \u0026#34;groupId:artifactId:version\u0026#34;  groupId = \u0026#34;{groupId}\u0026#34; artifactId = \u0026#34;{artifact}\u0026#34; version = \u0026#34;{version}\u0026#34; } } repositories { maven { url \u0026#34;maven url\u0026#34; //maybe like http://{ip}/nexus/content/repositories/snapshots/  credentials { username propterties.getProperty(\u0026#34;maven.username\u0026#34;) password propterties.getProperty(\u0026#34;maven.password\u0026#34;) } } } } } task androidJavadocs(type: Javadoc) { failOnError false options.addStringOption(\u0026#39;Xdoclint:none\u0026#39;, \u0026#39;-quiet\u0026#39;) options.addStringOption(\u0026#39;encoding\u0026#39;, \u0026#39;UTF-8\u0026#39;) options.addStringOption(\u0026#39;charSet\u0026#39;, \u0026#39;UTF-8\u0026#39;) source = android.sourceSets.main.java.srcDirs classpath += project.files(android.getBootClasspath().join(File.pathSeparator)) android.libraryVariants.all { variant -\u0026gt; if (variant.name == \u0026#39;release\u0026#39;) { owner.classpath += variant.javaCompileProvider.get().classpath } } exclude \u0026#39;**/R.html\u0026#39;, \u0026#39;**/R.*.html\u0026#39;, \u0026#39;**/index.html\u0026#39; } task androidJavadocsJar(type: Jar, dependsOn: androidJavadocs) { archiveClassifier.set(\u0026#39;javadoc\u0026#39;) from androidJavadocs.destinationDir } task androidSourcesJar(type: Jar) { archiveClassifier.set(\u0026#39;sources\u0026#39;) from android.sourceSets.main.java.srcDirs } 当然相关信息你都可以独立在一个gralde文件中进行管理\n当你配置好这些的时候你gradle sync 一下 会在你的gradle window中看到publishing 类别 #  其中有这些task\n generateMetadataFileForReleasePublication generatePomFileForReleasePublication publish publishAllPublicationsToMavenRepository publishReleasePublicationToMavenLocal publishReleasePublicationToMavenRepository publishToMavenLocal  点击publishReleasePublicationToMavenRepository 就可以上传到maven中了 不过在上传之前你最好在本地验证一下\n依赖的依赖 #  这种方式会自动的将你的依赖添加到 pom文件中，所以你只需要在需要上传的module中添加上面的代码即可。这样就可以循环上传所有的sdk\nSNAPSHOT #  repositories { maven { url \u0026#34;maven url\u0026#34; //maybe like http://{ip}/nexus/content/repositories/snapshots/  credentials { username propterties.getProperty(\u0026#34;maven.username\u0026#34;) password propterties.getProperty(\u0026#34;maven.password\u0026#34;) } } } 在这里定义的url中写入的snapshots的仓库地址 然后定义\nversion = \u0026#34;{version}\u0026#34; 的时候加上-SNAPSHOT的后缀就可以将sdk上传到快照仓库。\n修改snapshot的依赖的默认拉取时长 #  默认情况下，maven针对snapshot的依赖会每隔24小时强行刷新一次，而我们可以通过配置啦修改这个默认的刷新时长 添加在 module的build.gradle 的根节点上\nconfigurations.all { // check for updates every build  resolutionStrategy.cacheChangingModulesFor 0, \u0026#39;seconds\u0026#39; } "});index.add({'id':21,'href':'/docs/kotlin/plus/fanxin/','title':"Kotlin 泛型",'section':"Plus",'content':"java的泛型 #   kotin的泛型类型 与java一样中几乎一致 没有什么大的区别，相应的例子也在 这里 有体现。 官方介绍\n java 泛型中的通配符 #   首先需要和各位读者明确java中的泛型的两个概念，这有助于你理解kotlin的泛型\n  泛型定义，上限和下限 泛型读取模式   泛型定义是指 在类或者方法上的定义的泛型，这些定义我们 可以定义上限和下限。比如这段代码  class A{} class B extends A{} class C extends A{} class Fu\u0026lt;T\u0026gt; {} class Zi\u0026lt;T extends B\u0026gt; extends Fu\u0026lt;T\u0026gt; {} Zi class定义了他的泛型类型具有上限是B，意味着他的类型只能传入B的子类。\n你不能在Java中这样定义 class A\u0026lt;? extends T\u0026gt; 因为这样编译器无法在编译阶段确定他的类型\n泛型读取模式  List\u0026lt;? extends A\u0026gt; list = new ArrayList\u0026lt;B\u0026gt;(); A a0 = list.get(0); list.add(new A()); 这一段代码中list.add(new A()); 会报错。这是因为当我们在使用？extends xx的时候会有一个规则就是读写权限限制。我们再来看一段代码：\nList\u0026lt;? super B\u0026gt; list = new ArrayList\u0026lt;A\u0026gt;(); B b = list.get(0); list.add(new B()); 这一段代码中B b = list.get(0); 会报错。 其实我们去读写权限安全的角度去思考编译器的处理逻辑就能够理解。\n 当我们声明一个变量为 ? extends A 的时候，是希望这个泛型变量接受的泛型类型为A的子类，而且我们只关注A的方法，不考虑子类的扩展或者重载（不然直接声明一个子类的泛型变量即可） 以list为例，当声明了一个list，泛型类型为A的子类，那么这个list的元素是不是可以有很多种子类的可能（比如B或者C）。这就会遇到一个问题，如果允许这个list可以修改，那么运行期间就可能报错，（比如arraylist是使用数组来实现的，但是你类型不同，数组怎么实现？）。所有为了避免这种问题，编译器所幸就拒绝你对其进行修改只允许获取。 同理，当你声明一个变量为? super B的时候，你是希望这个泛型变量接收的泛型类型为B的父类，而且我们关注点在B的方法上面。同样以list为例，当你声明了一个list，泛型类型为B的父类那么这个list的元素的时候，你去获取这个元素的时候你得到的引用为B，但是这个B 可能是b的父类的元素，这中间就会产生转化错误（我们可以用父类去引用子类的实例，但是不能用子类去引用父类的实例）。那么编译器就索性拒绝你对其进行获取，但是允许你修改,当然你只可以添加B的类型的实例。  两者的区别  像第一小节所的你不能在Java中这样定义 class A\u0026lt;? extends T\u0026gt;。这就导致了Java中泛型其实可以分为两种理解，第一种就是在定义的时候规定的泛型，我们叫他泛型定义。还有一种就是泛型读取模式定义了一个类型引用了一个变量，限制了对这个变量的各种读取模式。\nkotlin 的泛型 #   当你理解Java的泛型之后用out代替 ? extends。用 in代替? super 就可以了。\n 当然kotlin作为一门有野心的语音不会这么简单的处理泛型。那么有什么需要注意的嘛？接下来我们来看看\n  扩展到整个类的修饰\nclass Array\u0026lt;T\u0026gt;(val size: Int) { fun get(index: Int): T { …… } fun set(index: Int, value: T) { …… } } 这里当我们给一个类 定义了泛型的时候类中的各个方法和属性就可以使用这个T。那么我们这么定义呢\nclass Array\u0026lt;in T\u0026gt;(val size: Int) { fun get(index: Int): T { …… } // 这里会报错  fun set(index: Int, value: T) { …… } } 这里我们就可以发现类里面的所有T 都带上了in的限制。\n这一点Java是做不到的，这个特性也是Kotlin 特有的\n  使用处型变：类型投影\nfun copy(from: Array\u0026lt;out Any\u0026gt;, to: Array\u0026lt;Any\u0026gt;) { …… } 在这里定义了out 就限制了from数组被修改。\n  星投影 （copy 从官网）\n有时你想说，你对类型参数一无所知，但仍然希望以安全的方式使用它。 这里的安全方式是定义泛型类型的这种投影，该泛型类型的每个具体实例化将是该投影的子类型。\nKotlin 为此提供了所谓的星投影语法：\n 对于 Foo ，其中 T 是一个具有上界 TUpper 的协变类型参数，Foo \u0026lt;\u0026gt; 等价于 Foo 。 这意味着当 T 未知时，你可以安全地从 Foo \u0026lt;\u0026gt; 读取 TUpper 的值。 对于 Foo ，其中 T 是一个逆变类型参数，Foo \u0026lt;\u0026gt; 等价于 Foo 。 这意味着当 T 未知时，没有什么可以以安全的方式写入 Foo \u0026lt;\u0026gt;。 对于 Foo ，其中 T 是一个具有上界 TUpper 的不型变类型参数，Foo\u0026lt;*\u0026gt; 对于读取值时等价于 Foo而对于写值时等价于 Foo。  如果泛型类型具有多个类型参数，则每个类型参数都可以单独投影。 例如，如果类型被声明为 interface Function \u0026lt;in T, out U\u0026gt;，我们可以想象以下星投影：\n Function\u0026lt;*, String\u0026gt; 表示 Function\u0026lt;in Nothing, String\u0026gt;； Function\u0026lt;Int, *\u0026gt; 表示 Function\u0026lt;Int, out Any?\u0026gt;； Function\u0026lt;*, *\u0026gt; 表示 Function\u0026lt;in Nothing, out Any?\u0026gt;。  注意：星投影非常像 Java 的原始类型，但是安全。\n  泛型擦除\n这一点和Java 类似在虚拟机上泛型是没有具体的类型的。这些仅在编译器检查。is as 之类的关键字也不能再这一点上进行判断\n  "});index.add({'id':22,'href':'/docs/kotlin/plus/plus1/','title':"Kotlin 进阶知识",'section':"Plus",'content':"  顶级属性和顶级方法\nval PI = 3.14 var x = 0 fun incrementX() { x += 1 } fun main() { println(\u0026quot;x = $x; PI = $PI\u0026quot;) incrementX() println(\u0026quot;incrementX()\u0026quot;) println(\u0026quot;x = $x; PI = $PI\u0026quot;) } 定义在class 外面的属性 可以理解为 java中public 静态属性，可以被所有地方使用，只需要import 即可 方法同理。\n  幕后属性\nprivate var _table: Map\u0026lt;String, Int\u0026gt;? = null public val table: Map\u0026lt;String, Int\u0026gt; get() { if (_table == null) { _table = HashMap() // 类型参数已推断出  } return _table ?: throw AssertionError(\u0026#34;Set to null by another thread\u0026#34;) } 以上代码中table 属性就是幕后属性。当我们访问table属性的时候其实访问的是 get() 方法，get方法中访问了_table属性，这就造成了 table 属性其实并不会被访问到的情况\nclass demo(var name: String) { val size: Int get() { return name.length } } fun main() { val a = demo(\u0026#34;sq\u0026#34;) println(a.size) a.name = \u0026#34;111123\u0026#34; println(a.size) } /** result 2 6 */ 从这里我们可以看到访问size 其实就是在访问get方法，\n 我们可以认为 size 属性就是get方法的别名，val 修饰属性 只是限制了set方法的出现，var修饰属性可以添加set方法而已    ?:\nval isEmpty = ... val a = isEmpty ?: c 这里如果isEmpty 为空，将会默认执行 c。 c可以是一个变量，也可以是一个语句。其实这就是kotlin中的特性，{} 中的最后一个语句将作为返回值\n  reified \u0026ndash; 使抽象的东西更加具体或真实 可以查看这篇文章\ninline fun \u0026lt;reified T : Activity\u0026gt; Activity.startActivity() { startActivity(Intent(this, T::class.java)) } startActivity\u0026lt;NewActivity\u0026gt;()   as? 安全的类型转化。 a as b 如果a 为空则返回null 否则类型转化\nval nullorNot = ... val nullorNot as? Abc   基本数字类型\n   类型 大小（比特数） 最小值 最大值     Byte 8 -128 127   Short 16 -32768 32767   Int 32 -2,147,483,648 (-231) 2,147,483,647 (231 - 1)   Long 64 -9,223,372,036,854,775,808 (-263) 9,223,372,036,854,775,807 (263 - 1)    默认数字类型不超过int的范围推断为Int。可以通过在数字后面添加L 来显式地表明为Long型\n  sam 转化 single abstract method。只有一个方法的 接口可以通过kotlin 的转化成更加简洁的写法。\n  kotlin 集合分为 可变集合 和不可变集合\n  "});index.add({'id':23,'href':'/docs/android/binder/binder/','title':"Binder以及相关概念",'section':"Android",'content':"binder 的相关笔记 #  为什么要多进程 #   获得更多的内存 每个进程使用的内存大小通过 getprop dalivk.vm.heapsize可以 得到 风险隔离，每个进程不会影响别的进程  进程间通信 IPC 是为了什么 #   A调用B的方法 A获取B的数据 A传递数据给B之后再获取数据   linux 进程通信 #   管道 socket 共享内存 信号量 等等  binder 有什么优势（言下之义就是 和另外的进程间通信有什么优势） #   性能： \u0026ndash; binder：数据只拷贝一次 \u0026ndash; 共享内存：数据无需拷贝 \u0026ndash; socket： 拷贝两次 易用性： \u0026ndash; binder： 基于c/s 架构，易用性较高，降低了应用开发者的使用难度， \u0026ndash; 共享内存：同步处理进程数据，比较麻烦 \u0026ndash; socket： 通用接口，传输效率低，开销比较大 安全性： \u0026ndash; binder：实名，匿名， 每个应用分配一个uid \u0026ndash; 共享内存：依赖与上层协议，访问点开放不安全 \u0026ndash; 依赖与上层协议，访问接入点开放不安全  linux 基础 内核空间，用户空间。 #  内核态与用户态：\n（1）当一个任务（进程）执行系统调用而陷入内核代码中执行时，称进程处于内核运行态（内核态）。此时处理器处于特权级最高的（0级）内核代码中执行。当进程处于内核态时，执行的内核代码会使用当前进程的内核栈。每个进程都有自己的内核栈。\n（2）当进程在执行用户自己的代码时，则称其处于用户运行态（用户态）。此时处理器在特权级最低的（3级）用户代码中运行。当正在执行用户程序而突然被中断程序中断时，此时用户程序也可以象征性地称为处于进程的内核态。因为中断处理程序将使用当前进程的内核栈。\nbinder 一次拷贝， 共享内存 无需拷贝 why #   了解linux 基础 内核空间，用户空间。 \u0026ndash; https://www.cnblogs.com/sparkdev/p/8410350.html \u0026ndash; https://www.cnblogs.com/Anker/p/3269106.html \u0026ndash; https://blog.csdn.net/lvyibin890/article/details/82217193  binder 一次拷贝 #   binder 数据发送方 准备好数据 内核 通过 copy_from_user() copy 到存放到一块 共享物理内存 内核也mmap到这一块物理内存 数据接收方， 通过mmap 将这块内存映射起来。memory mapping 用户空间 可以操作文件吗？ 不可以，用户空间只能操作虚拟内存 mmap 可以将一块虚拟内存空间直接映射到一个 磁盘文件或者指定物理内存，当在用户空间修改文件内容时，就相当与直接操作物理内存或者文件。 mmap 在驱动中怎么实现的？后续学习  共享内存 无需拷贝 #   数据接受方，内核空间，数据接受方 全部mmap 到同一块区域   binder驱动 如何启动 #   linux 中 一切皆文件 binder 驱动 也是一个文件 可以被mmap  从栗子研究 binder 分层 以及底层逻辑 #   mermaid.initialize({ \"flowchart\": { \"useMaxWidth\":true }, \"theme\": \"default\" } ) graph TD; Client--BinderProxy; ServiceManager--BinderProxy; BinderProxy--JNI[\"Android Runtime and AndroidUtilBinder\"]; JNI--BpBinder; BpBinder -- ioctl -- Kernal[\"Kernal \\dev\\binder\"]; service_manager -- ioctl -- Kernal; Server--Binder; Binder--JNI; JNI--JavaBBinder; JavaBBinder--BBinder; BBinder -- ioctl ---- Kernal; BpBinder -.- BBinder BpBinder -.- service_manager; BBinder -.- service_manager;  Framework JNI Native Kernal  Kernal #   binder_init 注册binder驱动 binder_open 打开binder驱动 binder_ioctl 读写 binder_mmap 映射物理内存  Native #   ServiceManager  JNI #  Framework #  "});index.add({'id':24,'href':'/docs/android/Handler/','title':"Handler",'section':"Android",'content':"Handler #   handler 是学习中问得最常见的一个问题。而这一次我将从几个handler最常见的几个问题来开始学习这个问题\n  一个线程可以有几个Handler 一个线程可以有几个looper handler的内存泄漏的原因？为什么其他的内部类没有提说过有这个问题？ 为何主线程可以new Handler？ 如果想要在子线程中new handler要做些什么准备？ 子线程中维护的Looper，消息队列无消息的时候的处理方案是什么？有什么用？ 既然可以存在多个Handler 往MessageQueue中add 数据，那内部是如何确保线程数据安全的？ 我们使用Message 时应该如何创建它？ 使用Handler的postDelay后消息队列会有什么变化？ looper死循环为什么不会导致应用卡死？  那么我将会从源码的角度上开始分析这几个问题。 #    开篇 handler在线源码\n 先来看看我们的最常见的使用handler的方式\nHandler handler = new Handler() { @Override public void handleMessage(Message msg) { super.handleMessage(msg); switch (msg.what) { case 1: break; } } }; handler.sendEmptyMessage(1); 然后我们从源码中分析，所有的 send post 方法最终都会调用到 enqueueMessage\n private boolean enqueueMessage(MessageQueue queue, Message msg, long uptimeMillis) { msg.target = this; if (mAsynchronous) { msg.setAsynchronous(true); } return queue.enqueueMessage(msg, uptimeMillis); } 那么我们下一步就要探寻queue.enqueueMessage 里面做了什么。这一步我们看到 queue来自于 Looper\n// Handler.java  mQueue = mLooper.mQueue;// // Looper.java  mQueue = new MessageQueue(quitAllowed);//  MessageQueue.java\nboolean enqueueMessage(Message msg, long when) { if (msg.target == null) { throw new IllegalArgumentException(\u0026#34;Message must have a target.\u0026#34;); } if (msg.isInUse()) { throw new IllegalStateException(msg + \u0026#34; This message is already in use.\u0026#34;); } synchronized (this) { if (mQuitting) { IllegalStateException e = new IllegalStateException( msg.target + \u0026#34; sending message to a Handler on a dead thread\u0026#34;); Log.w(TAG, e.getMessage(), e); msg.recycle(); return false; } msg.markInUse(); msg.when = when; Message p = mMessages; boolean needWake; if (p == null || when == 0 || when \u0026lt; p.when) { // New head, wake up the event queue if blocked.  msg.next = p; mMessages = msg; needWake = mBlocked; } else { // Inserted within the middle of the queue. Usually we don\u0026#39;t have to wake  // up the event queue unless there is a barrier at the head of the queue  // and the message is the earliest asynchronous message in the queue.  needWake = mBlocked \u0026amp;\u0026amp; p.target == null \u0026amp;\u0026amp; msg.isAsynchronous(); Message prev; for (;;) { prev = p; p = p.next; if (p == null || when \u0026lt; p.when) { break; } if (needWake \u0026amp;\u0026amp; p.isAsynchronous()) { needWake = false; } } msg.next = p; // invariant: p == prev.next  prev.next = msg; } // We can assume mPtr != 0 because mQuitting is false.  if (needWake) { nativeWake(mPtr); } } return true; } private native void nativePollOnce(long ptr, int timeoutMillis); /*non-static for callbacks*/ private native static void nativeWake(long ptr); 从里面我们可以看到 equeueMessage 只是将message 插入到队列中，至于怎么插入的我们后面再说。 在插入之后这个message 会怎么执行呢，重点在执行nativeWake(mPtr); 这一句上。 课外阅读native 代码地址 android_os_MessageQueue.cpp\n在这里会做一个唤醒，既然有唤醒，就会有沉睡，那么我们来看messagequeue 在哪里调用沉睡的方法nativePollOnce\nMessage next() { // Return here if the message loop has already quit and been disposed.  // This can happen if the application tries to restart a looper after quit  // which is not supported.  final long ptr = mPtr; if (ptr == 0) { return null; } int pendingIdleHandlerCount = -1; // -1 only during first iteration  int nextPollTimeoutMillis = 0; for (;;) { if (nextPollTimeoutMillis != 0) { Binder.flushPendingCommands(); } // 看这里看这里看这里  nativePollOnce(ptr, nextPollTimeoutMillis); synchronized (this) { // Try to retrieve the next message. Return if found.  final long now = SystemClock.uptimeMillis(); Message prevMsg = null; Message msg = mMessages; if (msg != null \u0026amp;\u0026amp; msg.target == null) { // Stalled by a barrier. Find the next asynchronous message in the queue.  do { prevMsg = msg; msg = msg.next; } while (msg != null \u0026amp;\u0026amp; !msg.isAsynchronous()); } if (msg != null) { if (now \u0026lt; msg.when) { // Next message is not ready. Set a timeout to wake up when it is ready.  nextPollTimeoutMillis = (int) Math.min(msg.when - now, Integer.MAX_VALUE); } else { // Got a message.  mBlocked = false; if (prevMsg != null) { prevMsg.next = msg.next; } else { mMessages = msg.next; } msg.next = null; if (DEBUG) Log.v(TAG, \u0026#34;Returning message: \u0026#34; + msg); msg.markInUse(); return msg; } } else { // No more messages.  nextPollTimeoutMillis = -1; } // Process the quit message now that all pending messages have been handled.  if (mQuitting) { dispose(); return null; } // If first time idle, then get the number of idlers to run.  // Idle handles only run if the queue is empty or if the first message  // in the queue (possibly a barrier) is due to be handled in the future.  if (pendingIdleHandlerCount \u0026lt; 0 \u0026amp;\u0026amp; (mMessages == null || now \u0026lt; mMessages.when)) { pendingIdleHandlerCount = mIdleHandlers.size(); } if (pendingIdleHandlerCount \u0026lt;= 0) { // No idle handlers to run. Loop and wait some more.  mBlocked = true; continue; } if (mPendingIdleHandlers == null) { mPendingIdleHandlers = new IdleHandler[Math.max(pendingIdleHandlerCount, 4)]; } mPendingIdleHandlers = mIdleHandlers.toArray(mPendingIdleHandlers); } // Run the idle handlers.  // We only ever reach this code block during the first iteration.  for (int i = 0; i \u0026lt; pendingIdleHandlerCount; i++) { final IdleHandler idler = mPendingIdleHandlers[i]; mPendingIdleHandlers[i] = null; // release the reference to the handler  boolean keep = false; try { keep = idler.queueIdle(); } catch (Throwable t) { Log.wtf(TAG, \u0026#34;IdleHandler threw exception\u0026#34;, t); } if (!keep) { synchronized (this) { mIdleHandlers.remove(idler); } } } // Reset the idle handler count to 0 so we do not run them again.  pendingIdleHandlerCount = 0; // While calling an idle handler, a new message could have been delivered  // so go back and look again for a pending message without waiting.  nextPollTimeoutMillis = 0; } } 这里的大概流程就是按照当前的队列找到 队头的message 取出并返回，然后继续等待。 如果有下一个message则等待 一段时间（视下一个message的delay决定）或者等待唤醒。\n还差最后一步2,那么是谁来嗲用message 的next的呢？ 是Looper\n/** * Run the message queue in this thread. Be sure to call * {@link #quit()} to end the loop. */ public static void loop() { final Looper me = myLooper(); if (me == null) { throw new RuntimeException(\u0026#34;No Looper; Looper.prepare() wasn\u0026#39;t called on this thread.\u0026#34;); } final MessageQueue queue = me.mQueue; // Make sure the identity of this thread is that of the local process,  // and keep track of what that identity token actually is.  Binder.clearCallingIdentity(); final long ident = Binder.clearCallingIdentity(); // Allow overriding a threshold with a system prop. e.g.  // adb shell \u0026#39;setprop log.looper.1000.main.slow 1 \u0026amp;\u0026amp; stop \u0026amp;\u0026amp; start\u0026#39;  final int thresholdOverride = SystemProperties.getInt(\u0026#34;log.looper.\u0026#34; + Process.myUid() + \u0026#34;.\u0026#34; + Thread.currentThread().getName() + \u0026#34;.slow\u0026#34;, 0); boolean slowDeliveryDetected = false; for (;;) { Message msg = queue.next(); // might block  if (msg == null) { // No message indicates that the message queue is quitting.  return; } // This must be in a local variable, in case a UI event sets the logger  final Printer logging = me.mLogging; if (logging != null) { logging.println(\u0026#34;\u0026gt;\u0026gt;\u0026gt;\u0026gt;\u0026gt; Dispatching to \u0026#34; + msg.target + \u0026#34; \u0026#34; + msg.callback + \u0026#34;: \u0026#34; + msg.what); } final long traceTag = me.mTraceTag; long slowDispatchThresholdMs = me.mSlowDispatchThresholdMs; long slowDeliveryThresholdMs = me.mSlowDeliveryThresholdMs; if (thresholdOverride \u0026gt; 0) { slowDispatchThresholdMs = thresholdOverride; slowDeliveryThresholdMs = thresholdOverride; } final boolean logSlowDelivery = (slowDeliveryThresholdMs \u0026gt; 0) \u0026amp;\u0026amp; (msg.when \u0026gt; 0); final boolean logSlowDispatch = (slowDispatchThresholdMs \u0026gt; 0); final boolean needStartTime = logSlowDelivery || logSlowDispatch; final boolean needEndTime = logSlowDispatch; if (traceTag != 0 \u0026amp;\u0026amp; Trace.isTagEnabled(traceTag)) { Trace.traceBegin(traceTag, msg.target.getTraceName(msg)); } final long dispatchStart = needStartTime ? SystemClock.uptimeMillis() : 0; final long dispatchEnd; try { msg.target.dispatchMessage(msg); dispatchEnd = needEndTime ? SystemClock.uptimeMillis() : 0; } finally { if (traceTag != 0) { Trace.traceEnd(traceTag); } } if (logSlowDelivery) { if (slowDeliveryDetected) { if ((dispatchStart - msg.when) \u0026lt;= 10) { Slog.w(TAG, \u0026#34;Drained\u0026#34;); slowDeliveryDetected = false; } } else { if (showSlowLog(slowDeliveryThresholdMs, msg.when, dispatchStart, \u0026#34;delivery\u0026#34;, msg)) { // Once we write a slow delivery log, suppress until the queue drains.  slowDeliveryDetected = true; } } } if (logSlowDispatch) { showSlowLog(slowDispatchThresholdMs, dispatchStart, dispatchEnd, \u0026#34;dispatch\u0026#34;, msg); } if (logging != null) { logging.println(\u0026#34;\u0026lt;\u0026lt;\u0026lt;\u0026lt;\u0026lt; Finished to \u0026#34; + msg.target + \u0026#34; \u0026#34; + msg.callback); } // Make sure that during the course of dispatching the  // identity of the thread wasn\u0026#39;t corrupted.  final long newIdent = Binder.clearCallingIdentity(); if (ident != newIdent) { Log.wtf(TAG, \u0026#34;Thread identity changed from 0x\u0026#34; + Long.toHexString(ident) + \u0026#34; to 0x\u0026#34; + Long.toHexString(newIdent) + \u0026#34; while dispatching to \u0026#34; + msg.target.getClass().getName() + \u0026#34; \u0026#34; + msg.callback + \u0026#34; what=\u0026#34; + msg.what); } msg.recycleUnchecked(); } } Looper.loop() 方法是一个无限循环，从messagequeue 取出消息之后就dispatch分发这个message处理msg.target.dispatchMessage(msg); 那么现在我们可以看到这handler的大郅流程如下 looper 从mq 中去取数据 如果取不到就等待block在next上。 取到之后就在loop() 方法里面就地分发。 而handler则负责往mq 里面塞message。\n至于最开始\nHandler handler = new Handler() { @Override public void handleMessage(Message msg) { super.handleMessage(msg); switch (msg.what) { case 1: break; } } }; 里面的handlemessage 怎么回调的，那我们再从头追述一下。\n//Handler.java private boolean enqueueMessage(MessageQueue queue, Message msg, long uptimeMillis) { msg.target = this;//看这里  if (mAsynchronous) { msg.setAsynchronous(true); } return queue.enqueueMessage(msg, uptimeMillis); } /** * Handle system messages here. */ public void dispatchMessage(Message msg) { if (msg.callback != null) { handleCallback(msg); } else { if (mCallback != null) { if (mCallback.handleMessage(msg)) { return; } } handleMessage(msg); } } 看到没有这里有个msg.target = this;而这一句也是我们常说的 handler容易导致内存泄漏的问题。\n// Looper.java msg.target.dispatchMessage(msg); 那么结合刚刚看的looper的源码就可以知道 Looper 中调用了 handler的 dispatchMessage 而dispatchMessage 中就调用了hanlderMessage 从这个方法里面我们也可以看到 如果设置了 callback 就不会调用 handleMessage了。\n结合上一篇Handler 整体流程通关 的源码初步分析，我们一个一个来分析问题： #一个线程可以有几个handler 如果使用过handler的同学都知道在实际使用过程中可以有无数个handler。\n#一个线程可以有几个looper 一个线程可以有几个looper 那么就要分析looper的源码\nprivate static void prepare(boolean quitAllowed) { if (sThreadLocal.get() != null) { throw new RuntimeException(\u0026#34;Only one Looper may be created per thread\u0026#34;); } sThreadLocal.set(new Looper(quitAllowed)); } public static void prepareMainLooper() { prepare(false); synchronized (Looper.class) { if (sMainLooper != null) { throw new IllegalStateException(\u0026#34;The main Looper has already been prepared.\u0026#34;); } sMainLooper = myLooper(); } } Looper在使用之前必须prepare 在prepare 里面使用了 ThreadLocal， 看我的这篇文章 在这里保证了一个线程只能有一个Looper\n#handler的内存泄漏的原因？为什么其他的内部类没有提说过有这个问题？ 在上一篇 源码分析的文章里面已经说过了啊，在调用到 enqueueMessage 的是否会将 handler赋值给 message的target，而Message 在 messagequeue中等待的时候如果生命周期发生变化但是message中的target不释放就会导致泄漏，毕竟内存泄漏就是生命周期不相等导致的\n#为何主线程可以new Handler？ 如果想要在子线程中new Handler要做些什么准备？\nnew Thread() { @Override public void run() { Handler handler = new Handler(); handler.post(new Runnable() { @Override public void run() { } }); } }.start(); 我们在子线程中这样运行是不会生效的\npublic boolean sendMessageAtTime(Message msg, long uptimeMillis) { MessageQueue queue = mQueue; if (queue == null) { RuntimeException e = new RuntimeException( this + \u0026#34; sendMessageAtTime() called with no mQueue\u0026#34;); Log.w(\u0026#34;Looper\u0026#34;, e.getMessage(), e); return false; } return enqueueMessage(queue, msg, uptimeMillis); } 所以为什么主线程的Handler 可以正确运行，必然是主线程的Handler里面的MessageQueue 是ready的 而我们又知道 messagequeue来之于looper。所以主线程必然在某个时间准备好了Looper，那么我们就去看主线程的启动地方。\n//ActivityThread.java  public static void main(String[] args) { Trace.traceBegin(Trace.TRACE_TAG_ACTIVITY_MANAGER, \u0026#34;ActivityThreadMain\u0026#34;); // CloseGuard defaults to true and can be quite spammy. We  // disable it here, but selectively enable it later (via  // StrictMode) on debug builds, but using DropBox, not logs.  CloseGuard.setEnabled(false); Environment.initForCurrentUser(); // Set the reporter for event logging in libcore  EventLogger.setReporter(new EventLoggingReporter()); // Make sure TrustedCertificateStore looks in the right place for CA certificates  final File configDir = Environment.getUserConfigDirectory(UserHandle.myUserId()); TrustedCertificateStore.setDefaultUserDirectory(configDir); Process.setArgV0(\u0026#34;\u0026lt;pre-initialized\u0026gt;\u0026#34;); //看这里  Looper.prepareMainLooper(); // Find the value for {@link #PROC_START_SEQ_IDENT} if provided on the command line.  // It will be in the format \u0026#34;seq=114\u0026#34;  long startSeq = 0; if (args != null) { for (int i = args.length - 1; i \u0026gt;= 0; --i) { if (args[i] != null \u0026amp;\u0026amp; args[i].startsWith(PROC_START_SEQ_IDENT)) { startSeq = Long.parseLong( args[i].substring(PROC_START_SEQ_IDENT.length())); } } } ActivityThread thread = new ActivityThread(); thread.attach(false, startSeq); if (sMainThreadHandler == null) { sMainThreadHandler = thread.getHandler(); } if (false) { Looper.myLooper().setMessageLogging(new LogPrinter(Log.DEBUG, \u0026#34;ActivityThread\u0026#34;)); } // End of event ActivityThreadMain.  Trace.traceEnd(Trace.TRACE_TAG_ACTIVITY_MANAGER); Looper.loop(); throw new RuntimeException(\u0026#34;Main thread loop unexpectedly exited\u0026#34;); } 在这个方法里面，looper在Looper.prepareMainLooper(); 之后做好准备工作之后 就开始调用loop 开始取消息，所有的 生命周期，我们都是通过message来驱动的。Looper中private static Looper sMainLooper; 存在这个变量更是确保了一个进程只有一个 sMainLooper，当然会有一些锁来确保线程安全。 如果想要在子线程中new Handler要做些什么准备？ 在创建之前 调用looper的prepare 即可。\nnew Thread() { @Override public void run() { Looper.prepare(); Handler handler = new Handler(); handler.post(new Runnable() { @Override public void run() { } }); Looper.loop(); } }.start(); #子线程中维护的Looper，消息队列无消息的时候的处理方案是什么？有什么用？ 这里有两种解释。\n 第一种：上一篇文章我们就说到了 loop() 方法会不断的去调用messagequeue的next() 方法。代码就不贴了，最终会在调用nativePollOnce(ptr, nextPollTimeoutMillis); 这一步时卡住，此时线程就休眠了，等待下一次的nativeWake 或者timeout自动唤醒。 这样做有什么好处呢，节约cpu。 第二种：当消息队列无消息的时候以为着什么 这个子线程已经无用了，可以推出了，这时候问的就是该如何退出。  //Looper.java  public void quit() { mQueue.quit(false); } public void quitSafely() { mQueue.quit(true); } //MessageQueue.java  void quit(boolean safe) { if (!mQuitAllowed) { throw new IllegalStateException(\u0026#34;Main thread not allowed to quit.\u0026#34;); } synchronized (this) { if (mQuitting) { return; } mQuitting = true; if (safe) { removeAllFutureMessagesLocked(); } else { removeAllMessagesLocked(); } // We can assume mPtr != 0 because mQuitting was previously false.  nativeWake(mPtr); } } private void removeAllMessagesLocked() { Message p = mMessages; while (p != null) { Message n = p.next; p.recycleUnchecked(); p = n; } mMessages = null; } private void removeAllFutureMessagesLocked() { final long now = SystemClock.uptimeMillis(); Message p = mMessages; if (p != null) { if (p.when \u0026gt; now) { removeAllMessagesLocked(); } else { Message n; for (;;) { n = p.next; if (n == null) { return; } if (n.when \u0026gt; now) { break; } p = n; } p.next = null; do { p = n; n = p.next; p.recycleUnchecked(); } while (n != null); } } }  quit 和quit safely的区别看这里\u0026ndash;未发布 这里主要是把message 全部删除。 在Looper.loop 方法中\n for (;;) { Message msg = queue.next(); // might block // 这里如果不退出这里必然返回的不为空，要么block在这，要么返回一个非空值， //只有在退出时，清空队列，并且唤醒block 这里才会返回null 从而退出 if (msg == null) { // No message indicates that the message queue is quitting. return; } 。。。 当取出的message 为null时将会推出loop ，线程也自动结束了\n有什么用？\n//Message.java  void recycleUnchecked() { // Mark the message as in use while it remains in the recycled object pool.  // Clear out all other details.  flags = FLAG_IN_USE; what = 0; arg1 = 0; arg2 = 0; obj = null; replyTo = null; sendingUid = -1; when = 0; target = null; callback = null; data = null; synchronized (sPoolSync) { if (sPoolSize \u0026lt; MAX_POOL_SIZE) { next = sPool; sPool = this; sPoolSize++; } } } 在这里会清空message的target callback data等内容，可以释放内存，避免内存泄漏。 #既然可以存在多个handler 往mq中add 数据，那内部是如何确保线程数据安全的？\n//MessageQueue.java  boolean enqueueMessage(Message msg, long when) { if (msg.target == null) { throw new IllegalArgumentException(\u0026#34;Message must have a target.\u0026#34;); } if (msg.isInUse()) { throw new IllegalStateException(msg + \u0026#34; This message is already in use.\u0026#34;); } synchronized (this) { if (mQuitting) { IllegalStateException e = new IllegalStateException( msg.target + \u0026#34; sending message to a Handler on a dead thread\u0026#34;); Log.w(TAG, e.getMessage(), e); msg.recycle(); return false; } ... 在这里加锁了，synchronized (this) 那么synchronized 锁的内容不同有什么区别呢\u0026ndash; 未发布 #我们使用Message 时应该如何创建它？ Message 我们可以直接new 也可以 通过obtain 来获取复用的 message 实例。 那么这里问的就是obtain 的运作逻辑和为什么要用obtain\n//Message.java public static Message obtain() { synchronized (sPoolSync) { if (sPool != null) { Message m = sPool; sPool = m.next; m.next = null; m.flags = 0; // clear in-use flag  sPoolSize--; return m; } } return new Message(); } 这里用了一个享元模式，Message 是Android系统中很常见的一个类，如果我们每次使用都new的话 ，这个内存就抖动起来了呀。 这里也是为了避免过多的内存创建销毁的过程，平稳使用内存。 #使用Handler的postDelay后消息队列会有什么变化\n//Handler.java  public final boolean postDelayed(Runnable r, long delayMillis) { return sendMessageDelayed(getPostMessage(r), delayMillis); } public final boolean sendMessageDelayed(Message msg, long delayMillis) { if (delayMillis \u0026lt; 0) { delayMillis = 0; } return sendMessageAtTime(msg, SystemClock.uptimeMillis() + delayMillis); } public boolean sendMessageAtTime(Message msg, long uptimeMillis) { MessageQueue queue = mQueue; if (queue == null) { RuntimeException e = new RuntimeException( this + \u0026#34; sendMessageAtTime() called with no mQueue\u0026#34;); Log.w(\u0026#34;Looper\u0026#34;, e.getMessage(), e); return false; } return enqueueMessage(queue, msg, uptimeMillis); } 我们可以看到在调用enqueueMessage的之前都是传入了一个时间值，而在messagequeue的源码中，message也是按照时间顺序排列的 一个队列。在插入之后会查看是否需要wake。如果我们插入的是一个time为0的时候messagequeue会立刻唤醒，如果插入的是一个延迟任务，将不会唤醒messagequeue。\nlooper死循环为什么不会导致应用卡死？ #    源码 借用这篇文章你可以知道service boradcast provider anr 的原理 借用这篇文章 你可以知道 input的 anr  这里你可以看到 为什么会anr 总结起来都是 有某些地方发送了 timeout的 message ，然后hander 处理了这个message。 而当 looper 就是循环读取messagequeue的message 然后处理，如果没有message 就等待 这时候 的等待是不可能达成这个anr的逻辑的。\n"});index.add({'id':25,'href':'/docs/android/view/view/','title':"View ",'section':"View",'content':"view 绘制逻辑\n"});index.add({'id':26,'href':'/docs/arch/','title':"Arch",'section':"Docs",'content':"Jetpack Dagger\n"});index.add({'id':27,'href':'/docs/kotlin/coroutines/how-to-use/','title':"Kotlin 协程 - 怎么使用",'section':"Kotlin 协程本质",'content':" 参考文档 https://www.jianshu.com/u/a324daa6fa19\n 添加依赖 #  kotlin的标准库中有kotlin的协程基础的库，我们现在只关注如何使用协程，重要的部分都在这个库里。（原理在下一篇文章中）。\nimplementation \u0026#39;org.jetbrains.kotlinx:kotlinx-coroutines-core:1.4.2\u0026#39; kotlin 的版本必须在1.4.10 之上\n基础使用 launch #  fun main() { GlobalScope.launch { delay(500) println(\u0026#34;in global scope ${Thread.currentThread().name}\u0026#34;) } Thread.sleep(1000)// 由于globalscope的生命周期是跟随主线程的 所以这里不sleep的话会导致协程被取消  println(\u0026#34;thread sleep ${Thread.currentThread().name}\u0026#34;) } kotlin 在jvm上的实现是依赖于 java的thread的，所以我们可以在协程体中获取到相关的Thread的信息，并且也可以使用Thread的方法\n  我们来看看其中的launch 方法\npublic fun CoroutineScope.launch( context: CoroutineContext = EmptyCoroutineContext, start: CoroutineStart = CoroutineStart.DEFAULT, block: suspend CoroutineScope.() -\u0026gt; Unit ): Job   context：协程上下文。类似于一个list的概念，其中包含了协程运行的各个参数。具体概念之后介绍。\n  start：启动模式\n  DEFAULT：允许协程马上开始执行。允许在协程运行之前取消。\n  LAZY：需要调用job的start方法，来允许协程马上开始执行。\nsuspend fun main() { println(\u0026#34;start in ${Thread.currentThread().name}\u0026#34;) val job = GlobalScope.launch(start = CoroutineStart.LAZY) { println(\u0026#34;in global scope ${Thread.currentThread().name}==== start\u0026#34;) delay(500) println(\u0026#34;in global scope ${Thread.currentThread().name}==== end\u0026#34;) } println(\u0026#34;job is defined in ${Thread.currentThread().name}\u0026#34;) job.start() Thread.sleep(1000) // 由于globalscope的生命周期是跟随主线程的 所以这里不sleep的话会导致协程被取消  println(\u0026#34;end in ${Thread.currentThread().name}\u0026#34;) } /* start in main job is defined in main in global scope DefaultDispatcher-worker-1 ==== start in global scope DefaultDispatcher-worker-1 ==== end end in main */   ATOMIC：与DEFAULT相似，只是协程一定会运行到第一个挂起点（suspend 函数）\n@ExperimentalCoroutinesApi suspend fun main() { println(\u0026#34;start in ${Thread.currentThread().name}\u0026#34;) val job = GlobalScope.launch(start = CoroutineStart.ATOMIC) { println(\u0026#34;in global scope ${Thread.currentThread().name}==== start\u0026#34;) delay(500) println(\u0026#34;in global scope ${Thread.currentThread().name}==== end\u0026#34;) } //job.cancelAndJoin()  println(\u0026#34;end in ${Thread.currentThread().name}\u0026#34;) //Thread.sleep(1000) } /* start in main end in main in global scope DefaultDispatcher-worker-2 ==== start ====== 也有可能是这样 ====== 为什么会这样？todo start in main end in main */   UNDISPATCHED：先不调度执行，等到第一个挂起点再调度。\n@ExperimentalCoroutinesApi suspend fun main() { println(\u0026#34;start in ${Thread.currentThread().name}\u0026#34;) val job = GlobalScope.launch(start = CoroutineStart.UNDISPATCHED) { println(\u0026#34;in global scope ${Thread.currentThread().name}==== start\u0026#34;) delay(500) println(\u0026#34;in global scope ${Thread.currentThread().name}==== end\u0026#34;) } Thread.sleep(1000) println(\u0026#34;end in ${Thread.currentThread().name}\u0026#34;) } /* result start in main in global scope main ==== start in global scope DefaultDispatcher-worker-1 ==== end end in main */ public suspend fun delay(timeMillis: Long) { /*...*/ }     block：协程的代码块\n  Job:返回一个job\npublic interface Job : CoroutineContext.Element { /*...*/ public fun start(): Boolean public fun cancel(cause: CancellationException? = null) public fun cancel(): Unit = cancel(null) public fun cancel(cause: Throwable? = null): Boolean /*...*/ public suspend fun join() /*...*/ } 与rxjava 类似返回一个disposable一样用于控制这个协程体的引用\n    基础使用 async #  suspend fun main() { println(\u0026#34;start in ${Thread.currentThread().name}\u0026#34;) val deferred = GlobalScope.async { println(\u0026#34;in global scope ${Thread.currentThread().name}==== start\u0026#34;) delay(500) println(\u0026#34;in global scope ${Thread.currentThread().name}==== end\u0026#34;) } println(\u0026#34;deferred is defined in ${Thread.currentThread().name}\u0026#34;) deferred.await() // 这个方法需要在suspend 方法中调用  Thread.sleep(1000) println(\u0026#34;end in ${Thread.currentThread().name}\u0026#34;) } /* start in main deferred is defined in main in global scope DefaultDispatcher-worker-1 ==== start in global scope DefaultDispatcher-worker-1 ==== end end in DefaultDispatcher-worker-1 */ 我们来看一下async方法的实现\npublic fun \u0026lt;T\u0026gt; CoroutineScope.async( context: CoroutineContext = EmptyCoroutineContext, start: CoroutineStart = CoroutineStart.DEFAULT, block: suspend CoroutineScope.() -\u0026gt; T ): Deferred\u0026lt;T\u0026gt; 这里与launch相同，除了返回值不同。那么来看看Deferred的代码\npublic interface Deferred\u0026lt;out T\u0026gt; : Job { public suspend fun await(): T public val onAwait: SelectClause1\u0026lt;T\u0026gt; public fun getCompleted(): T public fun getCompletionExceptionOrNull(): Throwable? }   await：挂起当前协程，直到async启动的子协程执行完成。\n  SelectClause1： select 之后再说\n  getCompleted：\nsuspend fun main() { println(\u0026#34;start in ${Thread.currentThread().name}\u0026#34;) val deferred = GlobalScope.async { println(\u0026#34;in global scope ${Thread.currentThread().name}==== start\u0026#34;) delay(500) println(\u0026#34;in global scope ${Thread.currentThread().name}==== end\u0026#34;) } println(\u0026#34;deferred is defined in ${Thread.currentThread().name}\u0026#34;) deferred.invokeOnCompletion { println(\u0026#34;getCompleted in invokeOnCompletion is ${deferred.getCompleted()}\u0026#34;) } Thread.sleep(1000) println(\u0026#34;end in ${Thread.currentThread().name}\u0026#34;) } /* start in main in global scope DefaultDispatcher-worker-1 ==== start deferred is defined in main in global scope DefaultDispatcher-worker-1 ==== end getCompleted in invokeOnCompletion is kotlin.Unit end in main */   getCompletionExceptionOrNull：\n与getCompleted一致\n  async的几种用法\nsuspend fun doSomethingUsefulOne(): Int { delay(1000) return 1000 } suspend fun doSomethingUsefulTwo(): Int { delay(500) return 500 } suspend fun concurrentSum(): Int = coroutineScope { val one = async { doSomethingUsefulOne() } val two = async { doSomethingUsefulTwo() } one.await() + two.await() } fun main() { log(\u0026#34;start in ${Thread.currentThread().name}\u0026#34;) runBlocking { val time = measureTimeMillis { log(\u0026#34;The answer is ${concurrentSum()}\u0026#34;) } log(\u0026#34;Completed in $timems\u0026#34;) } log(\u0026#34;end in ${Thread.currentThread().name}\u0026#34;) } 基础作用withContext #  fun \u0026lt;T\u0026gt; log(t: T) { println(\u0026#34;[${Thread.currentThread().name}] $t\u0026#34;) } fun main() { newSingleThreadContext(\u0026#34;Ctx1\u0026#34;).use { ctx1 -\u0026gt; newSingleThreadContext(\u0026#34;Ctx2\u0026#34;).use { ctx2 -\u0026gt; runBlocking(ctx1) { log(\u0026#34;Started in ctx1\u0026#34;) withContext(ctx2) { log(\u0026#34;Working in ctx2\u0026#34;) } log(\u0026#34;Back to ctx1\u0026#34;) } } } } /* [Ctx1] Started in ctx1 [Ctx2] Working in ctx2 [Ctx1] Back to ctx1 */ 基础作用withTimeout #  fun \u0026lt;T\u0026gt; log(t: T) { println(\u0026#34;${DateTime.now().toString(\u0026#34;YYYY-MM-DD HH:mm:ss:SSS\u0026#34;)}\u0026gt;_ [${Thread.currentThread().name}] $t\u0026#34;) } suspend fun main() { log(\u0026#34;start in ${Thread.currentThread().name}\u0026#34;) withTimeout(1000) { log(\u0026#34;in global scope ${Thread.currentThread().name}==== start\u0026#34;) delay(2000) log(\u0026#34;in global scope ${Thread.currentThread().name}==== end\u0026#34;) } Thread.sleep(1000) log(\u0026#34;end in ${Thread.currentThread().name}\u0026#34;) } public suspend fun \u0026lt;T\u0026gt; withTimeout(timeMillis: Long, block: suspend CoroutineScope.() -\u0026gt; T): T 拦截器 #  fun myLog(msg: String) { println(\u0026#34;${DateTime.now().toString(\u0026#34;HH:mm:ss:SSS\u0026#34;)}@[${Thread.currentThread().name}] \u0026gt;\u0026gt; $msg\u0026#34;) } suspend fun main() { GlobalScope.launch(MyContinuationInterceptor()) { myLog(\u0026#34;1\u0026#34;) synchronized(this) { } val job = async { myLog(\u0026#34;2\u0026#34;) delay(1000) myLog(\u0026#34;3\u0026#34;) \u0026#34;Hello\u0026#34; } myLog(\u0026#34;4\u0026#34;) val result = job.await() myLog(\u0026#34;5. $result\u0026#34;) }.join() myLog(\u0026#34;6\u0026#34;) } class MyContinuationInterceptor : ContinuationInterceptor { override val key = ContinuationInterceptor override fun \u0026lt;T\u0026gt; interceptContinuation(continuation: Continuation\u0026lt;T\u0026gt;) = MyContinuation(continuation) } class MyContinuation\u0026lt;T\u0026gt;(val continuation: Continuation\u0026lt;T\u0026gt;) : Continuation\u0026lt;T\u0026gt; { override val context = continuation.context override fun resumeWith(result: Result\u0026lt;T\u0026gt;) { myLog(\u0026#34;\u0026lt;MyContinuation\u0026gt; $result\u0026#34;) continuation.resumeWith(result) } } /* 21:06:11:823@[main] \u0026gt;\u0026gt; \u0026lt;MyContinuation\u0026gt; Success(kotlin.Unit) 21:06:11:874@[main] \u0026gt;\u0026gt; 1 21:06:11:874@[main] \u0026gt;\u0026gt; 1.5 21:06:11:877@[main] \u0026gt;\u0026gt; \u0026lt;MyContinuation\u0026gt; Success(kotlin.Unit) 21:06:11:878@[main] \u0026gt;\u0026gt; 2 21:06:11:887@[main] \u0026gt;\u0026gt; 4 21:06:12:886@[kotlinx.coroutines.DefaultExecutor] \u0026gt;\u0026gt; \u0026lt;MyContinuation\u0026gt; Success(kotlin.Unit) 21:06:12:886@[kotlinx.coroutines.DefaultExecutor] \u0026gt;\u0026gt; 3 21:06:12:888@[kotlinx.coroutines.DefaultExecutor] \u0026gt;\u0026gt; \u0026lt;MyContinuation\u0026gt; Success(Hello) 21:06:12:888@[kotlinx.coroutines.DefaultExecutor] \u0026gt;\u0026gt; 5. Hello 21:06:12:888@[kotlinx.coroutines.DefaultExecutor] \u0026gt;\u0026gt; 6 */ suspend #   标记和提醒  将包含耗时任务的函数标记为suspend   编译器将根据suspend函数来处理字节码  scope #  public interface CoroutineScope { public val coroutineContext: CoroutineContext } public val CoroutineScope.isActive: Boolean public fun CoroutineScope.cancel(cause: CancellationException? = null) public fun CoroutineScope.ensureActive() val scope = CoroutineScope(SupervisorJob() + Dispatchers.IO) scope.launch { log(\u0026#34;start\u0026#34;) launch(SupervisorJob()) { log(\u0026#34;start 2\u0026#34;) delay(2000) log(\u0026#34;end 2\u0026#34;) } log(\u0026#34;end\u0026#34;) } Thread.sleep(1000) scope.cancel() Thread.sleep(Long.MAX_VALUE) /* 17:30:24:664@[DefaultDispatcher-worker-2] \u0026gt;\u0026gt; start 17:30:24:732@[DefaultDispatcher-worker-2] \u0026gt;\u0026gt; end 17:30:24:732@[DefaultDispatcher-worker-3] \u0026gt;\u0026gt; start 2 17:30:26:739@[DefaultDispatcher-worker-3] \u0026gt;\u0026gt; end 2 */ public fun CoroutineScope.cancel(cause: CancellationException? = null) { val job = coroutineContext[Job] ?: error(\u0026#34;Scope cannot be cancelled because it does not have a job: $this\u0026#34;) job.cancel(cause) } 从cancel中可以看出 是获取到当前的这个协程的上下文中的job属性调用这个job的cancel。这样是不会取消这个子协程的运行的。（如果子协程和父协程用的不是同一个job的话）\n"});index.add({'id':28,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/aqs/','title':"多线程--aqs",'section':"多线程",'content':"aqs 的简介 #    aqs 为什么开发工作中没有感知到呢？\n  同步工具类都是继承自aqs。\n  模版方法设计模式。 类似于draw（canvas） 中的 这个\n protected void dispatchDraw(Canvas canvas) { } protected void onDraw(Canvas canvas) { } public void draw(Canvas canvas) { final int privateFlags = mPrivateFlags; mPrivateFlags = (privateFlags \u0026amp; ~PFLAG_DIRTY_MASK) | PFLAG_DRAWN; /* * Draw traversal performs several drawing steps which must be executed * in the appropriate order: * * 1. Draw the background * 2. If necessary, save the canvas' layers to prepare for fading * 3. Draw view's content * 4. Draw children * 5. If necessary, draw the fading edges and restore layers * 6. Draw decorations (scrollbars for instance) * 7. If necessary, draw the default focus highlight */ // Step 1, draw the background, if needed int saveCount; drawBackground(canvas); // skip step 2 \u0026amp; 5 if possible (common case) final int viewFlags = mViewFlags; boolean horizontalEdges = (viewFlags \u0026amp; FADING_EDGE_HORIZONTAL) != 0; boolean verticalEdges = (viewFlags \u0026amp; FADING_EDGE_VERTICAL) != 0; if (!verticalEdges \u0026amp;\u0026amp; !horizontalEdges) { // Step 3, draw the content onDraw(canvas); // Step 4, draw the children dispatchDraw(canvas); drawAutofilledHighlight(canvas); // Overlay is part of the content and draws b eneath Foreground if (mOverlay != null \u0026amp;\u0026amp; !mOverlay.isEmpty()) { mOverlay.getOverlayView().dispatchDraw(canvas); } // Step 6, draw decorations (foreground, scrollbars) onDrawForeground(canvas); // Step 7, draw the default focus highlight drawDefaultFocusHighlight(canvas); if (isShowingLayoutBounds()) { debugDrawFocus(canvas); } // we're done... return; }   aqs中的待继承方法\n  clh 队列锁 #   clh 三个人的头字母  qnode mypred locked 线程A 需要获取锁 new 一个qnode mypred 指向队列的尾结点 locked=true  clh 队列锁 是一种自旋锁\naqs 是按照这种思想来实现的\n"});index.add({'id':29,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/cas/','title':"多线程--cas",'section':"多线程",'content':"什么是cas #  cas = compare and swap。机器指令级别实现的。原子操作，自旋实现，先campare 变量是否被修改过，如果被修改过，重新再读取campare再swap\n什么时候用 cas 什么时候用 锁 #  cas 推荐在一些简单的场景，竞争不大的场景下使用，比如知识一些计数的工作等。\ncas 的原子性怎么保证 #  原子性由cpu保证，cas 是一条cpu的指令\ncas的问题 #   aba问题 开销问题 只能保证一个共享变量的原子操作  aba 问题怎么办 #   atomic markable reference 只关心变量别改动过嘛 atomic stamped reference 关心变量修改了几次  开销问题 #   cas 是由于 cpu指令 会一直自旋 到满足条件的，导致开销会比较大，如果竞争非常激烈那么开销问题是成倍增加  "});index.add({'id':30,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/lock/','title':"多线程--lock",'section':"多线程",'content':"实现一个自定义的lock 类似于 lock\n学习完 aqs之后再来研究lock的实现\n  公平锁和非公平锁\n  锁的可重入\n  "});index.add({'id':31,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/synchronized/','title':"多线程--synchronized",'section':"多线程",'content':"synchronized(this) #  synchronized 在底层字节码的实现由这两个实现\n monitorenter  拿到monitor的所有权，进入代码块\n monitorexit  每一个对象都有一个monitor与之关联。 字节码获取一个moniter对象的所有权就获取了一个锁\npublic synchronized void test() #  对象头 #  优化synchronized 的性能设计了多个锁的量级 #    对象头\n  偏向锁 （经过统计发现，现代cpu 的锁大部分都是由同一个线程反复获得，所以设计了偏向锁，连自旋都不做了）\n  轻量级锁 - 为了避免上下文切换这类重量级操作。自旋锁cas。 适应性自旋锁 自旋锁次数由虚拟机动态调整。 自旋时间不大于上下文切换所需要的时间，否则就超出了 轻量级锁的意义\n  重量级锁 上下文切换\n  当偏向锁撤销的时候需要释放锁会导致stop the world。 这就引起一个问题，\n  为什么偏向锁撤销的时候会stop the world 因为撤销偏向锁的时候需要修改堆栈的对象的对象头内容，如果这时候不\n  偏向锁 适用于 只有一个线程访问同步块场景，因为偏向锁的撤销会导致stoptheworld。\n  "});index.add({'id':32,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/thread_local/','title':"多线程--thread local",'section':"多线程",'content':"ThreadLocal的使用方式 #  ThreadLocal 为什么可以每个线程保存一份自己的变量 #   public class ThreadLocal\u0026lt;T\u0026gt; { /*...*/ public T get() { Thread var1 = Thread.currentThread(); ThreadLocal.ThreadLocalMap var2 = this.getMap(var1); if (var2 != null) { ThreadLocal.ThreadLocalMap.Entry var3 = var2.getEntry(this); if (var3 != null) { Object var4 = var3.value; return var4; } } return this.setInitialValue(); } private T setInitialValue() { Object var1 = this.initialValue(); Thread var2 = Thread.currentThread(); ThreadLocal.ThreadLocalMap var3 = this.getMap(var2); if (var3 != null) { var3.set(this, var1); } else { this.createMap(var2, var1); } return var1; } public void set(T var1) { Thread var2 = Thread.currentThread(); ThreadLocal.ThreadLocalMap var3 = this.getMap(var2); if (var3 != null) { var3.set(this, var1); } else { this.createMap(var2, var1); } } /*...*/ static class ThreadLocalMap { private static final int INITIAL_CAPACITY = 16; private ThreadLocal.ThreadLocalMap.Entry[] table; private int size; private int threshold; /*...*/ private void set(ThreadLocal\u0026lt;?\u0026gt; var1, Object var2) { ThreadLocal.ThreadLocalMap.Entry[] var3 = this.table; int var4 = var3.length; int var5 = var1.threadLocalHashCode \u0026amp; var4 - 1; for(ThreadLocal.ThreadLocalMap.Entry var6 = var3[var5]; var6 != null; var6 = var3[var5 = nextIndex(var5, var4)]) { ThreadLocal var7 = (ThreadLocal)var6.get(); if (var7 == var1) { var6.value = var2; return; } if (var7 == null) { this.replaceStaleEntry(var1, var2, var5); return; } } var3[var5] = new ThreadLocal.ThreadLocalMap.Entry(var1, var2); int var8 = ++this.size; if (!this.cleanSomeSlots(var5, var8) \u0026amp;\u0026amp; var8 \u0026gt;= this.threshold) { this.rehash(); } } static class Entry extends WeakReference\u0026lt;ThreadLocal\u0026lt;?\u0026gt;\u0026gt; { Object value; Entry(ThreadLocal\u0026lt;?\u0026gt; var1, Object var2) { super(var1); this.value = var2; } } } static final class SuppliedThreadLocal\u0026lt;T\u0026gt; extends ThreadLocal\u0026lt;T\u0026gt; {/*...*/} } "});index.add({'id':33,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/volatile/','title':"多线程--volatile",'section':"多线程",'content':" jmm\n volatile 如何保证可见性 #  volatile 可见性 #  最轻量级的同步工具，只能保证可见性，在线程的工作内存中对变量的修改会马上同步到主内存中。只能保证可见性。\nvolatile 防止重排序 #  现代cpu 可以一次执行多个指令，从而 引入了 流水线和重排序 重排序缓存。\narm 架构拥有 3级流水线，以为这可能同时执行3条指令。\n单线程情况下 重排序 将会保证执行结果相同。但是多线程情况下导致出现混乱的情况。\nvolatile使用场景 #  一个线程写，多个线程读\nvolatile 实现原理 #  lock 前缀 汇编指令 lock指令添加之后 线程的工作内存中使用到变量的时候必须重新从主内存中重新读取一遍 线程的工作内存中对变量进行修改之后必须立马写会主内存\n"});index.add({'id':34,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/blockingqueue/','title':"多线程--阻塞队列和线程池原理",'section':"多线程",'content':"队列 Queue #  阻塞队列 BlockingQueue #  阻塞队列的几个实现 #   ArrayBlockingQueue LinkedBlockingQueue PriorityBlockingQueue DelayQueue SynchronousQueue LinkedTransferQueue LinkedBlockingDeque   线程池的接口 #   exectuor execotorsevice 线程池怎么选择：cpu密集型 io密集型，混合型  线程池的参数意义 #  线程池的实现原理 #  ThreadPoolExecutor 源码解析 #  "});index.add({'id':35,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/questions/','title':"多线程--面试题",'section':"多线程",'content':"synchronized 修饰普通方法和静态方法的区别？什么是可见性？ #   synchronized 锁的一定是一个具体对象，synchronzied修改的是对象头的内容， synchronized 静态方法加的是 位于方法区中的class对象 synchronized 加在普通方法上锁的是this对象 可见性： 根据jmm，在线程的工作内存中修改一个变量，其他线程将看不到他在这个线程的修改，这就是可见性。 线程从主内存中读取变量到工作内存中，修改运行在线程的工作内存中，不定时地将数据写回主内存。 使用volatile 可以在线程修改变量之后，强行要求将其写回主内存，并且在其他协程使用的时候，强行要求其从主内存再读取一次  锁分哪几类？ #  按照各个角度来分：\n 线程要不要锁住资源  锁住：悲观锁 不锁住：乐观锁   锁住同步资源失败，线程要不要阻塞？  阻塞： 不阻塞：自旋锁 适应性自旋锁   synchronized的为了优化所定义的几个级别的锁  偏向锁 轻量级锁 重量级锁   多个线程竞争的时候是否公平  公平锁 排队锁 非公平锁 先尝试获取一次锁，再排队   一个线程中的多个流程能不能获取同一把锁  可重入锁 非可重入锁   多个线程能不能共享一把锁  共享锁 （读锁） 排他锁 （写锁）    cas 无锁编程的原理 #  利用了现代cpu提供的compare and swap 原子操作能力，辅助以自旋直到完成为止等方式实现了无锁化编程的能力。\n cas的三大问题  aba问题 开销问题 只能进行一些简单操作    reentrantLock的实现原理 #  可重入锁。显式锁的一种实现。内部实现了aqs的子类Sync。aqs内部维护了一个state，当线程获取一次锁state就加一，释放一次锁state就减一。当state为0的时候锁将被释放。\naqs原理 #   aqs 是clh队列思想的一种变体实现。是juc的一个基础实现 aqs内部维护了一个state（用来表示锁的同步状态）和一个链表（线程的竞争锁的排队）。 使用模版方法的设计模式，通过子类来继承实现各式各样的显式锁。子类只需实现几个模版方法即可，比如tryAcquire tryRelease等几个方法 各种实现：CountDownLatch、信号量、读写锁，共享锁等 每个线程通过cas 自旋，之后park来实现线程的等待  synchronized 的原理以及于 reentrantlock的区别 #  synchronized 修饰方法和放置在同步代码块上会有不同，放到方法上会添加方法的flag，而放置到同步代码块上将添加虚拟机指令 monitorenter 和monitorexit。两种方式实现是一样的。 monitorenter都是通过修改monitor对象的markword作为标记来实现的，通过获取monitor对象的所有权来进行加锁。 而reentrantlock是通过aqs的原理实现的显式锁，reentrantlock 提供了非公平锁和公平锁的实现，而synchronzied是非公平的加锁的\nsynchronized做了哪些优化 #  锁消除 锁粗化 逃逸分析 https://blog.csdn.net/qq_26222859/article/details/80546917 偏向锁 轻量级锁 重量级锁\nvolatile 能否保证线程安全？在dcl上的作用是什么 #  dcl: double check lock new 一个对象 不是原子操作，这里至少会有3步，1、内存分配。2、初始化内存空间。3、将引用指向内存空间 由于指令重排序的原因可能会产生第三步在第二步之前的情况，这时候别的进程访问就可能导致npe的情况存在。 volatile 关键字抑制指令重排序\nvolatile和synchronized的区别 #  volatile 只保证了可见性 synchronized 可见性 排他性 内置锁的机制\n什么是守护线程，你是如何退出一个线程的 #  todo 守护线程 中断的理解\nstop 方法可能导致线程在不确定的情况下运行\nsleep、wait、yield的区别、wait的线程如何唤醒它 #  wait是继承自object的 有配套的 notify和notifyAll方法，在使用wait的时候必须通过synchronzied 关键字获取锁，在wait的时候会释放相应的锁等待别的线程notify或者notifyAll\nyield：让出cpu的执行权，等待cpu的调度回来执行\nsleep：休眠一定时间\n锁的状态：当sleep 和yield的时候线程持有锁，不会释放锁，wait将会释放锁\nsleep 是可中断的吗 #  当然可以中断\n线程生命周期 #  new：线程刚刚创建等待调用start启动 runnable： 调用start之后线程进入可执行状态，等待cpu调度。该状态也包括线程处于执行状态，由于这两个状态有cpu决定，所以java中混为一谈 terminated：线程run方法跑完进入结束状态 等待：wait join park 进入等待状态，等待唤醒，notify notifyAll unpark将能唤醒线程 等待超时：sleep wait join parkNanos parkUntil 进入一段时间的休眠。notify notifyAll unpark唤醒线程或者等待超时自动唤醒 阻塞：synchronized\nthreadlocal是什么 #  threadlocal 允许每个线程保存一个线程专属的副本，\n线程池的基本原理 #  为什么使用线程池\n 提高线程的可管理性 降低线程的开销 提高响应速度  线程池的几个参数的意义\n有三个线程t1、t2、t3 怎么确保它们按照顺序执行 #   join： t3的方法里面调用t2的join t2 调用t1的join  "});index.add({'id':36,'href':'/docs/kotlin/coroutines/','title':"Kotlin 协程本质",'section':"Kotlin",'content':"协程\n  官方文档\n协程是jetbrains 提供的一套 用于简化 异步编程的API。其最重要的一点就是当他挂起时，不会阻塞其他协程，协程之间切换几乎没有额外的损耗。\n kotlin 协程是什么 #   kotlin 协程在jvm上的 实现就是一套线程框架，这是由于kotlin的协程中的调度器都是基于线程之心执行的  上下文包含的内容 #    所有的可能的元素\npublic interface ThreadContextElement\u0026lt;S\u0026gt; : CoroutineContext.Element public interface ContinuationInterceptor : CoroutineContext.Element public interface CoroutineExceptionHandler : CoroutineContext.Element public interface Job : CoroutineContext.Element //// public abstract class AbstractCoroutineContextElement(public override val key: Key\u0026lt;*\u0026gt;) : Element public data class CoroutineName(val name: String) : AbstractCoroutineContextElement(CoroutineName) internal class YieldContext : AbstractCoroutineContextElement(Key) public abstract class CoroutineDispatcher : AbstractCoroutineContextElement(ContinuationInterceptor), ContinuationInterceptor public object NonCancellable : AbstractCoroutineContextElement(Job), Job internal data class CoroutineId( val id: Long) : ThreadContextElement\u0026lt;String\u0026gt;, AbstractCoroutineContextElement(CoroutineId) internal class AndroidExceptionPreHandler : AbstractCoroutineContextElement(CoroutineExceptionHandler), CoroutineExceptionHandler   Job\n  ContinuationInterceptor 拦截器\n  错误处理\n  name\n  id\n  "});index.add({'id':37,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/base/','title':"多线程--基础知识",'section':"多线程",'content':" 图解 #   初始状态：new thread 未 start 运行状态： 分为运行中和就绪状态，对于java层来说，不需要care 这两种状态的转化，这都是内部的逻辑，当一个线程调用了start之后线程进入就绪状态，等待系统调度，如果现场进入不需要cpu时间片 或者线程主动调用了yield之后进入 就绪态等待cpu的下次调度 等待状态：如图中所说，通过三种方法回进入等待状态 ，需要主动唤醒 等待超时状态：相比与等待状态就多了一个超时自动唤醒的逻辑 阻塞：有且只有synchronized 关键字才会让线程进入阻塞状态 终止：运行完成进程结束  实现现场的几种方式 #   继承 thread 实现 runnable 接口 callable：严格意义上来说这种方式不是一种实现线程的方式  // Thread.java  * There are two ways to create a new thread of execution. One is to * declare a class to be a subclass of \u0026lt;code\u0026gt;Thread\u0026lt;/code\u0026gt;. This * subclass should override the \u0026lt;code\u0026gt;run\u0026lt;/code\u0026gt; method of class * \u0026lt;code\u0026gt;Thread\u0026lt;/code\u0026gt;. An instance of the subclass can then be * allocated and started. For example, a thread that computes primes * larger than a stated value could be written as follows: * \u0026lt;hr\u0026gt;\u0026lt;blockquote\u0026gt;\u0026lt;pre\u0026gt; * class PrimeThread extends Thread { * long minPrime; * PrimeThread(long minPrime) { * this.minPrime = minPrime; * } * * public void run() { * // compute primes larger than minPrime  * \u0026amp;nbsp;.\u0026amp;nbsp;.\u0026amp;nbsp;. * } * } * \u0026lt;/pre\u0026gt;\u0026lt;/blockquote\u0026gt;\u0026lt;hr\u0026gt; * \u0026lt;p\u0026gt; * The following code would then create a thread and start it running: * \u0026lt;blockquote\u0026gt;\u0026lt;pre\u0026gt; * PrimeThread p = new PrimeThread(143); * p.start(); * \u0026lt;/pre\u0026gt;\u0026lt;/blockquote\u0026gt; * \u0026lt;p\u0026gt; * The other way to create a thread is to declare a class that * implements the \u0026lt;code\u0026gt;Runnable\u0026lt;/code\u0026gt; interface. That class then * implements the \u0026lt;code\u0026gt;run\u0026lt;/code\u0026gt; method. An instance of the class can * then be allocated, passed as an argument when creating * \u0026lt;code\u0026gt;Thread\u0026lt;/code\u0026gt;, and started. The same example in this other * style looks like the following: * \u0026lt;hr\u0026gt;\u0026lt;blockquote\u0026gt;\u0026lt;pre\u0026gt; * class PrimeRun implements Runnable { * long minPrime; * PrimeRun(long minPrime) { * this.minPrime = minPrime; * } * * public void run() { * // compute primes larger than minPrime  * \u0026amp;nbsp;.\u0026amp;nbsp;.\u0026amp;nbsp;. * } * } * \u0026lt;/pre\u0026gt;\u0026lt;/blockquote\u0026gt;\u0026lt;hr\u0026gt; * \u0026lt;p\u0026gt; * The following code would then create a thread and start it running: * \u0026lt;blockquote\u0026gt;\u0026lt;pre\u0026gt; * PrimeRun p = new PrimeRun(143); * new Thread(p).start(); * \u0026lt;/pre\u0026gt;\u0026lt;/blockquote\u0026gt; * \u0026lt;p\u0026gt; 从注释上就可以看到 java官方的说法就是只有这两种方法实现了现场。 至于callable 让我们来看一下callable的实现方式\n Callable\u0026lt;String\u0026gt; callable = new Callable\u0026lt;String\u0026gt;() { @Override public String call() throws Exception { Thread.sleep(1000); return \u0026quot;aaa\u0026quot;; } }; FutureTask\u0026lt;String\u0026gt; featureTask = new FutureTask\u0026lt;\u0026gt;(callable); new Thread(featureTask).start(); try { String ret = featureTask.get(); } catch (ExecutionException e) { e.printStackTrace(); } catch (InterruptedException e) { e.printStackTrace(); } 其实callable 是通过futuretask 包装一下\n//FutureTask.java public class FutureTask\u0026lt;V\u0026gt; implements RunnableFuture\u0026lt;V\u0026gt; { //。。。 } //RunnableFuture.java public interface RunnableFuture\u0026lt;V\u0026gt; extends Runnable, Future\u0026lt;V\u0026gt; { /** * Sets this Future to the result of its computation * unless it has been cancelled. */ void run(); } callable 就是通过传递一个runnable 到thread 来实现线程的。\nFutureTask的实现 #  //FutureTask.java package java.util.concurrent; import java.util.concurrent.locks.LockSupport; /** * 一个可以取消的异步调度。这个类提供了{@link Future}的一种实现， * 这个实现方式提供了start 和cancel的方法用于控制这个异步的计算过程， * 还提供了查询当前这个计算过程是否完成，以及取得计算结果的方法。 * 这个计算结果只有当计算过程结束之后才能获取到。 * {@code get} 这个方法将会一直block除非计算过程结束。 * 一旦计算过程结束，那么计算过程不能被重启或者取消， * 除非使用{@link #runAndReset}。 * * 一个 {@code FutureTask} 可以用于即实现了 {@link Callable} 也实现了 * {@link Runnable}。一个 {@code FutureTask} 可以提交给线程池 * {@link Executor} 来执行 * * \u0026lt;p\u0026gt;In addition to serving as a standalone class, this class provides * {@code protected} functionality that may be useful when creating * customized task classes. * * @since 1.5 * @author Doug Lea * @param \u0026lt;V\u0026gt; The result type returned by this FutureTask\u0026#39;s {@code get} methods */ public class FutureTask\u0026lt;V\u0026gt; implements RunnableFuture\u0026lt;V\u0026gt; { /* * Revision notes: This differs from previous versions of this * class that relied on AbstractQueuedSynchronizer, mainly to * avoid surprising users about retaining interrupt status during * cancellation races. Sync control in the current design relies * on a \u0026#34;state\u0026#34; field updated via CAS to track completion, along * with a simple Treiber stack to hold waiting threads. * * Style note: As usual, we bypass overhead of using * AtomicXFieldUpdaters and instead directly use Unsafe intrinsics. */ /** * The run state of this task, initially NEW. The run state * transitions to a terminal state only in methods set, * setException, and cancel. During completion, state may take on * transient values of COMPLETING (while outcome is being set) or * INTERRUPTING (only while interrupting the runner to satisfy a * cancel(true)). Transitions from these intermediate to final * states use cheaper ordered/lazy writes because values are unique * and cannot be further modified. * * Possible state transitions: * NEW -\u0026gt; COMPLETING -\u0026gt; NORMAL * NEW -\u0026gt; COMPLETING -\u0026gt; EXCEPTIONAL * NEW -\u0026gt; CANCELLED * NEW -\u0026gt; INTERRUPTING -\u0026gt; INTERRUPTED */ private volatile int state; private static final int NEW = 0; private static final int COMPLETING = 1; private static final int NORMAL = 2; private static final int EXCEPTIONAL = 3; private static final int CANCELLED = 4; private static final int INTERRUPTING = 5; private static final int INTERRUPTED = 6; /** The underlying callable; nulled out after running */ private Callable\u0026lt;V\u0026gt; callable; /** The result to return or exception to throw from get() */ private Object outcome; // non-volatile, protected by state reads/writes  /** The thread running the callable; CASed during run() */ private volatile Thread runner; /** Treiber stack of waiting threads */ private volatile WaitNode waiters; /** * Returns result or throws exception for completed task. * * @param s completed state value */ @SuppressWarnings(\u0026#34;unchecked\u0026#34;) private V report(int s) throws ExecutionException { Object x = outcome; if (s == NORMAL) return (V)x; if (s \u0026gt;= CANCELLED) throw new CancellationException(); throw new ExecutionException((Throwable)x); } /** * Creates a {@code FutureTask} that will, upon running, execute the * given {@code Callable}. * * @param callable the callable task * @throws NullPointerException if the callable is null */ public FutureTask(Callable\u0026lt;V\u0026gt; callable) { if (callable == null) throw new NullPointerException(); this.callable = callable; this.state = NEW; // ensure visibility of callable  } /** * Creates a {@code FutureTask} that will, upon running, execute the * given {@code Runnable}, and arrange that {@code get} will return the * given result on successful completion. * * @param runnable the runnable task * @param result the result to return on successful completion. If * you don\u0026#39;t need a particular result, consider using * constructions of the form: * {@code Future\u0026lt;?\u0026gt; f = new FutureTask\u0026lt;Void\u0026gt;(runnable, null)} * @throws NullPointerException if the runnable is null */ public FutureTask(Runnable runnable, V result) { this.callable = Executors.callable(runnable, result); this.state = NEW; // ensure visibility of callable  } public boolean isCancelled() { return state \u0026gt;= CANCELLED; } public boolean isDone() { return state != NEW; } public boolean cancel(boolean mayInterruptIfRunning) { if (!(state == NEW \u0026amp;\u0026amp; U.compareAndSwapInt(this, STATE, NEW, mayInterruptIfRunning ? INTERRUPTING : CANCELLED))) return false; try { // in case call to interrupt throws exception  if (mayInterruptIfRunning) { try { Thread t = runner; if (t != null) t.interrupt(); } finally { // final state  U.putOrderedInt(this, STATE, INTERRUPTED); } } } finally { finishCompletion(); } return true; } /** * @throws CancellationException {@inheritDoc} */ public V get() throws InterruptedException, ExecutionException { int s = state; if (s \u0026lt;= COMPLETING) s = awaitDone(false, 0L); return report(s); } /** * @throws CancellationException {@inheritDoc} */ public V get(long timeout, TimeUnit unit) throws InterruptedException, ExecutionException, TimeoutException { if (unit == null) throw new NullPointerException(); int s = state; if (s \u0026lt;= COMPLETING \u0026amp;\u0026amp; (s = awaitDone(true, unit.toNanos(timeout))) \u0026lt;= COMPLETING) throw new TimeoutException(); return report(s); } /** * Protected method invoked when this task transitions to state * {@code isDone} (whether normally or via cancellation). The * default implementation does nothing. Subclasses may override * this method to invoke completion callbacks or perform * bookkeeping. Note that you can query status inside the * implementation of this method to determine whether this task * has been cancelled. */ protected void done() { } /** * Sets the result of this future to the given value unless * this future has already been set or has been cancelled. * * \u0026lt;p\u0026gt;This method is invoked internally by the {@link #run} method * upon successful completion of the computation. * * @param v the value */ protected void set(V v) { if (U.compareAndSwapInt(this, STATE, NEW, COMPLETING)) { outcome = v; U.putOrderedInt(this, STATE, NORMAL); // final state  finishCompletion(); } } /** * Causes this future to report an {@link ExecutionException} * with the given throwable as its cause, unless this future has * already been set or has been cancelled. * * \u0026lt;p\u0026gt;This method is invoked internally by the {@link #run} method * upon failure of the computation. * * @param t the cause of failure */ protected void setException(Throwable t) { if (U.compareAndSwapInt(this, STATE, NEW, COMPLETING)) { outcome = t; U.putOrderedInt(this, STATE, EXCEPTIONAL); // final state  finishCompletion(); } } public void run() { if (state != NEW || !U.compareAndSwapObject(this, RUNNER, null, Thread.currentThread())) return; try { Callable\u0026lt;V\u0026gt; c = callable; if (c != null \u0026amp;\u0026amp; state == NEW) { V result; boolean ran; try { result = c.call(); ran = true; } catch (Throwable ex) { result = null; ran = false; setException(ex); } if (ran) set(result); } } finally { // runner must be non-null until state is settled to  // prevent concurrent calls to run()  runner = null; // state must be re-read after nulling runner to prevent  // leaked interrupts  int s = state; if (s \u0026gt;= INTERRUPTING) handlePossibleCancellationInterrupt(s); } } /** * Executes the computation without setting its result, and then * resets this future to initial state, failing to do so if the * computation encounters an exception or is cancelled. This is * designed for use with tasks that intrinsically execute more * than once. * * @return {@code true} if successfully run and reset */ protected boolean runAndReset() { if (state != NEW || !U.compareAndSwapObject(this, RUNNER, null, Thread.currentThread())) return false; boolean ran = false; int s = state; try { Callable\u0026lt;V\u0026gt; c = callable; if (c != null \u0026amp;\u0026amp; s == NEW) { try { c.call(); // don\u0026#39;t set result  ran = true; } catch (Throwable ex) { setException(ex); } } } finally { // runner must be non-null until state is settled to  // prevent concurrent calls to run()  runner = null; // state must be re-read after nulling runner to prevent  // leaked interrupts  s = state; if (s \u0026gt;= INTERRUPTING) handlePossibleCancellationInterrupt(s); } return ran \u0026amp;\u0026amp; s == NEW; } /** * Ensures that any interrupt from a possible cancel(true) is only * delivered to a task while in run or runAndReset. */ private void handlePossibleCancellationInterrupt(int s) { // It is possible for our interrupter to stall before getting a  // chance to interrupt us. Let\u0026#39;s spin-wait patiently.  if (s == INTERRUPTING) while (state == INTERRUPTING) Thread.yield(); // wait out pending interrupt  // assert state == INTERRUPTED;  // We want to clear any interrupt we may have received from  // cancel(true). However, it is permissible to use interrupts  // as an independent mechanism for a task to communicate with  // its caller, and there is no way to clear only the  // cancellation interrupt.  //  // Thread.interrupted();  } /** * Simple linked list nodes to record waiting threads in a Treiber * stack. See other classes such as Phaser and SynchronousQueue * for more detailed explanation. */ static final class WaitNode { volatile Thread thread; volatile WaitNode next; WaitNode() { thread = Thread.currentThread(); } } /** * Removes and signals all waiting threads, invokes done(), and * nulls out callable. */ private void finishCompletion() { // assert state \u0026gt; COMPLETING;  for (WaitNode q; (q = waiters) != null;) { if (U.compareAndSwapObject(this, WAITERS, q, null)) { for (;;) { Thread t = q.thread; if (t != null) { q.thread = null; LockSupport.unpark(t); } WaitNode next = q.next; if (next == null) break; q.next = null; // unlink to help gc  q = next; } break; } } done(); callable = null; // to reduce footprint  } /** * Awaits completion or aborts on interrupt or timeout. * * @param timed true if use timed waits * @param nanos time to wait, if timed * @return state upon completion or at timeout */ private int awaitDone(boolean timed, long nanos) throws InterruptedException { // The code below is very delicate, to achieve these goals:  // - call nanoTime exactly once for each call to park  // - if nanos \u0026lt;= 0L, return promptly without allocation or nanoTime  // - if nanos == Long.MIN_VALUE, don\u0026#39;t underflow  // - if nanos == Long.MAX_VALUE, and nanoTime is non-monotonic  // and we suffer a spurious wakeup, we will do no worse than  // to park-spin for a while  long startTime = 0L; // Special value 0L means not yet parked  WaitNode q = null; boolean queued = false; for (;;) { int s = state; if (s \u0026gt; COMPLETING) { if (q != null) q.thread = null; return s; } else if (s == COMPLETING) // We may have already promised (via isDone) that we are done  // so never return empty-handed or throw InterruptedException  Thread.yield(); else if (Thread.interrupted()) { removeWaiter(q); throw new InterruptedException(); } else if (q == null) { if (timed \u0026amp;\u0026amp; nanos \u0026lt;= 0L) return s; q = new WaitNode(); } else if (!queued) queued = U.compareAndSwapObject(this, WAITERS, q.next = waiters, q); else if (timed) { final long parkNanos; if (startTime == 0L) { // first time  startTime = System.nanoTime(); if (startTime == 0L) startTime = 1L; parkNanos = nanos; } else { long elapsed = System.nanoTime() - startTime; if (elapsed \u0026gt;= nanos) { removeWaiter(q); return state; } parkNanos = nanos - elapsed; } // nanoTime may be slow; recheck before parking  if (state \u0026lt; COMPLETING) LockSupport.parkNanos(this, parkNanos); } else LockSupport.park(this); } } /** * Tries to unlink a timed-out or interrupted wait node to avoid * accumulating garbage. Internal nodes are simply unspliced * without CAS since it is harmless if they are traversed anyway * by releasers. To avoid effects of unsplicing from already * removed nodes, the list is retraversed in case of an apparent * race. This is slow when there are a lot of nodes, but we don\u0026#39;t * expect lists to be long enough to outweigh higher-overhead * schemes. */ private void removeWaiter(WaitNode node) { if (node != null) { node.thread = null; retry: for (;;) { // restart on removeWaiter race  for (WaitNode pred = null, q = waiters, s; q != null; q = s) { s = q.next; if (q.thread != null) pred = q; else if (pred != null) { pred.next = s; if (pred.thread == null) // check for race  continue retry; } else if (!U.compareAndSwapObject(this, WAITERS, q, s)) continue retry; } break; } } } // Unsafe mechanics  private static final sun.misc.Unsafe U = sun.misc.Unsafe.getUnsafe(); private static final long STATE; private static final long RUNNER; private static final long WAITERS; static { try { STATE = U.objectFieldOffset (FutureTask.class.getDeclaredField(\u0026#34;state\u0026#34;)); RUNNER = U.objectFieldOffset (FutureTask.class.getDeclaredField(\u0026#34;runner\u0026#34;)); WAITERS = U.objectFieldOffset (FutureTask.class.getDeclaredField(\u0026#34;waiters\u0026#34;)); } catch (ReflectiveOperationException e) { throw new Error(e); } // Reduce the risk of rare disastrous classloading in first call to  // LockSupport.park: https://bugs.openjdk.java.net/browse/JDK-8074773  Class\u0026lt;?\u0026gt; ensureLoaded = LockSupport.class; } } 死锁的原因 #   多个操作者 抢占多个资源 抢占资源的顺序不对 拿到资源不释放   死锁的条件 #   互斥 请求保持 不剥夺 环路等待  "});index.add({'id':38,'href':'/docs/java/%E6%B7%B1%E5%85%A5%E7%90%86%E8%A7%A3Java-%E8%99%9A%E6%8B%9F%E6%9C%BA/2/','title':"《深入理解Java 虚拟机》第二章",'section':"《深入理解 Java 虚拟机》",'content':"java 虚拟机所管理的内存将会包括以下几个内存区域 #   方法区 虚拟机栈 本地方法栈 堆内存 程序计数器  程序计数器 #   线程私有 通过改变程序计数器来控制 下一条需要执行的字节码指令 一个内核只会控制一个线程，每个线程都有一个程序计数器用来控制当前线程的逻辑 每个线程之间的程序计数器没有关联，独立存储，所有这一类内存被称为程序计数器内存 如果当前在java线程上执行，那么程序计数器记录的就是正在执行的虚拟机字节码指令地址 如果在执行native代码 那么程序计数器记录的就是空 程序计数器不会oom  java虚拟机栈 #   线程私有 虚拟机栈的生命周期与线程相同 每个方法在执行时都会创建一个栈帧（栈帧会在第八章讲到）（局部变量表，操作数栈，动态链接，方法出口） 一个方法调用就是一个栈帧入虚拟机栈的过程，一个方法退出就是一个栈帧退出虚拟机栈的过程 一个栈帧的局部变量表是编译期间就确定的，运行期间是不会变的 当线程请求的栈深度超过最大值时将会抛出stackoverflowerror  public class ExampleUnitTest { @Test public void testStackOverflow() { testStack(1); } private void testStack(int i) { System.out.println(i); testStack(i + 1); } } // 9073 // java.lang.StackOverflowError  java虚拟机栈申请不到足够的内存是，将会抛出 oom  public class ExampleUnitTest { @Test public void testOOM() { testNewArray(0); } private void testNewArray(long last) { System.out.println(last); double[] doubles = new double[1024 * 1024 * 10]; last += doubles.length; testNewArray(last); } } //513802240 //java.lang.OutOfMemoryError: Java heap space 本地方法栈 #   线程私有 功能与java虚拟机栈十分相似 具体的实现由具体的虚拟机来实现，没有明确的强制规定 本地方法栈也会抛出 oom和stackoverflow hotspot 将本地方法栈与java虚拟机栈合二为一。  java堆 #   所有线程共享 此区域的目的就是存放对象实例 gc的主要工作区域 thread local allocation buffer 堆中可能划分出多个线程私有的分配缓冲区 还可以细分为 新生代（eden， from survivor， to survivor），老年代， 详细内容看第三章 将抛出 oom当堆内存不足以分配新的实例，或者无法扩展时  方法区 #   所有现场共享的内存区域 记录加载到虚拟机的类信息，常量，静态变量，即时编译器编译后的代码等 不等同于永久代，在最新的规范中，方法区或将使用 native memory 来使用 也会发生内存泄漏 也会发生oom  运行时常量池 #   能throw出oom 用于存放 在编译器就确定的那些 常量信息 string intern 可以将string 在运行过程中存放到 常量次中 参考这篇文章 1.7之后将常量池放到了堆中，从方法区中移动出  直接内存 #   newio 通过使用channel等方式 在nativememory上开辟了一块直接内存，java可以通过 directbytebuffer 操作nativemomery 提高效率，避免了重复拷贝 受限于native 内存也有大小，也会爆出oom   hotspot 虚拟机内容 #  对象的创建 #     "});index.add({'id':39,'href':'/docs/java/','title':"Java",'section':"Docs",'content':"java的各种知识集合\n"});index.add({'id':40,'href':'/docs/java/JavaVM/gc/','title':"Java 垃圾回收器 回收算法",'section':"Java v M",'content':"  垃圾回收算法\n 复制 标记整理 标记清理    回收具体算法\n 单线程serial-new（复制、新生代） serial-old（标记整理） 多线程 paraller scavange（复制、新生代 并行） paraller old（标记整理 并行） Paraller new（复制、新生代，并行） cms（老年代，标记清理，并行、并发）    cms\n 先进行一次stoptheworld 标记和gcroot直接相关的对象 并发的进行标记 stoptheworld 重新标记 并发的进行垃圾清除    g1\n 化整为零    常量池\n 静态常量池：编译期间确定的常量池 比如字面量 动态常量池    "});index.add({'id':41,'href':'/docs/java/other/io0/','title':"HSDB",'section':"Other",'content':"java -cp sa-jdi.jar sun.jvm.hotspot.HSDB hsdb\n"});index.add({'id':42,'href':'/docs/java/JavaVM/java-allocate/','title':"Java ",'section':"Java v M",'content':"  虚拟机栈-一个线程一个栈\n  动态链接 多态 - 静态分派 动态分派 dizhi\n  局部变量表 存放8大基础类型和对象引用地址。 为什么不存放对象本身呢？\n  操作数栈\n  返回地址\n    对象的分配策略\n 对象逃逸分析：分析对象是否可以直接在栈中分配对象，如果是分配对象到栈内存中 本地线程分配缓冲：是否具有本地线程缓冲，如果有直接映射到对应的缓冲中 tlab 是否大对象：如果是大对象直接分配到老年代 对象优先分配到eden区 空间分配担保：虚拟机保证，在分配的时候如果当前的区域有足够的空间分配内存则保证一定那能分配成功，因为会先进行一次gc 大对象直接进入老年代 长期存活的对象进入老年代 对象的gc年龄会动态的判断    gc年龄\n 当对象进去eden区之后每次gc都将对象的gc年龄加1。当超过阈值时，将会升级到下一代 eden 复制算法 复制到from或者to之中的一个 from和to相互复制直到进入老年代 当每个区满的时候将会触发gc minor gc 、young gc 新生代 major gc、old gc 老年代 full gc 全部区域 gc 年龄记在markword 区域    "});index.add({'id':43,'href':'/docs/java/other/io/','title':"Java IO 的基础应用",'section':"Other",'content':"Java中IO基础应用 #    课外阅读 okio\n Input\\Output 方向理解 #  从内存的角度来理解input\\output的方向。\n 内存输出到外部 output Write 内存接受输入 input Read  mermaid.initialize({ \"flowchart\": { \"useMaxWidth\":true }, \"theme\": \"default\" } ) graph TD; 内存-- output --外部; 外部-- input --内存;   字节流 #  InputStream\\OutputStream\n举个栗子 #  val inputStream = DataInputStream(BufferedInputStream(FileInputStream(File(\u0026#34;/sdcard/a.png\u0026#34;)))) 几个主要实现类的类图（以InputStream为例） #  先看几个常见的Stream类\n java.io.BufferedInputStream java.io.ByteArrayInputStream java.io.DataInputStream java.io.FilterInputStream 我们来分析他的继承关系  classDiagram InputStream 几个主要stream的功能介绍 #   BufferedInputStream FileInputStream DataInputStream ByteArrayInputStream ObjectInputStream  字符流 #  Reader\\Writer\n举个栗子 #  val inputStream = FileInputStream(File(\u0026#34;/sdcard/a.png\u0026#34;)) val reader = BufferedReader(InputStreamReader(inputStream, \u0026#34;GBK\u0026#34;)) 几个主要实现类的类图（以Reader为例） #  先看几个常见的Reader类\n CharArrayReader BufferedReader FilterReader PipedReader 我们来分析他的继承关系  classDiagram Reader RandomAccessFile #  FileChannel(nio) #  "});index.add({'id':44,'href':'/docs/java/JavaVM/question/','title':"Java vm 面试题",'section':"Java v M",'content':"  jvm 内存结构\n jmm的规则内存分为线程的工作内存、主内存之分 线程的工作内存包括虚拟栈、本地方法栈、程序计数器 主内存包括堆、方法区 堆按照垃圾回收算法分为 eden、from、to、老年代 方法区分为静态方法区，动态方法区 虚拟机栈是一个栈帧的filo栈。一个栈帧包含操作数栈、本地变量表、动态链接、返回地址 直接内存、本地内存    什么情况下内存栈溢出\n 线程爆炸多    描述一下 new一个对象的流程\n 检查对象的class是否存在方法区中，如果没有则加载 分配内存  分析内存存放的区域  逃逸分析：是否分配到栈上 是否大对象，如果是直接分配到老年代 分配到eden   内存的规整化  指针碰撞 空闲列表   考虑并发问题：  talb：本地线程分配内存缓冲 cas：分配内存区域重试     内存空间初始化 设置 对象初始化    Java对象会不会分配在栈中\n 逃逸分析：可以在栈上分配 几乎所有的对象都在堆中分配    如果判断一个对象是否被回收，有哪些算法，实际虚拟机使用得最多得是什么\n  引用计数\n  gcroot 可达性算法\n  引用计数算法，无法处理循环引用需要引入额外的机制。python的机制\n  虚拟机使用的最多的是gcroot可达性算法。\n    gc收集算法有哪些？他们的特点是什么\n 复制：适用于新生代这种包含大量即用即死的对象情况，标记出不可回收对象之后直接复制到另一个区域。缺点是空间利用率低，只有50%。hotspot的实现是一种变种方式811eden from to的分配比例提高了内存的利用率 标记整理：标记出不可回收对象之后，将对象整理排放。优点是内存规整，下次可以直接使用指针碰撞的方式分配内存，能提高分配的效率。垃圾收集算法的效率不高。 标记清除：标记出不可回收对象之后，将回收对象抹除，优点是回收算法的效率较高。缺点就是大量的内存碎片。下次分配只能使用空闲列表的方式，甚至会导致明明内存足够却无法分配内存的情况存在。    jvm中一次完整的gc流程是怎么样的？对象如何晋级到老年代？\n 需要明确gc的算法。 当一个区满的时候进行gc。比如新手代对象满了 进行一次minorgc。老年区满了进行一次major gc。fullgc 就是全局gc 一个正常对象在eden区分配，经过一次gc 将未回收对象复制到from/to区 再经过一次gc复制到to/from区。gc年龄将会记录在对象头的markword区域内，当这个值超过阈值的时候，将会复制到老年代。 新生代的算法都是使用复制算法 当对象进入老年代之后使用复制整理或者复制清楚算法。 cms 算法使用复制清除算法。 复制整理算法，将会暂停所有用户线程，然后进行标记整理。 cms算法会先进行一次stw标记出和gcroot直接引用的对象。然后并发的进行标记。再进行一次stw重新标记校验。然后再并发的进行清理内存    Java 中的几种引用关系，他们的区别是什么\n 强引用 ： oom也不会主动断开引用，除非由用户进行断开 软引用 ：oom之前将会释放软引用的对象 弱引用 ： 进行一次gc之后将会释放对象 虚引用 ： jvm内部进行标记的作用，对应java的开发者来说没有意义    final finally finalize\n final： finally： finalize：    String s = new String（“sss”）；创建了几个对象\n 2个    内存回收\n 空间担保    "});index.add({'id':45,'href':'/docs/java/JavaVM/java%E5%AF%B9%E8%B1%A1%E5%A4%B4/','title':"Java 对象头的内容",'section':"Java v M",'content':" 转自 这篇文章 修改了其中的几处错误 https://blog.csdn.net/lkforce/article/details/81128115\n Java对象保存在内存中时，由以下三部分组成：\n 1，对象头 2，实例数据 3，对齐填充字节\n 对象头的内部组成 #  Java 的对象头的数据\n 1，Mark Word 32bit 2，指向方法区中的指针 3，数组长度（只有数组对象才有）\n mark word 长度32bit #   todo\n 无锁状态下，25个bit的hashcode，4个bit的分代年龄，1个bit的偏向锁标示位 固定为0 ，2个bit的锁标记位 固定为01 偏向锁状态下，23个bit的线程ID，2个bit的epoch，4个bit的分代年龄，1个bit的偏向锁标记位固定为1 ，2个bit的锁标记位 固定为01  \u0026ndash; 当从偏向锁升级到 轻量级锁的机制，todo 翻书\n在大量并发的情况下应该弃用偏向锁\n 轻量级锁状态下，30个bit指向栈中的markword的备份 2个bit的锁标记位固定为00 重量级锁状态下，30个bit指向mutex的锁的指针，2个bit的锁标记为固定为10 gc的时候，30个bit为空，2个bit的锁标记位固定为11  "});index.add({'id':46,'href':'/docs/java/%E6%B7%B1%E5%85%A5%E7%90%86%E8%A7%A3Java-%E8%99%9A%E6%8B%9F%E6%9C%BA/%E8%99%9A%E6%8B%9F%E6%9C%BA-%E5%AD%97%E8%8A%82%E7%A0%81%E6%8C%87%E4%BB%A4%E8%A1%A8/','title':"《深入理解Java虚拟机》字节码指令表",'section':"《深入理解 Java 虚拟机》",'content':" 摘抄自 《深入理解Java虚拟机 \u0026ndash; JVM高级特性与最佳实践》\n    字节码 助记符 含义     0x00 nop nothing   0x01 aconst_null 将null push到栈顶（const =\u0026gt; push 一个常量 到栈顶）   0x02 iconst_m1 将int型-1 push到栈顶 （iconst =\u0026gt; 将int 类型常量 push到栈顶）   0x03 iconst_0 将int型 0 push到栈顶   0x04 iconst_1 将int型 1 push到栈顶   0x05 iconst_2 将int型 2 push到栈顶   0x06 iconst_3 将int型 3 push到栈顶   0x07 iconst_4 将int型 4 push到栈顶   0x08 iconst_5 将int型 5 push到栈顶   0x09 lconst_0 将long型 0 push到栈顶（lconst =\u0026gt; 将long 类型push到栈顶）   0x0a lconst_1 将long型 1 push到栈顶   0x0b fconst_0 将float型 0 push到栈顶（fconst =\u0026gt; 将float 类型push到栈顶）   0x0c fconst_1 将float型 1 push到栈顶   0x0d fconst_2 将float型 2 push到栈顶   0x0e dconst_0 将double型 0 push到栈顶（dconst =\u0026gt; 将double 类型push到栈顶）   0x0f dconst_1 将double型 1 push到栈顶   0x10 bipush 将单字节的常量值（-128 ～ 127）推送到栈顶（byte int push）   0x11 sipush 将一个短整型的常量值（-32768 ～ 32767）推送到栈顶（short int push）   0x12 ldc 将int、float、string 型的常量值从常量池中推送到栈顶（load const）   0x13 ldc_w 将int、float、string 型的常量值从常量池中推送到栈顶(宽索引)   0x14 ldc2_w 将long、double 型的常量值从常量池中推送到栈顶(宽索引)   0x15 iload 将指定的 int 的本地变量推送到栈顶 （int load）   0x16 lload 将指定的long 的本地变量推送到栈顶 （long load）   0x17 fload 将指定的float 的本地变量推送到栈顶 （float load）   0x18 dload 将指定的double 的本地变量推送到栈顶 （double load）   0x19 aload 将指定的引用类型 的本地变量推送到栈顶 （address load）   0x1a iload_0 将第一个 int 的本地变量推送到栈顶   0x1b iload_1 将第二个 int 的本地变量推送到栈顶   0x1c iload_2 将第三个 int 的本地变量推送到栈顶   0x1d iload_3 将第四个 int 的本地变量推送到栈顶   0x1e lload_0 将第一个 long 的本地变量推送到栈顶   0x1f lload_1 将第二个 long 的本地变量推送到栈顶   0x20 lload_2 将第三个 long 的本地变量推送到栈顶   0x21 lload_3 将第四个 long 的本地变量推送到栈顶   0x22 fload_0 将第一个 float 的本地变量推送到栈顶   0x23 fload_1 将第二个 float 的本地变量推送到栈顶   0x24 fload_2 将第三个 float 的本地变量推送到栈顶   0x25 fload_3 将第四个 float 的本地变量推送到栈顶   0x26 dload_0 将第一个 double 的本地变量推送到栈顶   0x27 dload_1 将第二个 double 的本地变量推送到栈顶   0x28 dload_2 将第三个 double 的本地变量推送到栈顶   0x29 dload_3 将第四个 double 的本地变量推送到栈顶   0x2a aload_0 将第一个 引用类型 的本地变量推送到栈顶   0x2b aload_1 将第二个 引用类型 的本地变量推送到栈顶   0x2c aload_2 将第三个 引用类型 的本地变量推送到栈顶   0x2d aload_3 将第四个 引用类型 的本地变量推送到栈顶   0x2e iaload 将int 数组指定的索引值推送的栈顶 （int array load 读取数组的某个值到栈顶）   0x2f laload 将long 数组指定的索引值推送的栈顶   0x30 faload 将float 数组指定的索引值推送的栈顶   0x31 daload 将double 数组指定的索引值推送的栈顶   0x32 aaload 将引用类型 数组指定的索引值推送的栈顶   0x33 baload 将byte 或者boolean 数组指定的索引值推送的栈顶   0x34 caload 将char 数组指定的索引值推送的栈顶   0x35 saload 将short 数组指定的索引值推送的栈顶   0x36 istore 将栈顶的int 数值存入指定的本地变量   0x37 lstore 将栈顶的long 数值存入指定的本地变量   0x38 fstore 将栈顶的float 数值存入指定的本地变量   0x39 dstore 将栈顶的double数值存入指定的本地变量   0x3a astore 将栈顶的引用型 数值存入指定的本地变量   0x3b istore_0 将栈顶的int 数值存入第一个本地变量   0x3c istore_1 将栈顶的int 数值存入第二个本地变量   0x3d istore_2 将栈顶的int 数值存入第三个本地变量   0x3e istore_3 将栈顶的int 数值存入第四个本地变量   0x3f lstore_0 将栈顶的long 数值存入第一个本地变量   0x40 lstore_1 将栈顶的long 数值存入第二个本地变量   0x41 lstore_2 将栈顶的long 数值存入第三个本地变量   0x42 lstore_3 将栈顶的long 数值存入第四个本地变量   0x43 fstore_0 将栈顶的float 数值存入第一个本地变量   0x44 fstore_1 将栈顶的float 数值存入第二个本地变量   0x45 fstore_2 将栈顶的float 数值存入第三个本地变量   0x46 fstore_3 将栈顶的float 数值存入第四个本地变量   0x47 dstore_0 将栈顶的double 数值存入第一个本地变量   0x48 dstore_1 将栈顶的double 数值存入第二个本地变量   0x49 dstore_2 将栈顶的double 数值存入第三个本地变量   0x4a dstore_3 将栈顶的double 数值存入第四个本地变量   0x4b astore_0 将栈顶的引用型 数值存入第一个本地变量   0x4c astore_1 将栈顶的引用型 数值存入第二个本地变量   0x4d astore_2 将栈顶的引用型 数值存入第三个本地变量   0x4e astore_3 将栈顶的引用型 数值存入第四个本地变量   0x4f iastore 将栈顶的int 数值存入指定数组的指定位置（将int 写入数组的某个位置）   0x50 lastore 将栈顶的long 数值存入指定数组的指定位置   0x51 fasotre 将栈顶的float 数值存入指定数组的指定位置   0x52 dastore 将栈顶的double 数值存入指定数组的指定位置   0x53 aastore 将栈顶的引用 数值存入指定数组的指定位置   0x54 basotre 将栈顶的byte或者boolean 数值存入指定数组的指定位置   0x55 castore 将栈顶的char 数值存入指定数组的指定位置   0x56 sastore 将栈顶的short 数值存入指定数组的指定位置   0x57 pop 将栈顶的数值弹出（单宽度的字符 即非long 和double）   0x58 pop2 将栈顶的一个两字节的数值（long或者double）或者两个单字节的数值弹出   0x59 dup 复制栈顶的数值并将其复制值压入栈顶 （dump）   0x5a dup_x1 复制栈顶的数值并将两个复制值压入栈顶   0x5b dup_x2 复制栈顶的数值并将三（或两个）个复制值压入栈顶   0x5c dup2 复制栈顶的数值并将其复制值压入栈顶 （双字节数类型 即 long 和double）   0x5d dup2_x1 复制栈顶的数值并将两个复制值压入栈顶（双字节数类型 即 long 和double）   0x5e dup2_x2 复制栈顶的数值并将三（或两个）个复制值压入栈顶（双字节数类型 即 long 和double）   0x5f swap 将栈顶的两个数字对换 （单字节数字）   0x60 iadd 将栈顶的两个int 相加并将结果压入栈顶 （int add）   0x61 ladd 将栈顶的两个long 相加并将结果压入栈顶   0x62 fadd 将栈顶的两个float 相加并将结果压入栈顶   0x63 dadd 将栈顶的两个double 相加并将结果压入栈顶   0x64 isub 将栈顶的两个int 相减并将结果压入栈顶 （int subtraction）   0x65 lsub 将栈顶的两个long 相减并将结果压入栈顶   0x66 fsub 将栈顶的两个float 相减并将结果压入栈顶   0x67 dsub 将栈顶的两个double 相减并将结果压入栈顶   0x68 imul 将栈顶的两个int 相乘并将结果压入栈顶 （int multiplication）   0x69 lmul 将栈顶的两个long 相乘并将结果压入栈顶   0x6a fmul 将栈顶的两个float 相乘并将结果压入栈顶   0x6b dmul 将栈顶的两个double 相乘并将结果压入栈顶   0x6c idiv 将栈顶的两个int 相除并将结果压入栈顶 （int division）   0x6d ldiv 将栈顶的两个int 相除并将结果压入栈顶   0x6e fdiv 将栈顶的两个int 相除并将结果压入栈顶   0x6f ddiv 将栈顶的两个int 相除并将结果压入栈顶   0x70 irem 将栈顶的两个int 做取模操作并将结果压入栈顶 （int remainder）   0x71 lrem 将栈顶的两个long 做取模操作并将结果压入栈顶   0x72 frem 将栈顶的两个float 做取模操作并将结果压入栈顶   0x73 drem 将栈顶的两个double 做取模操作并将结果压入栈顶   0x74 ineg 将栈顶的int 做取负操作并将结果压入栈顶 （int negate）   0x75 lneg 将栈顶的int 做取负操作并将结果压入栈顶   0x76 fneg 将栈顶的int 做取负操作并将结果压入栈顶   0x77 dneg 将栈顶的int 做取负操作并将结果压入栈顶   0x78 ishl 将栈顶的int 做左移操作并将结果压入栈顶 （int shift left）   0x79 lshl 将栈顶的long 做左移操作并将结果压入栈顶   0x7a ishr 将栈顶的int 做右移操作并将结果压入栈顶（int shift right）   0x7b lshr 将栈顶的long 做右移操作并将结果压入栈顶（long shift right）   0x7c iushr 将栈顶的unsigned int 做右移操作并将结果压入栈顶（unsigned int shift right）   0x7d lushr 将栈顶的unsigned long 做右移操作并将结果压入栈顶（unsigned long shift right）   0x7e iand 将栈顶的int 做 按位与 并将结果压入栈顶（int and）   0x7f land 将栈顶的long 做 按位与 并将结果压入栈顶（long and）   0x80 ior 将栈顶的int 做 按位或 并将结果压入栈顶（int or）   0x81 lor 将栈顶的long 做 按位或 并将结果压入栈顶（long or）   0x82 ixor 将栈顶的int 做 按位异或 并将结果压入栈顶（int xor）   0x83 lxor 将栈顶的long 做 按位异或 并将结果压入栈顶（long xor）   0x84 iinc 将int值增加指定值（i++， i\u0026ndash;， i+=2 等）   0x85 i2l 将栈顶的int 强转转化成 long并将结果压入栈顶 （int to long）   0x86 i2f 将栈顶的int 强转转化成 float并将结果压入栈顶   0x87 i2d 将栈顶的int 强转转化成 double并将结果压入栈顶   0x88 l2i 将栈顶的long 强转转化成 int并将结果压入栈顶   0x89 l2f 将栈顶的long 强转转化成 float并将结果压入栈顶   0x8a l2d 将栈顶的long 强转转化成 double并将结果压入栈顶   0x8b f2i 将栈顶的float 强转转化成 int并将结果压入栈顶   0x8c f2l 将栈顶的float 强转转化成 long并将结果压入栈顶   0x8d f2d 将栈顶的float 强转转化成 double并将结果压入栈顶   0x8e d2i 将栈顶的double 强转转化成 int并将结果压入栈顶   0x8f d2l 将栈顶的duoble 强转转化成 long并将结果压入栈顶   0x90 d2f 将栈顶的int 强转转化成 float并将结果压入栈顶   0x91 i2b 将栈顶的int 强转转化成 byte并将结果压入栈顶   0x92 i2c 将栈顶的int 强转转化成 char并将结果压入栈顶   0x93 i2s 将栈顶的int 强转转化成 short并将结果压入栈顶   0x94 lcmp 比较栈顶两long的数值的大小，并将结果（1、0或-1）压入栈顶 （long compare）   0x95 fcmpl 比较float的大小，并将结果（1、0或-1）压入栈顶。如果其中一项的值为NaN时，将-1压入栈顶 （float compare less）   0x96 fcmpg 比较float的大小，并将结果（1、0或-1）压入栈顶。如果其中一项的值为NaN时，将1压入栈顶 （float compare greater）   0x97 dcmpl 比较double的大小，并将结果（1、0或-1）压入栈顶。如果其中一项的值为NaN时，将-1压入栈顶 （double compare less）   0x98 dcmpg 比较double的大小，并将结果（1、0或-1）压入栈顶。如果其中一项的值为NaN时，将1压入栈顶 （double compare greater）   0x99 ifeg 当栈顶int型数值 等于0时跳转   0x9a ifne 当栈顶int型数值 不等于0时跳转   0x9b iflt 当栈顶int型数值 小于0时跳转   0x9c ifge 当栈顶int型数值 大于等于0时跳转   0x9d ifgt 当栈顶int型数值 大于0时跳转   0x9e ifle 当栈顶int型数值 小于等于0时跳转   0x9f if_icmpeq 比较栈顶的两个int的大小，当结果等于0时跳转   0xa0 if_icmpne 比较栈顶的两个int的大小，当结果不等于0时跳转   0xa1 if_icmplt 比较栈顶的两个int的大小，当结果小于0时跳转   0xa2 if_icmpge 比较栈顶的两个int的大小，当结果大于等于0时跳转   0xa3 if_icmpgt 比较栈顶的两个int的大小，当结果大于0时跳转   0xa4 if_icmple 比较栈顶的两个int的大小，当结果小于等于0时跳转   0xa5 if_acmpeq 比较栈顶的两个引用数值，当结果相等时跳转   0xa6 if_acmpne 比较栈顶的两个引用数值，当结果不相等时跳转   0xa7 goto 无条件跳转   0xa8 jsr 跳转到指定的16位offset位置，并将jsr的下一条指令地址压入栈顶   0xa9 ret 返回至本地变量指定的index 的指令位置（一般与 jsr 或者jsr_w 联合使用）   0xaa tableswitch 用于switch 条件跳转，case 值连续（可变长度指令） todo   0xab lookupswitch 用于switch条件跳转，case值不连续 （可变长度指令）todo   0xac ireturn 从当前方法返回int   0xad lreturn 从当前方法返回long   0xae freturn 从当前方法返回float   0xaf dreturn 从当前方法返回double   0xb0 areturn 从当前方法返回对象引用   0xb1 return 从当前方法返回 void   0xb2 getstatic 获取指定类的静态域，并将其值压入栈顶   0xb3 putstatic 为指定类的静态域赋值   0xb4 getfield 获取指定的类的实例域，并将其值压入栈顶   0xb5 putfield 为指定的类的实例域赋值   0xb6 invokevirtual 调用实例方法   0xb7 invokespecial 调用超类构造方法，实例初始化方法，私有方法   0xb8 invokestatic 调用静态方法   0xb9 invokeinterface 调用接口方法   0xba invokedynamic 调用动态方法   0xbb new 创建一个对象，并将其引用值压入栈顶   0xbc newarray 创建一个基本类型的数组，并将其引用值压入栈顶   0xbd anewarray 创建一个引用型的数组，并将其引用值压入栈顶   0xbe arraylength 获取数组的长度并压入栈顶   0xbf athrow 将栈顶的异常抛出   0xc0 checkcast 检验类型转换，检验未通过将抛出 classcastexeception   0xc1 instanceof 检验对象是否是指定的类的实例，如果是，则将1压入栈顶，否则将0压入栈顶   0xc2 monitorenter 获得对象的锁，用于同步方法或者同步块   0xc3 monitorexit 释放对象的锁，用于同步方法或者同步块   0xc4 wide 扩展本地变量的宽度   0xc5 multianewarray multi anewarray 创建指定类型和指定维度的多维数组（执行该命令时，操作栈中必须包含各维度的长度值），并将其引用值压入栈顶   0xc6 ifnull 为null时跳转   0xc7 ifnonnull 不为null时跳转   0xc8 goto_w 无条件跳转（宽索引）   0xc9 jsr_w 跳转到指定的32位offset位置，并将jsr_w 的下一条指令地址压入栈顶    "});index.add({'id':47,'href':'/docs/java/other/object_proxy/','title':"动态代理",'section':"Other",'content':" 在研究retrofit源码的时候，使用了动态代理的技术。顿时让我觉得这个技术很神奇，那么我们就来看看到底动态代理是怎么实现的。 动态代理相对于静态代理来说，动态代理对象调用的每一个方法都能回调到InvocationHandler的回调中。\n 使用 #  Proxy.newProxyInstance( service.getClassLoader(), new Class\u0026lt;?\u0026gt;[] {service}, new InvocationHandler() { private final Platform platform = Platform.get(); private final Object[] emptyArgs = new Object[0]; @Override public @Nullable Object invoke(Object proxy, Method method, @Nullable Object[] args) throws Throwable { // If the method is a method from Object then defer to normal invocation. if (method.getDeclaringClass() == Object.class) { return method.invoke(this, args); } args = args != null ? args : emptyArgs; return platform.isDefaultMethod(method) ? platform.invokeDefaultMethod(method, service, proxy, args) : loadServiceMethod(method).invoke(args); } }); "});index.add({'id':48,'href':'/docs/others/','title':"Others",'section':"Docs",'content':" 协议  "});index.add({'id':49,'href':'/docs/kotlin/samples/intro/','title':"【译】Kotlin - 基础介绍",'section':"Samples",'content':"hello world #  package org.kotlinlang.play // 1  fun main() { // 2  println(\u0026#34;Hello, World!\u0026#34;) // 3 }  1 kotlin 一般定义在包里。但是如果你不定义那么就将内容放到默认的包中。 2 main方法是程序的入口。 在 Kotlin 1.3 main方法可以不定义任何参数也不需要定义返回值。 3 println 方法将会把一行内容输入到标准输出。这个方法已经默认引用了，不需要显式的引用。分号也不再是必须的。   在早于1.3版本main 方法必须要有参数\nfun main(args: Array\u0026lt;String\u0026gt;) { println(\u0026quot;Hello, World!\u0026quot;) }  方法 #  普通方法 #  fun printMessage(message: String): Unit { // 1  println(message) } fun printMessageWithPrefix(message: String, prefix: String = \u0026#34;Info\u0026#34;) { // 2  println(\u0026#34;[$prefix] $message\u0026#34;) } fun sum(x: Int, y: Int): Int { // 3  return x + y } fun multiply(x: Int, y: Int) = x * y // 4  fun main() { printMessage(\u0026#34;Hello\u0026#34;) // 5  printMessageWithPrefix(\u0026#34;Hello\u0026#34;, \u0026#34;Log\u0026#34;) // 6  printMessageWithPrefix(\u0026#34;Hello\u0026#34;) // 7  printMessageWithPrefix(prefix = \u0026#34;Log\u0026#34;, message = \u0026#34;Hello\u0026#34;) // 8  println(sum(1, 2)) // 9 }  1 一个简单的方法，带有一个string参数和返回unit 就是返回void 没有返回值 2 一个带有两个参数的方法，其中 info是一个带有默认值的方法，无返回值就是默认Unit   通过tools show kotlin bytecode 再decompile 可以看到kotlin的java代码长什么样子\nfun printMessageWithPrefix(message: String, prefix: String = \u0026quot;Info\u0026quot;) { // 2 println(\u0026quot;[$prefix] $message\u0026quot;) } fun main() { printMessageWithPrefix(\u0026quot;1\u0026quot;) printMessageWithPrefix(\u0026quot;1\u0026quot;, \u0026quot;2\u0026quot;) } kotlin代码转化之后成为的样子，·从这可以看到kotlin在这里的处理是创建一个不同名字的方法，直接改了调用的地方，不是如预想中的重载·\npublic static final void printMessageWithPrefix(@NotNull String message, @NotNull String prefix) { Intrinsics.checkParameterIsNotNull(message, \u0026quot;message\u0026quot;); Intrinsics.checkParameterIsNotNull(prefix, \u0026quot;prefix\u0026quot;); String var2 = '[' + prefix + \u0026quot;] \u0026quot; + message; boolean var3 = false; System.out.println(var2); } // $FF: synthetic method public static void printMessageWithPrefix$default(String var0, String var1, int var2, Object var3) { if ((var2 \u0026amp; 2) != 0) { var1 = \u0026quot;Info\u0026quot;; } printMessageWithPrefix(var0, var1); } public static final void main() { printMessageWithPrefix$default(\u0026quot;1\u0026quot;, (String)null, 2, (Object)null); printMessageWithPrefix(\u0026quot;1\u0026quot;, \u0026quot;2\u0026quot;); } // $FF: synthetic method public static void main(String[] var0) { main(); }   3 一个返回int的值的方法 4 只有一个表达式的方法，并且推断返回值为int 5 调用了第一个方法传入了一个hello 的参数 6 调用了第二个方法传入了两个参数 7 调用了第二个方法传入了一个参数，第二个参数info带有默认值info 8 调用了第二个方法传入了带命名的参数，这使得参数不再是按照参数顺序来传入的 9 打印方法的返回值  infix functions 中缀方法 #   如果成员方法和扩展方法只有一个参数那么可以转化为中缀方法\n fun main() { infix fun Int.times(str: String) = str.repeat(this) // 1  println(2 times \u0026#34;Bye \u0026#34;) // 2  val pair = \u0026#34;Ferrari\u0026#34; to \u0026#34;Katrina\u0026#34; // 3  println(pair) infix fun String.onto(other: String) = Pair(this, other) // 4  val myPair = \u0026#34;McLaren\u0026#34; onto \u0026#34;Lucas\u0026#34; println(myPair) val sophia = Person(\u0026#34;Sophia\u0026#34;) val claudia = Person(\u0026#34;Claudia\u0026#34;) sophia likes claudia // 5 } class Person(val name: String) { val likedPeople = mutableListOf\u0026lt;Person\u0026gt;() infix fun likes(other: Person) { likedPeople.add(other) } // 6 }  1 定义一个中缀扩展方法在 Int 类里 2 嗲用这个方法 3 创建一个pair 通过标准库里的中缀方法 to 4 创建一个你自己的 类似于to的方法 onto 5 中缀符号 也可以定义成 成员方法，用于类对象使用 6 定义了中缀方法的类将会成为这个方法里面的第一个参数，即有个默认的this   local functions 内部方法 定义在方法中的方法\n 操作符方法 #  明确的方法可以升级为 操作符方法，允许调用者使用相应的符号进行运算\noperator fun Int.times(str: String) = str.repeat(this) // 1 println(2 * \u0026quot;Bye \u0026quot;) // 2 operator fun String.get(range: IntRange) = substring(range) // 3 val str = \u0026quot;Always forgive your enemies; nothing annoys them so much.\u0026quot; println(str[0..14]) //14  1 操作符和对应的重载方法是一一对应的 times 方法就是对应 *的,相当于重载操作符了 2 times 对应了 * 你调用 2 * \u0026quot;Bye \u0026quot; 相当与 调用了 2.times(\u0026quot;Bye \u0026quot;) 3 get(range: IntRange) ==\u0026gt; [0 .. 14] 4 可以参考这篇文章  带有 vararg 参数的方法 #   vararg 就相当于 java 中 String\u0026hellip; args\n fun printAll(vararg messages: String) { // 1 for (m in messages) println(m) } printAll(\u0026quot;Hello\u0026quot;, \u0026quot;Hallo\u0026quot;, \u0026quot;Salut\u0026quot;, \u0026quot;Hola\u0026quot;, \u0026quot;你好\u0026quot;) // 2 fun printAllWithPrefix(vararg messages: String, prefix: String) { // 3 for (m in messages) println(prefix + m) } printAllWithPrefix( \u0026quot;Hello\u0026quot;, \u0026quot;Hallo\u0026quot;, \u0026quot;Salut\u0026quot;, \u0026quot;Hola\u0026quot;, \u0026quot;你好\u0026quot;, prefix = \u0026quot;Greeting: \u0026quot; // 4 ) fun log(vararg entries: String) { printAll(*entries) // 5 }  1 如何获取 vararg中的每个参数 2 你也可以传入任意数量的参数包括0个 3 由于有命名参数的存在你可以在可变长度的参数后面再添加一个同类型的参数，二这一点在java中是做不到的 4 你应该像这样一样使用 5 在运行时中，vararg 是以数组的形式传递到参数中，这和java是一样的。你可以用* 将可变长度的参数以可变长度的参数来传递而不是以数组的方式来传递。这里不加 * 将会报错。   变量 #  kotlin 具有强大的变量的推断能力。你可以明确的定义变量的类型，也可以让编译器自己来推断变量类型是什么。推荐使用val 来定义变量，因为这是不变的变量，当然kotlin 也不会强制你将变量定义为不变，你可以使用var。\nvar a: String = \u0026quot;initial\u0026quot; // 1 println(a) val b: Int = 1 // 2 val c = 3 // 3  1 定义了一个可变变量，并且初始化 2 定义了一个不可变变量，并且初始化。相当于java中添加了 final 3 定义了一个不可变变量，并且初始化，并且没有明确定义变量名称。类型将由编译器推断，这里编译器推断的是Int  var e: Int // 1 println(e) // 2  1 定义了一个变量并且没有对他进行初始化 2 这里将会报错，变量必须进行初始化   你可以在任何地方进行初始化，只要在read 这个变量之前就可以。这里和java 不同\n val d: Int // 1 if (someCondition()) { d = 1 // 2 } else { d = 2 // 2 } println(d) // 3  1 定义一个不可变的变量 2 根据一些条件进行判断 之后再初始化 3 read 这个变量，这里不报错，因为已经初始化了   空安全检查 #  kotlin 想要创造一个没有NullPointerException的世界，所以不允许给一个变量赋予Null值。如果你确实需要赋予一个变量null，请在他的类型名称之后加上?\nvar neverNull: String = \u0026quot;This can't be null\u0026quot; // 1 neverNull = null // 2 var nullable: String? = \u0026quot;You can keep a null here\u0026quot; // 3 nullable = null // 4 var inferredNonNull = \u0026quot;The compiler assumes non-null\u0026quot; // 5 inferredNonNull = null // 6 fun strLength(notNull: String): Int { // 7 return notNull.length } strLength(neverNull) // 8 strLength(nullable) // 9  1 定义了一个不可为空的String，并且赋值 2 将这个字符串设置为null（这里将会报错） 3 定义一个可为空的String，并且赋值 4 将这个字符串设置为null，这里没有报错 5 定义一个由编译器进行推断的变量，这里编译器推断为String。编译器将会把变量优先推断为非空类型 6 报错，因为编译器进行推断的时候都将 7 定义了一个方法，传入的是非空的参数String 8 传入的是非空的String值，这里将不会报错 9 传入的可为空的String? 值，这里将会报错 有时候你必须处理null值，可能是因为Java代码传入了null 也可能是null代表了一种状态，这时候kotlin提供了一种处理null的方法  fun describeString(maybeString: String?): String { // 1 if (maybeString != null \u0026amp;\u0026amp; maybeString.length \u0026gt; 0) { // 2 return \u0026quot;String of length ${maybeString.length}\u0026quot; } else { return \u0026quot;Empty or null string\u0026quot; // 3 } }  1 定义了一个方法可入可为空的String 类型，返回一个不可为空的String类型 2 判断maybeString 是否为空或者为空字符串，如果是就返回maybeString的长度 3 不然的话就告知调用者，传入的参数为空或者为空字符串   类 #  类 定义由类名，类头（包含类型声明，私有构造方法等）、和类体组成，并且由大括号组成。类头和类体都是可以缺省的。如果类体缺省，那么大括号也可以缺省。\nclass Customer // 1 class Contact(val id: Int, var email: String) // 2 fun main() { val customer = Customer() // 3 val contact = Contact(1, \u0026quot;mary@gmail.com\u0026quot;) // 4 println(contact.id) // 5 contact.email = \u0026quot;jane@gmail.com\u0026quot; // 6 }  1 定义一个类Customer ，这个类没有定义任何属性和构造方法。 kotlin将会自动赋予一个无参构造方法 2 定义一个Contact 类，类里面有一个不可变变量的id，一个可变的变量email，并且有一个带有两个参数的构造方法 3 创建一个不可变的变量 实例customer类型推断为Customer。使用Customer的默认构造方法。在kotlin中是没有new关键字的 4 创建一个Contact的实例，使用了带有两个参数的构造方法 5 读取contact的属性id 6 更新contact的属性email   泛型 #  泛型是现代语言都具有的一种模板方法。泛型类和泛型方法使得代码具有高度的可复用性。就像List\u0026lt;T\u0026gt;里卖弄的内部逻辑与T就没有什么逻辑上的关系\n泛型类 #  第一种使用泛型的方法就是泛型类\nclass MutableStack\u0026lt;E\u0026gt;(vararg items: E) { // 1 private val elements = items.toMutableList() fun push(element: E) = elements.add(element) // 2 fun peek(): E = elements.last() // 3 fun pop(): E = elements.removeAt(elements.size - 1) fun isEmpty() = elements.isEmpty() fun size() = elements.size override fun toString() = \u0026quot;MutableStack(${elements.joinToString()})\u0026quot; }  1 定义一个泛型类，E可以被称为泛型参数。当你定义MutableStack\u0026lt;Int\u0026gt; 的时候Int 就被称呼为泛型参数 2 在泛型类里面的方法中你可以用E来代替泛型参数 3 你也可以用E来代替返回值  泛型方法 #  你当然也可以定义 泛型方法，如果他们的逻辑与泛型参数无关的话。比如你可以定义一个这样的方法\nfun \u0026lt;E\u0026gt; mutableStackOf(vararg elements: E) = MutableStack(*elements) fun main() { val stack = mutableStackOf(0.62, 3.14, 2.7) println(stack) } 注意：编译将会推断出mutableStackOf是一个Double的MutableStack所以你不需要填写mutableStackOf\u0026lt;Double\u0026gt;(...) 之类的\n 继承 #  kotlin 支持传统的面向对象的继承机制\nopen class Dog { // 1 open fun sayHello() { // 2 println(\u0026quot;wow wow!\u0026quot;) } } class Yorkshire : Dog() { // 3 override fun sayHello() { // 4 println(\u0026quot;wif wif!\u0026quot;) } } fun main() { val dog: Dog = Yorkshire() dog.sayHello() }  1 kotlin 的类默认是final的，如果你要允许类可以被继承，你需要添加 open 关键字到class 之前。 2 kotlin的方法默认也是final的，如果你要允许方法可以被重写，你需要添加open关键字到fun 之前。 3 一个子类应该定义在 : SuperclassName()之前。空的() 意味着super了父类的默认构造方法。 4 重写的方法胡总和属性，应该添加override 关键字  带有参数的构造方法的继承 #  open class Tiger(val origin: String) { fun sayHello() { println(\u0026quot;A tiger from $origin says: grrhhh!\u0026quot;) } } class SiberianTiger : Tiger(\u0026quot;Siberia\u0026quot;) // 1 fun main() { val tiger: Tiger = SiberianTiger() tiger.sayHello() }  1 如果你想要用父类的构造方法定义一个子类，那么你需要在定义的时候传入传给父类的字段。  传递参数给父类 #  open class Lion(val name: String, val origin: String) { fun sayHello() { println(\u0026quot;$name, the lion from $origin says: graoh!\u0026quot;) } } class Asiatic(name: String) : Lion(name = name, origin = \u0026quot;India\u0026quot;) // 1 fun main() { val lion: Lion = Asiatic(\u0026quot;Rufo\u0026quot;) // 2 lion.sayHello() }  1 Asiatic 类里的name 既不是val 也不是var。这是一个构造方法的参数，只用来将值传递给父类的的构造方法。 2 用构造参数Rufo创建一个Asiatic的实例，这个调用将会嗲用父类Lion 的双参构造方法  "});index.add({'id':50,'href':'/docs/kotlin/samples/delegate/','title':"【译】Kotlin 语法基础 - 代理",'section':"Samples",'content':"Delegation Pattern 委托模式 #  kotlin 天然支持 委托代理模式，不再需要编写一些模板文件。\ninterface SoundBehavior { // 1 fun makeSound() } class ScreamBehavior(val n:String): SoundBehavior { // 2 override fun makeSound() = println(\u0026quot;${n.toUpperCase()} !!!\u0026quot;) } class RockAndRollBehavior(val n:String): SoundBehavior { // 2 override fun makeSound() = println(\u0026quot;I'm The King of Rock 'N' Roll: $n\u0026quot;) } // Tom Araya is the \u0026quot;singer\u0026quot; of Slayer class TomAraya(n:String): SoundBehavior by ScreamBehavior(n) // 3 // You should know ;) class ElvisPresley(n:String): SoundBehavior by RockAndRollBehavior(n) // 3 fun main() { val tomAraya = TomAraya(\u0026quot;Thrash Metal\u0026quot;) tomAraya.makeSound() // 4 val elvisPresley = ElvisPresley(\u0026quot;Dancin' to the Jailhouse Rock.\u0026quot;) elvisPresley.makeSound() } /* THRASH METAL !!! I'm The King of Rock 'N' Roll: Dancin' to the Jailhouse Rock. */  1 定义一个接口 2 定义两个实现类，ScreamBehavior 和 RockAndRollBehavior。他们都实现了 SoundBehavior的接口。 3 TomAraya  和ElvisPresley  也是先了SoundBehavior的接口，但是他们没有提供实现，而是将实现委托给了ScreamBehavior 和 RockAndRollBehavior。通过一个by 关键字，这个委托就产生了，你看没有一丝一毫的多余代码。 4 当调用了 tomAraya 的  makeSound() 或者嗲用 elvisPresley 的  makeSound()的时候，他们分别调用了他们的委托类。   Delegated Properties 代理属性 #  kotlin 提供了一种 代理属性的机制,这个机制允许你将一个属性的get set 方法委托给某一个实例，这个实例必须有getValue 方法，如果待委托的属性还是一个可变属性那么 setValue 也是必须的。\nimport kotlin.reflect.KProperty class Example { var p: String by Delegate() // 1 override fun toString() = \u0026quot;Example Class\u0026quot; } class Delegate() { operator fun getValue(thisRef: Any?, prop: KProperty\u0026lt;*\u0026gt;): String { // 2 return \u0026quot;$thisRef, thank you for delegating '${prop.name}' to me!\u0026quot; } operator fun setValue(thisRef: Any?, prop: KProperty\u0026lt;*\u0026gt;, value: String) { // 2 println(\u0026quot;$value has been assigned to ${prop.name} in $thisRef\u0026quot;) } } fun main() { val e = Example() println(e.p) e.p = \u0026quot;NEW\u0026quot; } /* Example Class, thank you for delegating 'p' to me! NEW has been assigned to p in Example Class */  1 委托属性 p 类型是String 被委托给了一个class Delegate的实例，这个实例用by关键字定义在 p之后。 2 委托类里面的委托方法，这个方法的签名必须和这里一摸一样。方法里面你可以由自己决定需要几步操作。如果是不可变属性那么只有getValue 是必须的。  标准库里的delegate #  kotlin的标准库里面提供了一大堆有用的delegate，比如 lazy observable 等等。比如lazy的使用方法。\nclass LazySample { init { println(\u0026quot;created!\u0026quot;) // 1 } val lazyStr: String by lazy { println(\u0026quot;computed!\u0026quot;) // 2 \u0026quot;my lazy\u0026quot; } } fun main() { val sample = LazySample() // 1 println(\u0026quot;lazyStr = ${sample.lazyStr}\u0026quot;) // 2 println(\u0026quot; = ${sample.lazyStr}\u0026quot;) // 3 } /* created! computed! lazyStr = my lazy = my lazy */  1 lazy 的属性不会在类实例创建的时候初始化 2 第一次调用lazyStr的get()的时候，才会调用lazy类的实例的提供的表达式，返回一个\u0026quot;my lazy\u0026quot;。这个mylazy将会被赋值给lazyStr 3 再次调用get的时候将会直接返回之前储存的值。  如果你想要一个线程安全的 延迟初始化方案，请使用 blockingLazy() 代替。他保证了 getValue 后者 setValue 会只在一个线程上运行，并且所有的线程都可以读取到同样的值。\n保存属性到 map #  属性委托，同样可以用于保存内容到map 。这是很方便地用于类似于解析json，或者其他的什么东西之上的。\nclass User(val map: Map\u0026lt;String, Any?\u0026gt;) { val name: String by map // 1 val age: Int by map // 1 } fun main() { val user = User(mapOf( \u0026quot;name\u0026quot; to \u0026quot;John Doe\u0026quot;, \u0026quot;age\u0026quot; to 25 )) println(\u0026quot;name = ${user.name}, age = ${user.age}\u0026quot;) } //name = John Doe, age = 25  1 在这里 map 内部提供过来 delegate 属性类的作用，当调用user的属性的get的时候，会去map中取出value，key是user属性的名字。  当然你也可以用可变属性 不需要一定要val 的属性，只是你需要注意的是 如果你定义的是可变属性，那么你传入的map 也必须是可变map\n"});index.add({'id':51,'href':'/docs/kotlin/samples/funarea/','title':"【译】Kotlin 语法基础 - 作用域方法",'section':"Samples",'content':"let #  let 是一个kotlin 的标准库，可以用于实例检查和null检查，当let被调用再一个实例上的时候，你可以通过it 来再作用域内访问这个实例。作用域内的最后一句表达式，将会作为返回值返回\nfun customPrint(s: String) { print(s.toUpperCase()) } fun main() { val empty = \u0026quot;test\u0026quot;.let { // 1 customPrint(it) // 2 it.isEmpty() // 3 } println(\u0026quot; is empty: $empty\u0026quot;) fun printNonNull(str: String?) { println(\u0026quot;Printing \\\u0026quot;$str\\\u0026quot;:\u0026quot;) str?.let { // 4 print(\u0026quot;\\t\u0026quot;) customPrint(it) println() } } printNonNull(null) printNonNull(\u0026quot;my string\u0026quot;) } /* TEST is empty: false Printing \u0026quot;null\u0026quot;: Printing \u0026quot;my string\u0026quot;: MY STRING */  1 在“test”上执行这一个代码块，并且返回一个值作为结果 2 调用一个方法，通过it访问到“test”实例 3 返回let代码块的返回值 4 安全调用let代码块，只有当str不为空是才会执行let代码块。   run #  run 和let 很相似，执行一个代码块，返回一个结果。两者不同的是 let中使用it 来访问外部调用实例，而run中使用this 来访问外部调用实例，这在嗲用外部调用实例的方法是会提供一些便捷。\nfun main() { fun getNullableLength(ns: String?) { println(\u0026quot;for \\\u0026quot;$ns\\\u0026quot;:\u0026quot;) ns?.run { // 1 println(\u0026quot;\\tis empty? \u0026quot; + isEmpty()) // 2 println(\u0026quot;\\tlength = $length\u0026quot;) length // 3 } } getNullableLength(null) getNullableLength(\u0026quot;\u0026quot;) getNullableLength(\u0026quot;some string with Kotlin\u0026quot;) } /* for \u0026quot;null\u0026quot;: for \u0026quot;\u0026quot;: is empty? true length = 0 for \u0026quot;some string with Kotlin\u0026quot;: is empty? false length = 23 */  1 在一个可控变量上执行一个代码块 2 不需要显示的调用this.xxx 直接调用 isempty， 这里就相当于调用 this.isEmpty() 3 返回this.length   with #  class Configuration(var host: String, var port: Int) fun main() { val configuration = Configuration(host = \u0026quot;127.0.0.1\u0026quot;, port = 9000) with(configuration) { println(\u0026quot;$host:$port\u0026quot;) } // instead of: println(\u0026quot;${configuration.host}:${configuration.port}\u0026quot;) } /* 127.0.0.1:9000 127.0.0.1:9000 */ with是一个非扩展方法，在with的作用域里，你可以简洁地访问到参数地成员，意思就是在作用域里面你可以隐藏实例地名字当访问属性地时候。\n apply #  apply 在一个实例上运行一段代码，让后将返回这个实例。在代码块中，实例可以用this来代替访问。这个apply，可以简单地用于初始化实例。\ndata class Person(var name: String, var age: Int, var about: String) { constructor() : this(\u0026quot;\u0026quot;, 0, \u0026quot;\u0026quot;) } fun main() { val jake = Person() // 1 val stringDescription = jake.apply { // 2 name = \u0026quot;Jake\u0026quot; // 3 age = 30 about = \u0026quot;Android developer\u0026quot; }.toString() // 4 println(stringDescription) } //Person(name=Jake, age=30, about=Android developer)  1 创建一个实例 2 调用一个apply 代码块 3 修改属性 4 apply返回地还是 这个实例，在这里可以调用 toString(), 这样你就可以链式地调用。   also #  also 和apply的工作方式很像，他执行了一个代码块，然后返回这个实例。在代码块中，你需要使用it来访问这个实例，这是和apply不同的地方。所以这更像是用来执行一个额外的工作。比如在调用链中打印一些东西\ndata class Person(var name: String, var age: Int, var about: String) { constructor() : this(\u0026quot;\u0026quot;, 0, \u0026quot;\u0026quot;) } fun writeCreationLog(p: Person) { println(\u0026quot;A new person ${p.name} was created.\u0026quot;) } fun main() { val jake = Person(\u0026quot;Jake\u0026quot;, 30, \u0026quot;Android developer\u0026quot;) // 1 .also { // 2 writeCreationLog(it) // 3 } } //A new person Jake was created.  1 创建一个带有属性值的 Person 2 调用also代码块，代码块的返回值就是他自己 3 调用一个方法，打印一些内容  "});index.add({'id':52,'href':'/docs/kotlin/samples/function/','title':"【译】Kotlin 语法基础 - 函数",'section':"Samples",'content':"高阶函数 #   高阶函数 是以另一个函数为参数或者返回值的函数。\n以另一个函数为参数 #  fun calculate(x: Int, y: Int, operation: (Int, Int) -\u0026gt; Int): Int { // 1 return operation(x, y) // 2 } fun sum(x: Int, y: Int) = x + y // 3 fun main() { val sumResult = calculate(4, 5, ::sum) // 4 val mulResult = calculate(4, 5) { a, b -\u0026gt; a * b } // 5 println(\u0026quot;sumResult $sumResult, mulResult $mulResult\u0026quot;) }  1 定义一个高阶函数，他有两个int参数 x，y，同时他还有一个函数作为参数：operation。在operation的申明中，他的参数和返回值已经申明。 2 这个高阶函数的内部实现是获得operation的返回值在传入x，y的情况下。 3 定义一个函数，与operation的定义很像。 4 执行这个高阶函数，传入两个int值的参数，和传入一个函数参数::sum。:: 在kotlin中是一个使用名字来提取方法的符号。 5 执行这个高阶函数，插入两个int值的参数，和传入一个lambda为参数。这种写法是不是看起来很简洁？  以一个函数作为返回值 #  fun operation(): (Int) -\u0026gt; Int { // 1 return ::square } fun square(x: Int) = x * x // 2 fun main() { val func = operation() // 3 println(func(2)) // 4 }  1 定义一个高阶函数，他返回一个函数作为返回值。在这里(Int) -\u0026gt; Int的写法是申明的返回值的函数的结构。这里定义了返回square函数 2 定义名字叫square的函数，他的作用是返回x*x 3 执行这个高阶函数，获取一个函数作为返回值。在这里，operation()返回的func 就是square方法 4 执行func。这里square方法会被执行、  lambda 表达式 #   Lambda表达式是一种为了方便创建函数对等式（就是 相当于一种函数）。lambda 可以很简洁地表明函数，通过使用默认参数it\n// All examples create a function object that performs upper-casing. // So it's a function from String to String val upperCase1: (String) -\u0026gt; String = { str: String -\u0026gt; str.toUpperCase() } // 1 val upperCase2: (String) -\u0026gt; String = { str -\u0026gt; str.toUpperCase() } // 2 val upperCase3 = { str: String -\u0026gt; str.toUpperCase() } // 3 // val upperCase4 = { str -\u0026gt; str.toUpperCase() } // 4 val upperCase5: (String) -\u0026gt; String = { it.toUpperCase() } // 5 val upperCase6: (String) -\u0026gt; String = String::toUpperCase // 6 println(upperCase1(\u0026quot;hello\u0026quot;)) println(upperCase2(\u0026quot;hello\u0026quot;)) println(upperCase3(\u0026quot;hello\u0026quot;)) println(upperCase5(\u0026quot;hello\u0026quot;)) println(upperCase6(\u0026quot;hello\u0026quot;))  1 A lambda in all its glory, with explicit types everywhere。花括号里面的内容就是lambda，这部分被赋值为类型为 (String) -\u0026gt; String 的一个内容。 2 lambda 内部有发生类型推论。有这个推论的原因是，在外部定义了明确的类型。 3 lambda 外部发生了类型推论，这是因为lambda 内部的参数类型和返回值是可推论的 4 你不能在lambda 内部和外部同时省略类型，这将无法进行类型推论。 5 如果只有一个参数，你可以不定义lambda 内部的参数名字，默认使用it 6 如果你的lambda只有一个单一的函数调用，那么你就可以直接使用函数指针(::)  Extension Functions 扩展函数 和 Properties 属性 #  kotlin 可以通过 扩展机制 让你扩展任何的class 。顾名思义，有两种扩展方式：扩展方法和扩展属性。他们看起来像是普通的方法和属性，除了一点，你必须明确的说明你是要扩展那个类。\ndata class Item(val name: String, val price: Float) // 1 data class Order(val items: Collection\u0026lt;Item\u0026gt;) fun Order.maxPricedItemValue(): Float = this.items.maxBy { it.price }?.price ?: 0F // 2 fun Order.maxPricedItemName() = this.items.maxBy { it.price }?.name ?: \u0026quot;NO_PRODUCTS\u0026quot; val Order.commaDelimitedItemNames: String // 3 get() = items.map { it.name }.joinToString() fun main() { val order = Order(listOf(Item(\u0026quot;Bread\u0026quot;, 25.0F), Item(\u0026quot;Wine\u0026quot;, 29.0F), Item(\u0026quot;Water\u0026quot;, 12.0F))) println(\u0026quot;Max priced item name: ${order.maxPricedItemName()}\u0026quot;) // 4 println(\u0026quot;Max priced item value: ${order.maxPricedItemValue()}\u0026quot;) println(\u0026quot;Items: ${order.commaDelimitedItemNames}\u0026quot;) // 5 } /* Max priced item name: Wine Max priced item value: 29.0 Items: Bread, Wine, Water */  1 定义了两个 data class，item 和 order ，其中 order 包含了一个items的属性 2 添加一个Order的扩展函数 3 添加一个Order的扩展属性 4 执行 order的 扩张方法 maxPricedItemName() 5 访问 order的扩展属性 commaDelimitedItemNames  甚至你可以为null 扩展方法。在扩展方法中，你可以对this 进行检查是否为null，并根据检查结果做出你的逻辑\nfun \u0026lt;T\u0026gt; T?.nullSafeToString() = this?.toString() ?: \u0026quot;NULL\u0026quot; // 1 fun main() { println(null.nullSafeToString()) println(\u0026quot;Kotlin\u0026quot;.nullSafeToString()) }  1 定义了一个泛型方法，这个方法可以由null 来调用  "});index.add({'id':53,'href':'/docs/kotlin/samples/flow/','title':"【译】Kotlin 语法基础 - 流程控制",'section':"Samples",'content':"when #  when 语句 #  用来代替广泛使用的 switch 关键字，Kotlin 提供了一种更加灵活和简洁的when 结构。when可以被用来当作一个语句，也可以用来当作一个表达式\nfun main() { cases(\u0026quot;Hello\u0026quot;) cases(1) cases(0L) cases(MyClass()) cases(\u0026quot;hello\u0026quot;) } fun cases(obj: Any) { when (obj) { // 1 1 -\u0026gt; println(\u0026quot;One\u0026quot;) // 2 \u0026quot;Hello\u0026quot; -\u0026gt; println(\u0026quot;Greeting\u0026quot;) // 3 is Long -\u0026gt; println(\u0026quot;Long\u0026quot;) // 4 !is String -\u0026gt; println(\u0026quot;Not a string\u0026quot;) // 5 else -\u0026gt; println(\u0026quot;Unknown\u0026quot;) // 6 } } class MyClass /* Greeting One Long Not a string Unknown */  1 这是一个when语句 2 检查哪个obj 等于1 3 检查哪个obj 等于 Hello 4 检查哪个obj 是Long 5 检查哪个obj 不是String 6 默认语句 注意：将会按照顺序一条一条语句查询，直到一条语句满足条件，所以只有最靠前的满足条件的语句才会被执行  when 表达式 #  fun main() { println(whenAssign(\u0026quot;Hello\u0026quot;)) println(whenAssign(3.4)) println(whenAssign(1)) println(whenAssign(MyClass())) } fun whenAssign(obj: Any): Any { val result = when (obj) { // 1 1 -\u0026gt; \u0026quot;one\u0026quot; // 2 \u0026quot;Hello\u0026quot; -\u0026gt; 1 // 3 is Long -\u0026gt; false // 4 else -\u0026gt; 42 // 5 } return result } class MyClass  1 这是一个when 语句表达式 2 检查哪个obj等于1 如果等于返回一个one的字符串 3 检查哪个obj等于 Hello 如果等于返回一个 1 4 检查哪个obj 是Long 类型，如果等于返回一个false 5 默认返回 42。不像在 when语句中，在when表达式中else 式要求一定存在的，因为如果不存在，编译器将无法覆盖所有的可能性来推断出 返回值的类型   Loop 循环 #  kotlin 支持的循环模式有以下几种：for , while , do-while\nfor #  for 在kotlin的使用方式与大多数语言一致\nval cakes = listOf(\u0026quot;carrot\u0026quot;, \u0026quot;cheese\u0026quot;, \u0026quot;chocolate\u0026quot;) for (cake in cakes) { // 1 println(\u0026quot;Yummy, it's a $cake cake!\u0026quot;) }  1 将会遍历每个参数  while 和 do-while #  while 和 do-while 在kotlin的使用方式与大多数语言一致\nfun eatACake() = println(\u0026quot;Eat a Cake\u0026quot;) fun bakeACake() = println(\u0026quot;Bake a Cake\u0026quot;) fun main(args: Array\u0026lt;String\u0026gt;) { var cakesEaten = 0 var cakesBaked = 0 while (cakesEaten \u0026lt; 5) { // 1 eatACake() cakesEaten ++ } do { // 2 bakeACake() cakesBaked++ } while (cakesBaked \u0026lt; cakesEaten) }  1 执行语句块当判断条件为true的时候 2 先执行语句块再判断条件  Iterators 迭代器 #  你可以再类中自定义你的迭代器，通过再类里 实现 iterator 操作符 方法\nclass Animal(val name: String) class Zoo(val animals: List\u0026lt;Animal\u0026gt;) { operator fun iterator(): Iterator\u0026lt;Animal\u0026gt; { // 1 return animals.iterator() // 2 } /* // 2.1 operator fun iterator(): Iterator\u0026lt;Animal\u0026gt; { return object : Iterator\u0026lt;Animal\u0026gt; { override fun next() : Animal { return Animal(\u0026quot;111\u0026quot;) } override fun hasNext(): Boolean { return false } } } */ } fun main() { val zoo = Zoo(listOf(Animal(\u0026quot;zebra\u0026quot;), Animal(\u0026quot;lion\u0026quot;))) for (animal in zoo) { // 3 println(\u0026quot;Watch out, it's a ${animal.name}\u0026quot;) } } /* Watch out, it's a zebra Watch out, it's a lion */  1 在类中定义一个迭代器。这个操作符方法的方法名为 iterator，用operator 修复fun 2 返回一个迭代器这意味着你必须实现这两个方法 例如2.1那样 next(): Animal hasNext(): Boolean 3 通过使用用户定义的迭代器进行循环  The iterator can be declared in the type or as an extension function.\nRanges 区间 #  kotlin提供了一系列工具用于区间的数据处理。我们大致看一下\nfor(i in 0..3) { // 1 print(i) } print(\u0026quot; \u0026quot;) for(i in 2..8 step 2) { // 2 print(i) } print(\u0026quot; \u0026quot;) for (i in 3 downTo 0) { // 3 print(i) } print(\u0026quot; \u0026quot;) // 0123 2468 3210  1 从0到3 一个一个遍历，包含0 和3 。输出0 1 2 3 2 从2到8 两个两个遍历，包含2和8。输出 2 4 6 8 3 从3到0倒序一个一个遍历，包含3和0。输出 3 2 1 0  char数组也支持同样的操作\nfor (c in 'a'..'d') { // 1 print(c) } print(\u0026quot; \u0026quot;) for (c in 'z' downTo 's' step 2) { // 2 print(c) } print(\u0026quot; \u0026quot;) // abcd zxvt  1 按照字母表遍历 a 到 d 包括a和 d 2 按照字母表从z 倒序到 s 两个两个遍历。char 范围同样支持 step 和downTo 关键字  in关键字 同样支持用在if语句中\nval x = 2 if (x in 1..5) { // 1 print(\u0026quot;x is in range from 1 to 5\u0026quot;) } println() if (x !in 6..10) { // 2 print(\u0026quot;x is not in range from 6 to 10\u0026quot;) }  1 判断一个x 是否在1 - 5的范围里 2 判断x 是否不在 6 - 10 的范围中   相等关系检查 Equality Checks #  在kotlin 中，使用 == 来比较结构是否相等。使用 === 来比较引用地址是否相等。 更准确地说，a == b 编译完之后等价于  if (a == null) b == null else a.equals(b).\nval authors = setOf(\u0026quot;Shakespeare\u0026quot;, \u0026quot;Hemingway\u0026quot;, \u0026quot;Twain\u0026quot;) val writers = setOf(\u0026quot;Twain\u0026quot;, \u0026quot;Shakespeare\u0026quot;, \u0026quot;Hemingway\u0026quot;) val writers1 = setOf(\u0026quot;Twain\u0026quot;, \u0026quot;Shakespeare\u0026quot;, \u0026quot;Hemingway\u0026quot;) val writers2 = writers println(authors == writers) // 1 println(authors === writers) // 2 println(writers === writers1) // 3 println(writers2 === writers) // 4 /* true false false true */  1 返回 true 因为相当于调用了 authors.equals(writers) 然后sets将会忽略元素的顺序 2 返回 false 因为 authors 和 writers不是同样的引用地址. 3 返回 false 哪怕writers 和writers1 完全相同，两者指向的也不是相同的引用地址 4 返回 true 指向了同一个对象  多元表达式 Conditional Expression #  在kotlin中没有java 的哪种 a?b:c 的三元表达式。取而代之地是使用if表达式\nfun max(a: Int, b: Int) = if (a \u0026gt; b) a else b // 1 println(max(99, -42))  1 返回 a或者b  "});index.add({'id':54,'href':'/docs/kotlin/samples/special/','title':"【译】Kotlin 语法基础 - 特殊特性",'section':"Samples",'content':"Named Arguments #  和其他语言（java， c++，之类的）不同的是kotlin提供了一种特性叫命名参数。既可以和别的语言一样按照定义的方法的参数顺序来传递参数，也可以通过名字来传递参数，这样就避免了错误的顺序会带来的错误以及可以更清晰地调用。有些错误是很难以通过编译器来检查出编译错误的。比如这样\nfun format(userName: String, domain: String) = \u0026quot;$userName@$domain\u0026quot; fun main() { println(format(\u0026quot;mario\u0026quot;, \u0026quot;example.com\u0026quot;)) // 1 println(format(\u0026quot;domain.com\u0026quot;, \u0026quot;username\u0026quot;)) // 2 println(format(userName = \u0026quot;foo\u0026quot;, domain = \u0026quot;bar.com\u0026quot;)) // 3 println(format(domain = \u0026quot;frog.com\u0026quot;, userName = \u0026quot;pepe\u0026quot;)) // 4 }  1 传递了两个参数 2 同样也是传递了两个参数，但是在这里其实是发生了业务上的错误的。如果你使用命名参数就可以更清晰地发现这个问题。 3 这里就使用了命名参数，是不是很清晰呀！ 4 命名参数可以随意交换顺序哦   String Templates string模板 #  String 模板可以允许你在string被需要使用（比如println的时候string 被需要使用）的时候，将写在String 中的引用和表达式替换成真正的值。\nfun main() { val greeting = \u0026quot;Kotliner\u0026quot; var i = 1 var str = \u0026quot;Hello $i\u0026quot; i = 2 println(str) println(\u0026quot;Hello $i\u0026quot;) str = \u0026quot;Hello ${++i}\u0026quot; println(\u0026quot;Hello $i\u0026quot;) println(\u0026quot;Hello $greeting\u0026quot;) // 1 println(\u0026quot;Hello ${greeting.toUpperCase()}\u0026quot;) // 2 } /* 1 2 3 Hello Kotliner Hello KOTLINER */  1 打印一个在String 中的变量应用 用$ 开头表示 2 打印一个在String 中的表达式, 用$开头，用大括号包起来。   Destructuring Declarations 解构声明 #   解构声明 可以让你在只需要一个实例的成员的时候，可以用简单的几句就获取到你想要的结果。\nfun findMinMax(list: List\u0026lt;Int\u0026gt;): Pair\u0026lt;Int, Int\u0026gt; { // do the math return Pair(50, 100) } fun main() { val (x, y, z) = arrayOf(5, 10, 15) // 1 println(\u0026quot;$x, $y, $z\u0026quot;) val map = mapOf(\u0026quot;Alice\u0026quot; to 21, \u0026quot;Bob\u0026quot; to 25) for ((name, age) in map) { // 2 println(\u0026quot;$name is $age years old\u0026quot;) } val (min, max) = findMinMax(listOf(100, 90, 50, 98, 76, 83)) // 3 println(\u0026quot;$min, $max\u0026quot;) } /* 5, 10, 15 Alice is 21 years old Bob is 25 years old 50, 100 */  1 将array的 三个元素分别赋值给 x y z 2 将map的entry 分为 name 和 age 两个属性，在for循环中 3 这里的i情况其实和2 是差不多的 就是将pair 分为赋值给 min 和max。这里返回值也可以作为解构声明的一部分  data class User(val username: String, val email: String) // 1 fun getUser() = User(\u0026quot;Mary\u0026quot;, \u0026quot;mary@somewhere.com\u0026quot;) fun main() { val user = getUser() val (username, email) = user // 2 println(username == user.component1()) // 3 val (_, emailAddress) = getUser() // 4 }  1 定义一个data class 2 将user的 两个属性按照名字解构说明分给两个不可变变量 3 这里返回的是 true。这里通过自动编码加进去的 componentN() 方法来获取user的第几个属性。 4 解构声明也可以忽略某个属性，这里和go语言的多返回值很像。这里忽略的意义就是告知编译器，不需要处理这个属性的解构，能提高性能。  class Pair\u0026lt;K, V\u0026gt;(val first: K, val second: V) { // 1 operator fun component1(): K { return first } operator fun component2(): V { return second } } fun main() { val (num, name) = Pair(1, \u0026quot;one\u0026quot;) // 2 println(\u0026quot;num = $num, name = $name\u0026quot;) }  1 定义一个自己定义的Pair 类，包括自己定义 component1 和 component2 方法。 2 解构一个类，就是利用这个pair 这样的方式来做到的。  Smart Casts 灵活的类型转化 #  kotlin的编译器(这说明可以在ide中就这么操作不需要编码进行类型转化)可以灵活的进行大多数情况的类型转化，包括但不限于以下两种：\n 将可空类型灵活的转变为对应的不可控类型 从父类型转化为子类型  import java.time.LocalDate import java.time.chrono.ChronoLocalDate fun main() { val date: ChronoLocalDate? = LocalDate.now() // 1 if (date != null) { println(date.isLeapYear) // 2 } if (date != null \u0026amp;\u0026amp; date.isLeapYear) { // 3 println(\u0026quot;It's a leap year!\u0026quot;) } if (date == null || date.isLeapYear) { // 4 println(\u0026quot;There's no Feb 29 this year...\u0026quot;) } if (date is LocalDate) { val month = date.monthValue // 5 println(month) } } /* true It's a leap year! There's no Feb 29 this year... 10 */  1 定义一个可空类型的变量 2 判空之后date 自动转变成了他相对应的非空类型 3 在这里将会进行一个如2里面的 类型转化，这是由于和java中一样，有判断捷径存在。（即当两个boolean \u0026amp;\u0026amp; 的时候第一个为true 才会进行下一个判断，如果第一个为false，将不会进行下一个判断） 4 同3 理 5 这里便捷地将父类转化成了子类。这一点在java中可以很麻烦地哦  "});index.add({'id':55,'href':'/docs/kotlin/samples/specialclass/','title':"【译】Kotlin 语法基础 - 特殊类",'section':"Samples",'content':"Data Class #   Data class 可以用于创建一个数据类用于存储数据。这些类将会自动提供类似setter, getter,copy,toString(),hashCode(),componentN()方法\ndata class User(val name: String, val id: Int) // 1 fun main() { val user = User(\u0026quot;Alex\u0026quot;, 1) println(user) // 2 val secondUser = User(\u0026quot;Alex\u0026quot;, 1) val thirdUser = User(\u0026quot;Max\u0026quot;, 2) println(\u0026quot;user == secondUser: ${user == secondUser}\u0026quot;) // 3 println(\u0026quot;user == thirdUser: ${user == thirdUser}\u0026quot;) println(user.hashCode()) println(secondUser.hashCode()) // 4 println(thirdUser.hashCode()) // copy() function println(user.copy()) // 5 println(user.copy(\u0026quot;Max\u0026quot;)) // 6 println(user.copy(id = 2)) // 7 println(\u0026quot;name = ${user.component1()}\u0026quot;) // 8 println(\u0026quot;id = ${user.component2()}\u0026quot;) } /* User(name=Alex, id=1) user == secondUser: true user == thirdUser: false 63347075 63347075 2390846 User(name=Alex, id=1) User(name=Max, id=1) User(name=Alex, id=2) name = Alex id = 1 */  1 定义一个data class 2 println 输出 dataclass 的 toString() 方法的返回值 3 自动编码的equals() 方法将会考虑如果双方实例所有属性全部相等，那么者两个实例将会相等 4 相等的 dataclass hashcode 在equals的情况下也会返回相同的hashcode 5 自动编码的copy() 方法将会简便的创建一份副本 6 当你选择拷贝的时候，你可以便捷的修改内部属性。你可以按照构造函数的顺序依次传入相应的值 7 你也可以通过命名参数的方式来修改某个特定的参数 8 自动编码的componentN() 方法，可以让你以定义属性的顺序来依次地读取各个字段的值  Enum class 枚举 #   枚举类 等同于java中地枚举\nenum class State { IDLE, RUNNING, FINISHED // 1 } fun main() { val state = State.RUNNING // 2 val message = when (state) { // 3 State.IDLE -\u0026gt; \u0026quot;It's idle\u0026quot; State.RUNNING -\u0026gt; \u0026quot;It's running\u0026quot; State.FINISHED -\u0026gt; \u0026quot;It's finished\u0026quot; } println(message) }  1 定义具有三个实例地枚举类，每个实例都是唯一且固定地，枚举的数量也是固定不可变的。 2 可以访问一个枚举实例通过他的类名。 3 本俩当when 当作表达式的时候是需要明确使用else 字段的。但是当when 表达式遇到 枚举的时候，只要你列举了所有的额枚举变量，那么你就不需要else 字段了  枚举类，也可以像Java 那样在类里面定义方法字段等。这种情况你需要明确的使用分号来分割 枚举的实例和类里的其他要素。\nenum class Color(val rgb: Int) { // 1 RED(0xFF0000), // 2 GREEN(0x00FF00), BLUE(0x0000FF), YELLOW(0xFFFF00); fun containsRed() = (this.rgb and 0xFF0000 != 0) // 3 } fun main() { val red = Color.RED println(red) // 4 println(red.containsRed()) // 5 println(Color.BLUE.containsRed()) // 6 }  1 定义一个枚举类，具有一个属性和一个方法 2 每个实例，都必须传递一个明确的不相同的属性值 3 方法需要用分号和实力定义分隔开 4 默认生成的toString 方法，默认使用枚举的名字，比如这里将会打印出 RED。 5 这里会调用当前实例的containsRed 方法 6 你也可以通过类名来读取实例，然后再调用他的方法  密封类 Sealed Classes #   密封类 密封类用于限制继承。如果你定义了一个密封类，那么他的子类必须定义在同一个文件中。不允许子类定义在别的文件中，\nsealed class Mammal(val name: String) // 1 class Cat(val catName: String) : Mammal(catName) // 2 class Human(val humanName: String, val job: String) : Mammal(humanName) fun greetMammal(mammal: Mammal): String { when (mammal) { // 3 is Human -\u0026gt; return \u0026quot;Hello ${mammal.name}; You're working as a ${mammal.job}\u0026quot; // 4 is Cat -\u0026gt; return \u0026quot;Hello ${mammal.name}\u0026quot; //5 is Mammal -\u0026gt; return \u0026quot;Hello ${mammal.name}\u0026quot; } //6 } fun main() { println(greetMammal(Cat(\u0026quot;Snowy\u0026quot;))) println(greetMammal(Human(\u0026quot;John\u0026quot;, \u0026quot;IT\u0026quot;))) //println(greetMammal(Mammal(\u0026quot;John\u0026quot;))) // 7 } /* Hello Snowy Hello John; You're working as a IT */  1 定义一个密封类 2 定义一个他的子类，这个子类必须定义在同一个文件中 3 在这个方法中，when 表达式 不需要定义 else 的字段，是因为穷举了 所有的可能性，这里有人会问了Mammal 不算嘛，其实是因为你创建不出来 Mammal 这个类，7 这里会报错 Cannot access '\u0026lt;init\u0026gt;': it is private in 'Mammal' Sealed types cannot be instantiated 4 这里将会发生一个快速的强制转化，将 Mammal 转化为 Human 5 这里将会发生一个快速的强制转化，将 Mammal 转化为 Cat 6 这里不需要else 字段，因为所有的 子类都以及明确地覆盖了 7 这句话将会报错   Object Keyword #  类和对象在kotlin中和别的面向对象的语言中大同小异：class 是一个蓝图，object 是类的一个实例。通常来说，你定义了一个类，然后创建多个类的实例。\nimport java.util.Random class LuckDispatcher { //1 fun getNumber() { //2 var objRandom = Random() println(objRandom.nextInt(90)) } } fun main() { val d1 = LuckDispatcher() //3 val d2 = LuckDispatcher() d1.getNumber() //4 d2.getNumber() }  1 定义一个蓝图 2 定义一个方法 3 创建一个蓝图的实例 4 调用实例的方法  在kotlin中中你有这么一个定义 object keyword。这常常被用来定义 一个唯一的实现。这在Java中，你可以理解为单例模式：当有两个线程想要创建这个类的实例的时候，能保证只有同时只有一个实例。\n 在kotlin中，你只需要申明一个 object ： 没有类定义，没有构造方法，只有一个lazy 的实例。why lazy？因为他只会在被访问到的时候才会被创建，另一方面来说：他甚至可能不会被创建\n object Expression #  这是一个object Expression 基础的用法,：一个简单的object或者数据的结构体。在这里你不需要定义一个类的申明：你只需要创建一个object然后申明他的成员，并且在一个方法中去使用他。想这样的对象，在Java中会以匿名内部类的实例存在。\nfun rentPrice(standardDays: Int, festivityDays: Int, specialDays: Int): Unit { //1 val dayRates = object { //2 var standard: Int = 30 * standardDays var festivity: Int = 50 * festivityDays var special: Int = 100 * specialDays } val total = dayRates.standard + dayRates.festivity + dayRates.special //3 print(\u0026quot;Total price: $$total\u0026quot;) //4 } fun main() { rentPrice(10, 2, 1) //5 }  1 创建一个方法，带有三个 参数 2 创建一个object 并计算保存三个结果 3 访问这个object的结构体里面的值 4 打印结果 5 运行这个方法，只有在运行这个方法的时候这个object 才会被创建  object Declaration #  你也可以用 object 申明，这不是一个表达式，不能用于赋值语句，你最好通过类名直接访问他的成员\nobject DoAuth { //1 fun takeParams(username: String, password: String) { //2 println(\u0026quot;input Auth parameters = $username:$password\u0026quot;) } } fun main(){ DoAuth.takeParams(\u0026quot;foo\u0026quot;, \u0026quot;qwerty\u0026quot;) //3 }  1 创建一个object 的申明 2 在object 中定义一个方法 3 执行，在这里object 才会被真正的创建。  Companion Objects内部object #  申明在类的内部的另一种object的用法是 Companion Objects。从语法上来讲，这更像是java中的静态方法。如果你想在kotlin中使用Companion Object。请使用包级别的类方法定义。\nclass BigBen { //1 companion object Bonger { //2 fun getBongs(nTimes: Int) { //3 for (i in 1 .. nTimes) { print(\u0026quot;BONG \u0026quot;) } } } } fun main() { BigBen.getBongs(12) //4 }  1 定义一个class 2 定义一个 companion ，显示的定义了名字 3 定义了一个companion object方法， 4 通过companion object 的类名直接 访问他的方法  "});index.add({'id':56,'href':'/docs/kotlin/samples/collections/','title':"【译】Kotlin 语法基础 - 集合",'section':"Samples",'content':"List #  list 是一个有序的集合。在kotlin中 list 可以是可变的 MutableList  也可以是只读的 List 。在创建list的时候，使用标准类库里的 listOf() 创建只读的不可变的 List，使用 mutableListOf() 创建可变的list。为了避免不必要的修改，你可以用List的引用来指向可变list， 这将避免错误的修改。\nval systemUsers: MutableList\u0026lt;Int\u0026gt; = mutableListOf(1, 2, 3) // 1 val sudoers: List\u0026lt;Int\u0026gt; = systemUsers // 2 fun addSudoer(newUser: Int) { // 3 systemUsers.add(newUser) } fun getSysSudoers(): List\u0026lt;Int\u0026gt; { // 4 return sudoers } fun main() { addSudoer(4) // 5 println(\u0026quot;Tot sudoers: ${getSysSudoers().size}\u0026quot;) // 6 getSysSudoers().forEach { // 7 i -\u0026gt; println(\u0026quot;Some useful info on user $i\u0026quot;) } // getSysSudoers().add(5) \u0026lt;- Error! // 8 }  1 创建一个可变的list 2 通过一个List 的对象来指向 可变list。这将避免对List 进行修改 3 定义一个方法，将一个int 值添加到 可变list 4 定义一个方法，来获取可变list的一个 不可变引用。 5 调用addSudoer 方法 6 获取不可变list 引用 然后读取size 7 获取不可变list 引用再循环遍历 8 获取不可变list 然后调用add 方法将会导致报错   Set #  set 是一种无序的集合，并且不存在重复的健值。创建set，可以使用setOf() 和 mutableSetOf()。和list 一样，set 可以通过一个不可变的引用来避免不必要的修改。\nval openIssues: MutableSet\u0026lt;String\u0026gt; = mutableSetOf(\u0026quot;uniqueDescr1\u0026quot;, \u0026quot;uniqueDescr2\u0026quot;, \u0026quot;uniqueDescr3\u0026quot;) // 1 fun addIssue(uniqueDesc: String): Boolean { return openIssues.add(uniqueDesc) // 2 } fun getStatusLog(isAdded: Boolean): String { return if (isAdded) \u0026quot;registered correctly.\u0026quot; else \u0026quot;marked as duplicate and rejected.\u0026quot; // 3 } fun main() { val aNewIssue: String = \u0026quot;uniqueDescr4\u0026quot; val anIssueAlreadyIn: String = \u0026quot;uniqueDescr2\u0026quot; println(\u0026quot;Issue $aNewIssue ${getStatusLog(addIssue(aNewIssue))}\u0026quot;) // 4 println(\u0026quot;Issue $anIssueAlreadyIn ${getStatusLog(addIssue(anIssueAlreadyIn))}\u0026quot;) // 5 }  1 创建一个可变的set 2 定义一个方法往可变set里面添加元素，set的add 将会返回添加是否成功的结果 3 定义一个方法 4 打印添加成功的结果 5 打印添加失败的结果   Map #  map 是一个键值对的集合，键是唯一的，并且是用来找到相关的value值的。创建 map 同样有两种方法mapOf 和 mutableMapOf 。使用to的中缀方法可以快速的创建map 。和list 一样，map 可以通过一个不可变的引用来避免不必要的修改。\nconst val POINTS_X_PASS: Int = 15 val EZPassAccounts: MutableMap\u0026lt;Int, Int\u0026gt; = mutableMapOf(1 to 100, 2 to 100, 3 to 100) // 1 val EZPassReport: Map\u0026lt;Int, Int\u0026gt; = EZPassAccounts // 2 fun updatePointsCredit(accountId: Int) { if (EZPassAccounts.containsKey(accountId)) { // 3 println(\u0026quot;Updating $accountId...\u0026quot;) EZPassAccounts[accountId] = EZPassAccounts.getValue(accountId) + POINTS_X_PASS // 4 } else { println(\u0026quot;Error: Trying to update a non-existing account (id: $accountId)\u0026quot;) } } fun accountsReport() { println(\u0026quot;EZ-Pass report:\u0026quot;) EZPassReport.forEach { // 5 k, v -\u0026gt; println(\u0026quot;ID $k: credit $v\u0026quot;) } } fun main() { accountsReport() // 6 updatePointsCredit(1) // 7 updatePointsCredit(1) updatePointsCredit(5) // 8 accountsReport() // 9 }  1 创建一个可变的map ，并且展示了 to的用法 2 创建一个不可变的引用 3 检查key是否已经存在 4 读取key相对应的value ，并且将其修改 5 遍历不可变map 和输出他的键值对 6 在修改之前，先打印出结果 7 修改两次存在的key的对应的value 8 修改不存在的key对应的value 9 再打印一遍结果   filter #  过滤方法可以允许你对集合进行过滤，filter 需要你提供一个lambda的参数，lambda函数将会对每一个元素进行判断，如果判断的是true，那么久将结果加入到返回的集合中去。\nfun main() { val numbers = listOf(1, -2, 3, -4, 5, -6) // 1 val positives = numbers.filter { x -\u0026gt; x \u0026gt; 0 } // 2 val negatives = numbers.filter { it \u0026lt; 0 } // 3 println(\u0026quot;Numbers: $numbers\u0026quot;) println(\u0026quot;Positive Numbers: $positives\u0026quot;) println(\u0026quot;Negative Numbers: $negatives\u0026quot;) } /* Numbers: [1, -2, 3, -4, 5, -6] Positive Numbers: [1, 3, 5] Negative Numbers: [-2, -4, -6] */  1 创建一个list 2 过滤保留大于0的元素 3 过滤保留小于0的元素   map #  map 这个扩展方法，可以让你对集合中的每个元素做一个转化，你需要的是传入一个lambda的函数，作为转化所必须的元素。\nfun main() { val numbers = listOf(1, -2, 3, -4, 5, -6) // 1 val doubled = numbers.map { x -\u0026gt; x * 2 } // 2 val tripled = numbers.map { it * 3 } // 3 println(\u0026quot;Numbers: $numbers\u0026quot;) println(\u0026quot;Doubled Numbers: $doubled\u0026quot;) println(\u0026quot;Tripled Numbers: $tripled\u0026quot;) } /* Numbers: [1, -2, 3, -4, 5, -6] Doubled Numbers: [2, -4, 6, -8, 10, -12] Tripled Numbers: [3, -6, 9, -12, 15, -18] */  1 创建一个list 2 所有元素都 * 2 3 所有元素都 * 3，这里可以便捷的使用it，因为这里可以进行类型推断   any, all, none #  这几个方法用于检查集合中的方法是否符合给出的条件\nany #  any 方法当集合中至少有一个符合给出的条件就返回true\nfun main() { val numbers = listOf(1, -2, 3, -4, 5, -6) // 1 val anyNegative = numbers.any { it \u0026lt; 0 } // 2 val anyGT6 = numbers.any { it \u0026gt; 6 } // 3 println(\u0026quot;Numbers: $numbers\u0026quot;) println(\u0026quot;Is there any number less than 0: $anyNegative\u0026quot;) println(\u0026quot;Is there any number greater than 6: $anyGT6\u0026quot;) /* Numbers: [1, -2, 3, -4, 5, -6] Is there any number less than 0: true Is there any number greater than 6: false */ }  1 定义一个list 2 是否有一个元素小于0 3 是否有一个元素大于6  all #  当集合中所有的元素都符合条件的时候返回true\nfun main() { val numbers = listOf(1, -2, 3, -4, 5, -6) // 1 val allEven = numbers.all { it % 2 == 0 } // 2 val allLess6 = numbers.all { it \u0026lt; 6 } // 3 println(\u0026quot;Numbers: $numbers\u0026quot;) println(\u0026quot;All numbers are even: $allEven\u0026quot;) println(\u0026quot;All numbers are less than 6: $allLess6\u0026quot;) /* Numbers: [1, -2, 3, -4, 5, -6] All numbers are even: false All numbers are less than 6: true */ }  1 定义一个数组 2 判断是否所有元素都是偶数 3 判断是否所有元素都小于6  none #  当没有一个元素是符合给出的条件的是否返回true\nfun main() { val numbers = listOf(1, -2, 3, -4, 5, -6) // 1 val allEven = numbers.none { it % 2 == 1 } // 2 val allLess6 = numbers.none { it \u0026gt; 6 } // 3 println(\u0026quot;Numbers: $numbers\u0026quot;) println(\u0026quot;All numbers are even: $allEven\u0026quot;) println(\u0026quot;No element greater than 6: $allLess6\u0026quot;) /* Numbers: [1, -2, 3, -4, 5, -6] All numbers are even: false No element greater than 6: true */ }  1 定义一个list 2 检查是否没有元素是奇数 3 检查是否没有元素都是大于6   find, findLast #  查找集合中符和条件的第一个元素或者最后一个元素，如果查找不到就返回null。\nfun main() { val words = listOf(\u0026quot;Lets\u0026quot;, \u0026quot;find\u0026quot;, \u0026quot;something\u0026quot;, \u0026quot;in\u0026quot;, \u0026quot;collection\u0026quot;, \u0026quot;somehow\u0026quot;) // 1 val first = words.find { it.startsWith(\u0026quot;some\u0026quot;) } // 2 val last = words.findLast { it.startsWith(\u0026quot;some\u0026quot;) } // 3 val nothing = words.find { it.contains(\u0026quot;nothing\u0026quot;) } // 4 println(\u0026quot;The first word starting with \\\u0026quot;some\\\u0026quot; is \\\u0026quot;$first\\\u0026quot;\u0026quot;) println(\u0026quot;The last word starting with \\\u0026quot;some\\\u0026quot; is \\\u0026quot;$last\\\u0026quot;\u0026quot;) println(\u0026quot;The first word containing \\\u0026quot;nothing\\\u0026quot; is ${nothing?.let { \u0026quot;\\\u0026quot;$it\\\u0026quot;\u0026quot; } ?: \u0026quot;null\u0026quot;}\u0026quot;) } /* The first word starting with \u0026quot;some\u0026quot; is \u0026quot;something\u0026quot; The last word starting with \u0026quot;some\u0026quot; is \u0026quot;somehow\u0026quot; The first word containing \u0026quot;nothing\u0026quot; is null */  1 创建一个list 2 查找以some开头的第一个元素 3 察州以some开头的最后一个元素 4 查找包含noting的第一个元素   first, last #  first, last #  返回相应的集合的第一个或者最后一个元素。你可以传入lambda表达式作为条件来筛选 第一个或者最后一个元素。这个方法会是一种断言的方法，如果集合为空，或者不包含符和条件的元素将会抛出 NoSuchElementException\nfun main() { val numbers = listOf(1, -2, 3, -4, 5, -6) // 1 val first = numbers.first() // 2 val last = numbers.last() // 3 val firstEven = numbers.first { it % 2 == 0 } // 4 val lastOdd = numbers.last { it % 2 != 0 } // 5 println(\u0026quot;Numbers: $numbers\u0026quot;) println(\u0026quot;First $first, last $last, first even $firstEven, last odd $lastOdd\u0026quot;) }  1 创建一个list 2 读取list的第一个元素 3 读取list的最后一个元素 4 读取第一个符和条件的元素，及第一个偶数 5 读取最后一个符和条件的元素，及最后一个奇数  firstOrNull, lastOrNull #  这些方法与上面两个方法不同在于，如果没有符和条件的元素，将会返回null\nfun main() { val words = listOf(\u0026quot;foo\u0026quot;, \u0026quot;bar\u0026quot;, \u0026quot;baz\u0026quot;, \u0026quot;faz\u0026quot;) // 1 val empty = emptyList\u0026lt;String\u0026gt;() // 2 val first = empty.firstOrNull() // 3 val last = empty.lastOrNull() // 4 val firstF = words.firstOrNull { it.startsWith('f') } // 5 val firstZ = words.firstOrNull { it.startsWith('z') } // 6 val lastF = words.lastOrNull { it.endsWith('f') } // 7 val lastZ = words.lastOrNull { it.endsWith('z') } // 8 println(\u0026quot;First $first, last $last\u0026quot;) println(\u0026quot;First starts with 'f' is $firstF, last starts with 'z' is $firstZ\u0026quot;) println(\u0026quot;First ends with 'f' is $lastF, last ends with 'z' is $lastZ\u0026quot;) }  1 定义一个list 2 定义一个空list 3 读取空list的第一个元素，这里返回null，不会报错 4 读取空list的最后一个元素，这里返回null，不会报错 5 查找符和条件的第一个元素，结果是foo 6 查找符和条件的第一个元素，结果是null 7 查找符和条件的最后一个元素，结果是null 8 查找符和条件的最后一个元素，结果是faz   count #  count 方法将会返回集合的元素个数，或者返回符和条件的集合的元素个数\nfun main() { val numbers = listOf(1, -2, 3, -4, 5, -6) // 1 val totalCount = numbers.count() // 2 val evenCount = numbers.count { it % 2 == 0 } // 3 println(\u0026quot;Total number of elements: $totalCount\u0026quot;) println(\u0026quot;Number of even elements: $evenCount\u0026quot;) }  1 定义一个llist 2 计算数量 3 计算符和条件的数量，这里是计算所有偶数的数量   associateBy, groupBy #  两个方法都用于从一个集合中通过对key 进行归类然后来创建一个map。key 可以通过使用keySelector参数来选择，你也可以通过valueSelector 来进行value的选择。\n两者之间的区别\n associateBy：value 会使用符和条件的最后一个元素 groupBy：会把所有符和条件的元素作为放到一个数组中 作为value 返回的map中的entry的顺序维持了原来的list的顺序。  fun main() { data class Person(val name: String, val city: String, val phone: String) // 1 val people = listOf( // 2 Person(\u0026quot;John\u0026quot;, \u0026quot;Boston\u0026quot;, \u0026quot;+1-888-123456\u0026quot;), Person(\u0026quot;Sarah\u0026quot;, \u0026quot;Munich\u0026quot;, \u0026quot;+49-777-789123\u0026quot;), Person(\u0026quot;Svyatoslav\u0026quot;, \u0026quot;Saint-Petersburg\u0026quot;, \u0026quot;+7-999-456789\u0026quot;), Person(\u0026quot;Vasilisa\u0026quot;, \u0026quot;Saint-Petersburg\u0026quot;, \u0026quot;+7-999-123456\u0026quot;)) val phoneBook = people.associateBy { it.phone } // 3 val cityBook = people.associateBy(Person::phone, Person::city) // 4 val peopleCities = people.groupBy(Person::city, Person::name) // 5 println(\u0026quot;People: $people\u0026quot;) println(\u0026quot;Phone book: $phoneBook\u0026quot;) println(\u0026quot;City book: $cityBook\u0026quot;) println(\u0026quot;People living in each city: $peopleCities\u0026quot;) } /* People: [Person(name=John, city=Boston, phone=+1-888-123456), Person(name=Sarah, city=Munich, phone=+49-777-789123), Person(name=Svyatoslav, city=Saint-Petersburg, phone=+7-999-456789), Person(name=Vasilisa, city=Saint-Petersburg, phone=+7-999-123456)] Phone book: {+1-888-123456=Person(name=John, city=Boston, phone=+1-888-123456), +49-777-789123=Person(name=Sarah, city=Munich, phone=+49-777-789123), +7-999-456789=Person(name=Svyatoslav, city=Saint-Petersburg, phone=+7-999-456789), +7-999-123456=Person(name=Vasilisa, city=Saint-Petersburg, phone=+7-999-123456)} City book: {+1-888-123456=Boston, +49-777-789123=Munich, +7-999-456789=Saint-Petersburg, +7-999-123456=Saint-Petersburg} People living in each city: {Boston=[John], Munich=[Sarah], Saint-Petersburg=[Svyatoslav, Vasilisa]} */  1 定义一个data class 2 定义一个people的list 3 构建一个map，这个map的key是 people的的phone， value没有写，就默认为自身。 4 构建一个map，key为people的phone，value 为people的city 5 构建一个map，key为city，value为city相同的所有people的name   partition #  用于将一个list分为两个部分，\nfun main() { val numbers = listOf(1, -2, 3, -4, 5, -6) // 1 val evenOdd = numbers.partition { it % 2 == 0 } // 2 val (positives, negatives) = numbers.partition { it \u0026gt; 0 } // 3 println(\u0026quot;Numbers: $numbers\u0026quot;) println(\u0026quot;Even numbers: ${evenOdd.first}\u0026quot;) println(\u0026quot;Odd numbers: ${evenOdd.second}\u0026quot;) println(\u0026quot;Positive numbers: $positives\u0026quot;) println(\u0026quot;Negative numbers: $negatives\u0026quot;) }  flatMap #  用于遍历集合中的每个元素，然后将所有的结果放置到一个单独的数组中去。转化方式由用户定义。\nfun main() { val numbers1 = listOf(\u0026quot;1\u0026quot;, \u0026quot;2\u0026quot;, \u0026quot;3\u0026quot;) // 1 val numbers = listOf(1, 2, 3) val tripled = numbers.flatMap { listOf(it, it, it) } // 2 val tripled1 = numbers1.flatMap { listOf(it, it + 1) } println(\u0026quot;Numbers: $numbers1\u0026quot;) println(\u0026quot;Transformed: $tripled1\u0026quot;) println(\u0026quot;Numbers: $numbers\u0026quot;) println(\u0026quot;Transformed: $tripled\u0026quot;) }  1 定义一个数字的数组 2 关键点在于返回的结果不是一个list的list 而是一个list 有九个元素   min, max #  选出集合中最大和最小的元素，其中如果集合为空，则返回null\nfun main() { val numbers = listOf(1, 2, 3) val empty = emptyList\u0026lt;Int\u0026gt;() val numbers1 = listOf(\u0026quot;1\u0026quot;, \u0026quot;2\u0026quot;, \u0026quot;3\u0026quot;) println(\u0026quot;Numbers: $numbers, min = ${numbers.min()} max = ${numbers.max()}\u0026quot;) // 1 println(\u0026quot;Empty: $empty, min = ${empty.min()}, max = ${empty.max()}\u0026quot;) // 2 println(\u0026quot;Numbers: $numbers1, min = ${numbers1.min()} max = ${numbers1.max()}\u0026quot;) // 3 } /* Numbers: [1, 2, 3], min = 1 max = 3 Empty: [], min = null, max = null */  sorted #  返回一个集合的list 根据他们的自然排列顺序（升序） sortedBy 根据某个规则按照升序的方式排列\nimport kotlin.math.abs fun main() { val shuffled = listOf(5, 4, 2, 1, 3, -10) // 1 val natural = shuffled.sorted() // 2 val inverted = shuffled.sortedBy { -it } // 3 val descending = shuffled.sortedDescending() // 4 val descendingBy = shuffled.sortedByDescending { abs(it) } // 5 println(\u0026quot;Shuffled: $shuffled\u0026quot;) println(\u0026quot;Natural order: $natural\u0026quot;) println(\u0026quot;Inverted natural order: $inverted\u0026quot;) println(\u0026quot;Inverted natural order by absolute value: $descending\u0026quot;) println(\u0026quot;Inverted natural order of absolute values: $descendingBy\u0026quot;) }  1 创建一个list 2 排序，按照自然关系排序 3 按照自然关系倒序排序 4 按照自然关系倒序排序，通过使用sortedDescending 5 按照自然关系倒序排序，通过将每个元素进行取绝对值运算   Map Element Access map元素的访问 #  kotlin 通过 [] 来获取value根据key值，如果获取不到就返回null。getvalue() 方法也可以获取当前的value，只不过如果获取不到value，将会throw exception。我们可以通过withDefault 创建一个新的map，在这个map中，getvalue()将不会抛出异常，取而代之地是将会返回默认值\nfun main(args: Array\u0026lt;String\u0026gt;) { val map = mapOf(\u0026quot;key\u0026quot; to 42) val value1 = map[\u0026quot;key\u0026quot;] // 1 val value2 = map[\u0026quot;key2\u0026quot;] // 2 val value3: Int = map.getValue(\u0026quot;key\u0026quot;) // 1 val mapWithDefault = map.withDefault { k -\u0026gt; k.length } val value4 = mapWithDefault.getValue(\u0026quot;key2\u0026quot;) // 3 try { map.getValue(\u0026quot;anotherKey\u0026quot;) // 4 } catch (e: NoSuchElementException) { println(\u0026quot;Message: $e\u0026quot;) } println(\u0026quot;value1 is $value1\u0026quot;) println(\u0026quot;value2 is $value2\u0026quot;) println(\u0026quot;value3 is $value3\u0026quot;) println(\u0026quot;value4 is $value4\u0026quot;) }  1 返回42 2 返回null 3 返回4，value 是计算出来地，按照代码是根据key地长度 计算出来地。 4 报错，anotherKey 不在map中   zip #  将两个集合合并成一个新的集合，默认的合成方式为，结果集中包含的是两个集合的元素按照index 两两组成一个pair，当然你可以按照直接的方式来组成新的数据结构。 结果集的大小是由两个源数据的长度的最小值来决定的\nfun main() { val A = listOf(\u0026quot;a\u0026quot;, \u0026quot;b\u0026quot;, \u0026quot;c\u0026quot;) // 1 val B = listOf(1, 2, 3, 4) // 1 val resultPairs = A zip B // 2 val resultReduce = A.zip(B) { a, b -\u0026gt; \u0026quot;$a$b\u0026quot; } // 3 println(\u0026quot;A to B: $resultPairs\u0026quot;) println(\u0026quot;\\$A\\$B: $resultReduce\u0026quot;) } /* A to B: [(a, 1), (b, 2), (c, 3)] $A$B: [a1, b2, c3] */  1 定义了两个list 2 将两个list 合并成一个pair的list。zip 作为一个中缀方法在这里使用 3 将两个list合并成一个list，按照给出的方式合并，在这里，两个参数将被合并成为一个string。结果集也就是一个stirng的list   getOrElse #  这个方法提供了一种安全的方式去访问list，不用再担心数组越界的问题，如果访问的不是数组内的index，你可以提供一个默认的值以返回。\nfun main() { val list = listOf(0, 10, 20) println(list.getOrElse(1) { 42 }) // 1 println(list.getOrElse(10) { 42 }) // 2 } /* 10 42 */  1 打印了第二个元素 10 2 第11个元素明显越界了，返回了提供的默认值 42  getOrElse还可以用在map上。\nfun main() { val map = mutableMapOf\u0026lt;String, Int?\u0026gt;() println(map.getOrElse(\u0026quot;x\u0026quot;) { 1 }) // 1 map[\u0026quot;x\u0026quot;] = 3 println(map.getOrElse(\u0026quot;x\u0026quot;) { 1 }) // 2 map[\u0026quot;x\u0026quot;] = null println(map.getOrElse(\u0026quot;x\u0026quot;) { 1 }) // 3 } /* 1 3 1 */  1 打印了默认值1 因为x 不在key的范围内 2 打印了 3 因为添加了x的k-v 到map中 3 打印了1 应为key为x的value置为null了  "});index.add({'id':57,'href':'/docs/others/protocal/','title':"Protocal",'section':"Others",'content':"协议 #    RTSP  HTTP  "});index.add({'id':58,'href':'/docs/java/%E5%A4%9A%E7%BA%BF%E7%A8%8B/','title':"多线程",'section':"Java",'content':"java 的多线程和 android的多线程模块\n"});index.add({'id':59,'href':'/docs/open_sources/okhttp/','title':"Okhttp",'section':"OpenSources",'content':"okhttp #  整体流程 #  client -\u0026gt; newCall -\u0026gt; dispatcher -\u0026gt; interceptors -\u0026gt; response\nokhttp 使用栗子 #  "});index.add({'id':60,'href':'/docs/open_sources/glide/','title':"Glide 基础",'section':"OpenSources",'content':"glide #   \nglide 类图 #  "});index.add({'id':61,'href':'/docs/arch/dagger/','title':"Dagger",'section':"Arch",'content':"Dagger #  hilt #  AutoService #  "});index.add({'id':62,'href':'/docs/arch/jetpack/','title':"Jetpack",'section':"Arch",'content':"  本文所有的信息来源于官网的数据 https://developer.android.google.cn/jetpack/\n     库 说明      activity * 访问基于 Activity 构建的可组合 API。    ads 获取广告 ID（无论是否通过 Play 服务）。    annotation 公开元数据，帮助工具开发者和其他开发者了解您的应用代码。    appcompat * 允许在平台旧版 API 上访问新 API（很多使用 Material Design）。    arch.core 其他架构依赖项的帮助程序，包括可与 LiveData 配合使用的 JUnit 测试规则。    asynclayoutinflater 异步膨胀布局以避免界面出现卡顿。    autofill 通过扩展提示提高自动填充的准确性。    benchmark 在 Android Studio 中准确评估代码的性能。    biometric 通过生物识别特征或设备凭据进行身份验证，以及执行加密操作。    browser 在用户的默认浏览器中显示网页。    camera * 构建移动相机应用。    car 为支持 Android 技术的汽车开发驾驶友好型应用。    cardview 用圆角和阴影实现 Material Design 卡片图案。    collection 降低较小的现有集合和新集合对内存的影响。    compose 使用描述界面形状和数据依赖项的可组合函数，以编程方式定义界面。    compose.animation 在 Jetpack Compose 应用中构建动画，丰富用户的体验。    compose.foundation 使用现成可用的构建块编写 Jetpack Compose 应用，还可扩展 Foundation 以构建您自己的设计系统元素。    compose.material 使用现成可用的 Material Design 组件构建 Jetpack Compose UI。这是 Compose 的更高级别的入口点，旨在提供与 www.material.io 上描述的组件一致的组件。    compose.runtime Compose 的编程模型和状态管理的基本构建块，以及 Compose 编译器插件针对的核心运行时。    compose.ui 与设备互动所需的 Compose UI 的基本组件，包括布局、绘图和输入。    concurrent 使用协程将任务移出主线程，并充分利用 ListenableFuture。    constraintlayout 使用相对定位灵活地确定微件的位置和大小。    contentpager 在后台线程中加载 ContentProvider 数据并进行分页。    coordinatorlayout 定位顶级应用微件，例如 AppBarLayout 和 FloatingActionButton。    core 针对最新的平台功能和 API 调整应用，同时还支持旧设备。    cursoradapter 向 ListView 微件提供光标数据。    customview 实现自定义视图。    databinding * 使用声明性格式将布局中的界面组件绑定到应用中的数据源。    documentfile 查看文件文档。    drawerlayout 实现 Material Design 抽屉式导航栏微件。    dynamicanimation 使用基于物理特性的动画 API 制作流畅的动画。    emoji 在当前设备和旧版本设备上显示表情符号。    enterprise 创建企业专用应用。    exifinterface 读取和写入图片文件 EXIF 标记。    fragment * 将您的应用细分为在一个 Activity 中托管的多个独立屏幕。    gaming 在您的应用中以原生方式使用 Android 游戏 SDK 来执行复杂的游戏任务，例如帧同步。    gridlayout 实现网格布局。    heifwriter 使用 Android 设备上可用的编解码器，以 HEIF 格式对图像或图像集进行编码。    hilt 扩展了 Dagger Hilt 的功能，以实现 androidx 库中某些类的依赖项注入。    interpolator 在旧版平台上使用动画插值器。    jetifier 一款独立工具，可将某个库中对已弃用支持库的依赖项迁移到等效的 AndroidX 依赖项。    leanback 使用适合 dpad 的微件和模板 Fragment 为 Android TV 设备编写应用。    legacy 此工件及其类已弃用。从 Android 8 开始，后台检查限制会使此类不再有用。    lifecycle * 构建生命周期感知型组件，这些组件可以根据 Activity 或 Fragment 的当前生命周期状态调整行为。    loader 加载配置更改后继续存在的界面数据。    localbroadcastmanager 此工件及其类已弃用。请改用 LiveData 或响应式流。    media 与其他应用共享媒体内容和控件。已被 media2 取代。    media2 与其他应用共享媒体内容和控件。    mediarouter 利用通用界面实现在远程接收端设备上显示和播放媒体内容。    multidex 在搭载 Android 5 之前版本的设备上部署包含多个 dex 文件的应用。    navigation * 构建和组织应用内界面，处理深层链接以及在屏幕之间导航。    paging * 在页面中加载数据，并在 RecyclerView 中呈现。    palette 从图片中提取具有代表性的调色板。    percentlayout 此工件及其类已弃用。请改用 ConstraintLayout 和关联布局。    preference 无需与设备存储空间交互，也不需要管理界面，便能构建交互式设置画面。    print 通过您的应用打印照片、文档和其他图形及图片。    recommendation 将内容推广到 Android TV 启动器的主屏幕。    recyclerview 在您的界面中显示大量数据，同时最大限度减少内存用量。    remotecallback 创建一个封装容器，以便开发者更轻松地提供 PendingIntent。    room * 创建、存储和管理由 SQLite 数据库支持的持久性数据。    savedstate 编写可插入组件，这些组件会在进程终止时保存界面状态，并在进程重启时恢复界面状态。    security 安全地管理密钥并对文件和 sharedpreferences 进行加密。    sharetarget 提供向后兼容性，可以将快捷方式用作直接共享目标。    slice 在应用外显示模板化界面元素。    slidingpanelayout 实现滑动窗格界面模式。    startup 实现一种在应用启动时初始化组件的简单、高效方法。    sqlite 使用本地 SQLite 数据库。如果可能，请改用 Room。    swiperefreshlayout 实现下拉刷新的界面模式。    test * 在 Android 中进行测试。    textclassifier 识别文本中的对话、链接、选定内容和其他类似构造内容。    tracing 将跟踪事件写入系统跟踪缓冲区。    transition 使用开始和结束布局为界面中的动作添加动画效果。    tvprovider 提供 Android TV 频道。    ui 使用 Jetpack Compose 库。    vectordrawable 渲染矢量图形。    versionedparcelable 提供稳定且紧凑的二进制序列化格式，该格式可跨进程传递或安全保留。    viewpager 以可滑动的格式显示视图或 Fragment。如果可能，请改用 viewpager2。    viewpager2 以可滑动的格式显示视图或 Fragment。    wear 打造适用于 Wear OS by Google 谷歌智能手表的应用。    webkit 在 Android 5 及更高版本上使用新式 WebView API。    window 帮助支持不同的设备类型，例如可折叠设备。    work * 调度和执行可延期且基于约束条件的后台任务。     这是截至8月27日 官网上看到的所有的 jetpack提供的功能 这里我将找几个比较常用的库 来学习 jetpack 是如何做到 如它所说的 Jetpack 是一个由多个库组成的套件，可帮助开发者遵循最佳做法，减少样板代码并编写可在各种 Android 版本和设备中一致运行的代码，让开发者精力集中编写重要的代码。\n "});index.add({'id':63,'href':'/docs/kotlin/plus/','title':"Plus",'section':"Kotlin",'content':"协程\n"});index.add({'id':64,'href':'/docs/kotlin/samples/','title':"Samples",'section':"Kotlin",'content':"协程\n"});index.add({'id':65,'href':'/docs/arch/design_pattern/','title':"设计模式",'section':"Arch",'content':"设计模式文档大纲 #    设计模式-参考文档\n 设计模式模块都将按照这个模板来进行介绍\n 设计模式总体介绍 举个现有的栗子 该模式的子模块以及详解  "});index.add({'id':66,'href':'/posts/gradle_connect_reset/','title':"Gradle connect Reset",'section':"随笔",'content':" Could not install Gradle distribution from \u0026lsquo;https://services.gradle.org/distributions/gradle-6.5.1-all.zip'.\n 换了电脑之后发现gradle 下载不下来了，在研究了一番之后我找到了一下的方法。\n  到这个页面https://services.gradle.org/distributions/ 下载你需要的内容，可以用迅雷等工具下载。记得下载all.zip 的包\n  cd 到 {user}/.gradle/wrapper/dist 目录之下\n  android studio 中sync 一下，将会创建对应的目录\n  这个是项目目录下的gradle-wrapper.properties内容\ndistributionBase=GRADLE_USER_HOME distributionPath=wrapper/dists zipStoreBase=GRADLE_USER_HOME zipStorePath=wrapper/dists distributionUrl=https\\://services.gradle.org/distributions/gradle-6.5.1-all.zip 比如上面这个将会在 {user}/.gradle/wrapper/dist 目录下创建\ngradle-6.5.1-all/cdund22i8guosqylfo49op4dv 类似于这样的一个目录\n  cd 进去\ndrwxr-xr-x 10 bokmark staff 320 11 18 21:59 gradle-6.5.1 -rwxr-xr-x@ 1 bokmark staff 145830284 11 18 21:59 gradle-6.5.1-all.zip -rw-r--r-- 1 bokmark staff 0 11 18 21:59 gradle-6.5.1-all.zip.lck -rw-r--r-- 1 bokmark staff 0 11 18 21:59 gradle-6.5.1-all.zip.ok 这是成功的目录结构。\n-rw-r--r-- 1 bokmark staff 0 11 19 10:11 gradle-6.1.1-all.zip.lck -rw-r--r-- 1 bokmark staff 1156054 11 19 10:11 gradle-6.1.1-all.zip.part 这是失败的目录结构。\n  so，我们如果遇到 gradle 无法sync 的问题，就是先找到这个目录gradle-6.5.1-all/cdund22i8guosqylfo49op4dv\n  然后 rm -rf *\n  然后将通过迅雷下载好的 https://services.gradle.org/distributions/ 这个里面下载的gradle-xxx-all.zip 放到这个目录下\n  android studio中 sync 一下。\n  成功sync\n  如果需要别的版本的gradle可以再如法炮制\n  "});index.add({'id':67,'href':'/posts/maven-snapshot/','title':"Maven snapshot",'section':"随笔",'content':" 转载自 https://www.runoob.com/maven/maven-snapshots.html\n Maven 快照(SNAPSHOT) #  一个大型的软件应用通常包含多个模块，并且通常的场景是多个团队开发同一应用的不同模块。举个例子，设想一个团队开发应用的前端，项目为 app-ui(app-ui.jar:1.0)，而另一个团队开发应用的后台，使用的项目是 data-service(data-service.jar:1.0)。\n现在可能出现的情况是开发 data-service 的团队正在进行快节奏的 bug 修复或者项目改进，并且他们几乎每隔一天就要发布库到远程仓库。 现在如果 data-service 团队每隔一天上传一个新版本，那么将会出现下面的问题：\n data-service 团队每次发布更新的代码时都要告知 app-ui 团队。 app-ui 团队需要经常地更新他们 pom.xml 文件到最新版本。  为了解决这种情况，快照的概念派上了用场。\n 什么是快照? #  快照是一种特殊的版本，指定了某个当前的开发进度的副本。不同于常规的版本，Maven 每次构建都会在远程仓库中检查新的快照。 现在 data-service 团队会每次发布更新代码的快照到仓库中，比如说 data-service:1.0-SNAPSHOT 来替代旧的快照 jar 包。\n 项目快照 vs 版本 #  对于版本，如果 Maven 以前下载过指定的版本文件，比如说 data-service:1.0，Maven 将不会再从仓库下载新的可用的 1.0 文件。若要下载更新的代码，data-service 的版本需要升到1.1。\n快照的情况下，每次 app-ui 团队构建他们的项目时，Maven 将自动获取最新的快照(data-service:1.0-SNAPSHOT)。\napp-ui 项目的 pom.xml 文件 #  app-ui 项目使用的是 data-service 项目的 1.0 快照。\n\u0026lt;project xmlns=\u0026#34;http://maven.apache.org/POM/4.0.0\u0026#34; xmlns:xsi=\u0026#34;http://www.w3.org/2001/XMLSchema-instance\u0026#34; xsi:schemaLocation=\u0026#34;http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd\u0026#34;\u0026gt; \u0026lt;modelVersion\u0026gt;4.0.0\u0026lt;/modelVersion\u0026gt; \u0026lt;groupId\u0026gt;app-ui\u0026lt;/groupId\u0026gt; \u0026lt;artifactId\u0026gt;app-ui\u0026lt;/artifactId\u0026gt; \u0026lt;version\u0026gt;1.0\u0026lt;/version\u0026gt; \u0026lt;packaging\u0026gt;jar\u0026lt;/packaging\u0026gt; \u0026lt;name\u0026gt;health\u0026lt;/name\u0026gt; \u0026lt;url\u0026gt;http://maven.apache.org\u0026lt;/url\u0026gt; \u0026lt;properties\u0026gt; \u0026lt;project.build.sourceEncoding\u0026gt;UTF-8\u0026lt;/project.build.sourceEncoding\u0026gt; \u0026lt;/properties\u0026gt; \u0026lt;dependencies\u0026gt; \u0026lt;dependency\u0026gt; \u0026lt;groupId\u0026gt;data-service\u0026lt;/groupId\u0026gt; \u0026lt;artifactId\u0026gt;data-service\u0026lt;/artifactId\u0026gt; \u0026lt;version\u0026gt;1.0-SNAPSHOT\u0026lt;/version\u0026gt; \u0026lt;scope\u0026gt;test\u0026lt;/scope\u0026gt; \u0026lt;/dependency\u0026gt; \u0026lt;/dependencies\u0026gt; \u0026lt;/project\u0026gt; data-service 项目的 pom.xml 文件 #  data-service 项目为每次小的改动发布 1.0 快照。\n\u0026lt;project xmlns=\u0026#34;http://maven.apache.org/POM/4.0.0\u0026#34; xmlns:xsi=\u0026#34;http://www.w3.org/2001/XMLSchema-instance\u0026#34; xsi:schemaLocation=\u0026#34;http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd\u0026#34;\u0026gt; \u0026lt;modelVersion\u0026gt;4.0.0\u0026lt;/modelVersion\u0026gt; \u0026lt;groupId\u0026gt;data-service\u0026lt;/groupId\u0026gt; \u0026lt;artifactId\u0026gt;data-service\u0026lt;/artifactId\u0026gt; \u0026lt;version\u0026gt;1.0-SNAPSHOT\u0026lt;/version\u0026gt; \u0026lt;packaging\u0026gt;jar\u0026lt;/packaging\u0026gt; \u0026lt;name\u0026gt;health\u0026lt;/name\u0026gt; \u0026lt;url\u0026gt;http://maven.apache.org\u0026lt;/url\u0026gt; \u0026lt;properties\u0026gt; \u0026lt;project.build.sourceEncoding\u0026gt;UTF-8\u0026lt;/project.build.sourceEncoding\u0026gt; \u0026lt;/properties\u0026gt; \u0026lt;/project\u0026gt; 虽然，快照的情况下，Maven 在日常工作中会自动获取最新的快照， 你也可以在任何 maven 命令中使用 -U 参数强制 maven 现在最新的快照构建。\n"});index.add({'id':68,'href':'/posts/sed/','title':"sed",'section':"随笔",'content':" 最近有个问题就是 测试发过来的 log 一大堆里面很多不是我们自己应用的log。我们就从去除无用log的角度来分析sed怎么用\n sed全名叫stream editor，流编辑器，用程序的方式来编辑文本 官方文档\n 如果你和作者一样是mac用户那么恭喜你了。mac上的sed 与linux的不同。你需要安装gnu的sed套件。\nbrew install coreutils brew install gnu-sed 这时候你可以使用gsed来代替sed命令 当然你可以通过添加这个\nexport PATH=\u0026quot;/usr/local/opt/gnu-sed/libexec/gnubin:$PATH\u0026quot; 到zsh或者bash的配置文件中来，来使用sed 代替gsed\n 我们主要是通过官方文档来进行sed的学习\nsed hello world #  大致的格式类似于sed SCRIPT INPUTFILE ...\nsed 's/hello/world/' input.txt \u0026gt; output.txt 这一句话的作用就是将input.txt 中的每一行中的第一个hello替换成world 然后输出到output.txt。\nsed的大致格式 #  sed OPTIONS... [SCRIPT] [INPUTFILE...] 作者将分别简单介绍 OPTIONS SCRIPT INPUTFILE\nSCRIPT #  首先一个SCRIPT的大致格式为 [addr]X[options]\naddr #  addr 表明了file中的哪些行会被执行command。先看一些例子，我们再简单的来归纳一些规则 '144s/hello/world/' ： 只有144行执行 替换hello到world的命令 's/hello/world/' : 每一行都执行 替换hello到world的命令 '/apple/s/hello/world/' ：只有包含apple的行才执行 替换hello到world的命令 '4,17s/hello/world/' : 4到17行 执行 替换hello到world的命令 '/apple/!s/hello/world/':不包含apple的行才执行 替换hello到world的命令 '4,17!s/hello/world/':不是4到17行 执行 替换hello到world的命令\n规则如下：\n 如果是数字选行不需要用/ 4,17选4到17的range   $代表最后一行     1~3 从1开始每隔3行   addr之后添加! 进行反选 /apple/! 不包含apple的行 4,17!不包含4到17的行 如果是非数字选行，那么需要用//包起来。包起来的内容是一个正则表达式 /bash$/ 匹配以bash结尾的行 and so on 更多的请直接到开篇提到的官网进行查询  X #   s replace p print d delete  options #  根据各个关键词进行添加\nINPUTFILE #  如果你没有输入inputfile 或者inputfile 为 -。sed将会把当前的输入视为inputfile。所以以下三种方式是等价的\nsed 's/hello/world/' input.txt \u0026gt; output.txt sed 's/hello/world/' \u0026lt; input.txt \u0026gt; output.txt cat input.txt | sed 's/hello/world/' - \u0026gt; output.txt  多文件 sed 将会把多文件 视为一整个长流 sed -n '1p ; $p' one.txt two.txt three.txt 这句话将会输出第一个文件的第一句话和最后一个文件的最后一句话。使用-s 反转这个列表\n  OPTIONS #    -i\nsed 使用 -i 来代替输出。\nsed -i 's/hello/world/' file.txt 这句话将会把file.txt 文件中的第一个 hello 替换成world。\n  -n sed 默认会输出所有的输入。我们可以使用-n来压制这些默认的输出\nsed -n '45p' file.txt 这里将会print出file.txt 文件的第45行。（p就是print的意思）\n  -e -f 在没有-e 或者-f的情况下，sed将会把把第一个非option参数作为script 下一个非option的参数作为inputfile。 如果有-e或者-f 那么剩下的非option参数作为inputfile。\nsed 's/hello/world/' input.txt \u0026gt; output.txt sed -e 's/hello/world/' input.txt \u0026gt; output.txt sed --expression='s/hello/world/' input.txt \u0026gt; output.txt echo 's/hello/world/' \u0026gt; myscript.sed sed -f myscript.sed input.txt \u0026gt; output.txt sed --file=myscript.sed input.txt \u0026gt; output.txt 上面的这一些语句都是等价的。（当然，myscript.sed 里面写着 s/hello/world）\n  开始我们的探索 #  别忘了我们的目的，是为了在整体的log文件中，找出我们自己的应用的log\n 找出我们的应用的进程号 比如我这里 32085  sed '/32085/!d' main.log \u0026gt; main.log.1 其他用法等下次用到 我们再加 #  "});index.add({'id':69,'href':'/posts/git_alias/','title':"我的git配置",'section':"随笔",'content':"# This is Git's per-user configuration file.\r[user]\r# Please adapt and uncomment the following lines:\rname = xxx\remail = xxx\r[filter \u0026quot;lfs\u0026quot;]\rclean = git-lfs clean -- %f\rsmudge = git-lfs smudge -- %f\rprocess = git-lfs filter-process\rrequired = true\r[alias]\rco = checkout\rcp = cherry-pick\rcm = commit\rba = branch -a\rbh = branch\ramend = commit -a --amend\rlg = log\rlo = log --oneline\rst = status\rdf = diff\rreview = !sh -c 'git push origin HEAD:refs/for/$1' -\rup = pull --rebase\r"});index.add({'id':70,'href':'/docs/%E4%B9%A6%E6%9C%AC/','title':"技术书籍",'section':"Docs",'content':"Java网络编程（第4版）\nEffective Java 中文第二版\nHead First Java中文版\nHead First 设计模式(中文版)\nHTTP权威指南\nJava编程思想（第4版）\nJava并发编程实战（中文版）\nTCP IP详解\n深入理解Java虚拟机：JVM高级特性与最佳实践\n推荐名单 #  Java #    Java 编程思想  Effective java 中文版  深入理解 Java 虚拟机  Java 并发编程的艺术  Java 并发编程实战  数据结构与算法 #    算法  算法导论  算法之美  数据结构与算法分析  剑指 Offer  操作系统 #    现代操作系统  深入理解计算机系统  鸟哥的 Linux 私房菜  计算机网络 #    计算机网络  计算机网络 自顶向下方法  图解 HTTP  系统设计 #    淘宝技术这十年  大规模分布式存储系统  大型网站系统与 Java 中间件开发实践  编码艺术 #    重构  编程珠玑  代码大全  人月神话  程序员的职业素养  编写可读代码的艺术  设计模式 #    Head First 设计模式  设计模式 可复用面向对象软件的基础  敏捷软件开发 原则、模式与实践  数据库 #    数据库系统概念  MySQL 必知必会  高性能 MySQL  "});index.add({'id':71,'href':'/docs/arch/jetpack/compose/','title':"Compose",'section':"Jetpack",'content':"Compose #  第一步 Jetpack Compose 是干嘛用的？ #  做过启动优化的同学一定会发现LayoutInflater.inflate实在是太慢了，可是真当你一点点得去优化xml却不会有太多的提升，真的是搞得人头疼。这时候就要分析 LayoutInflater.inflate 里面到底做了什么？让我们来研究一下吧。\n public View inflate(@LayoutRes int resource, @Nullable ViewGroup root, boolean attachToRoot) { final Resources res = getContext().getResources(); if (DEBUG) { Log.d(TAG, \u0026quot;INFLATING from resource: \\\u0026quot;\u0026quot; + res.getResourceName(resource) + \u0026quot;\\\u0026quot; (\u0026quot; + Integer.toHexString(resource) + \u0026quot;)\u0026quot;); } View view = tryInflatePrecompiled(resource, res, root, attachToRoot); // 1 if (view != null) { return view; } XmlResourceParser parser = res.getLayout(resource); // 2 try { return inflate(parser, root, attachToRoot); // 3 } finally { parser.close(); }  1 tryInflatePrecompiled 这是另外一个故事我们之后再说。 2 这里的代码也不细贴了主要就是io读取文件内容。 这是一个大耗时。 3 关键的调用是在这里，我们深入再看。   public View inflate(XmlPullParser parser, @Nullable ViewGroup root, boolean attachToRoot) { synchronized (mConstructorArgs) { Trace.traceBegin(Trace.TRACE_TAG_VIEW, \u0026quot;inflate\u0026quot;); //... try { if (TAG_MERGE.equals(name)) { // ... rInflate(parser, root, inflaterContext, attrs, false); // 1 } else { // Temp is the root view that was found in the xml final View temp = createViewFromTag(root, name, inflaterContext, attrs); // 2 // ... // Inflate all children under temp against its context. rInflateChildren(parser, temp, attrs, true); // 3 if (DEBUG) { System.out.println(\u0026quot;-----\u0026gt; done inflating children\u0026quot;); } // We are supposed to attach all the views we found (int temp) // to root. Do that now. if (root != null \u0026amp;\u0026amp; attachToRoot) { root.addView(temp, params); // 4 } } } catch (XmlPullParserException e) { // ... } return result; } }  1 这里的代码就不贴了 主要是处理 merge的代码 2 根据当前的属性创建一个view 3 递归创建子view 4 递归结束是否attach  LayoutInflater.inflate 做了什么我们现在大致也知道了，第一是读取io文件内容，第二是递归创建view组件，构建内存中的view树。这两步都是大耗时，而且看起来不可避免，因为你必然要用xml来定义界面，对吧。但是，对嘛？不一定哦！Jetpack compose就是为了解决这个问题。 #  第二步 Jetpack Compose 怎么用呢。 #  Jetpack Compose 是基于kotlin的，所以你的项目如果是java的。那么恭喜你，这是一个好时机将你的项目转化成kotlin，相信我，kotlin 真香！\n配置kotlin #  plugins { id 'org.jetbrains.kotlin.android' version '1.4.0' } 配置gradle #  android { defaultConfig { ... minSdkVersion 21 } buildFeatures { // 这里这里这里这里这里这里这里这里这里这里 compose true } ... // Set both the Java and Kotlin compilers to target Java 8. compileOptions { sourceCompatibility JavaVersion.VERSION_1_8 targetCompatibility JavaVersion.VERSION_1_8 } kotlinOptions { jvmTarget = \u0026quot;1.8\u0026quot; // 这里这里这里这里这里这里这里这里这里这里 useIR = true } // 这里这里这里这里这里这里这里这里这里这里 composeOptions { kotlinCompilerVersion '1.4.0' kotlinCompilerExtensionVersion '1.0.0-alpha01' } } 配置依赖 #  dependencies { implementation 'androidx.compose.ui:ui:1.0.0-alpha01' // Tooling support (Previews, etc.) implementation 'androidx.ui:ui-tooling:1.0.0-alpha01' // Foundation (Border, Background, Box, Image, Scroll, shapes, animations, etc.) implementation 'androidx.compose.foundation:foundation:1.0.0-alpha01' // Material Design implementation 'androidx.compose.material:material:1.0.0-alpha01' // Material design icons implementation 'androidx.compose.material:material-icons-core:1.0.0-alpha01' implementation 'androidx.compose.material:material-icons-extended:1.0.0-alpha01' // Integration with observables implementation 'androidx.compose.runtime:runtime-livedata:1.0.0-alpha01' implementation 'androidx.compose.runtime:runtime-rxjava2:1.0.0-alpha01' // UI Tests androidTestImplementation 'androidx.ui:ui-test:1.0.0-alpha01' } "});index.add({'id':72,'href':'/docs/java/%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%84/HashMap-%E6%BA%90%E7%A0%81%E8%A7%A3%E6%9E%90%E4%B8%8E%E9%9D%A2%E8%AF%95%E9%A2%98%E6%95%B4%E7%90%86/','title':"Hash Map 源码解析与面试题整理",'section':"数据结构",'content':" 源码解析不会通篇解析，会通过面试题整理来针对性地解析其中的关键点\n  主要的几个面试题：\n HashMap的底层原理是什么？线程安全么？ HashMap中put是如何实现的？ 谈一下hashMap中什么时候需要进行扩容，扩容resize()又是如何实现的？ 什么是哈希碰撞？怎么解决? HashMap和HashTable的区别 HashMap中什么时候需要进行扩容，扩容resize()是如何实现的？ hashmap concurrenthashmap原理 arraylist和hashmap的区别，为什么取数快？   1. HashMap的底层原理是什么？线程安全么？ #  HashMap的底层原理是链表的数组， 通过hash算法计算出 key的hash值再根据数组长度取模得到index 如果index相同，那么就排在同一个链表中。链表中根据key的hash值大小有序排列方便查找  jdk 1.8 之后 androidsdk 24 之后 hashmap 的内部实现有链表改为 链表加红黑树实现，当一个链表的长度大于 8之后将会在后续添加的时候转变为红黑树   get： 先通过hash算法计算出key的hash值 然后再通过hash根据 链表数组的长度取模 获得index。根据index去循环链表或者红黑树取到相应的value。 put： 先通过hash算法计算出key的hash值 然后再通过hash根据 链表数组的长度取模 获得index，再根据排列顺序将 entry放到链表或者红黑树中。  线程不安全，当多个线程操作的时候可能使读取的数据为错误数据。\n2. HashMap中put是如何实现的？ #   简单过程：先通过hash算法计算出key的hash值 然后再通过hash根据 链表数组的长度取模 获得index，再根据排列顺序将 entry放到链表或者红黑树中。 看代码：\n public V put(K key, V value) { return putVal(hash(key), key, value, false, true); } final V putVal(int hash, K key, V value, boolean onlyIfAbsent, boolean evict) { Node\u0026lt;K,V\u0026gt;[] tab; Node\u0026lt;K,V\u0026gt; p; int n, i; if ((tab = table) == null || (n = tab.length) == 0) n = (tab = resize()).length; // Step 1 获取hashmap中链表数组的长度（其中包含了一个重要的步骤 resize 之后在沟通）  if ((p = tab[i = (n - 1) \u0026amp; hash]) == null) // 此处 p指向了tab数值中对应index元素链表的头结点  tab[i] = newNode(hash, key, value, null); // Step 2 对key值的hash对 长度取模 （ (n - 1) \u0026amp; hash 等价于 hash % n ，此处采用位运算是为了性能考虑）得到i。 // 再检查数组i元素是否存在，如果不存在将node\u0026lt;k,v\u0026gt; 赋值  else { Node\u0026lt;K,V\u0026gt; e; K k; if (p.hash == hash \u0026amp;\u0026amp; ((k = p.key) == key || (key != null \u0026amp;\u0026amp; key.equals(k)))) // Step 3 如果key相同 用e标记，指向p，后面将会把新的value 赋值给p节点  e = p; else if (p instanceof TreeNode) // 如果链表开始就是 树结构的 那么用树结构的逻辑将节点保存  e = ((TreeNode\u0026lt;K,V\u0026gt;)p).putTreeVal(this, tab, hash, key, value); else { for (int binCount = 0; ; ++binCount) { if ((e = p.next) == null) { p.next = newNode(hash, key, value, null); if (binCount \u0026gt;= TREEIFY_THRESHOLD - 1) // -1 for 1st  treeifyBin(tab, hash); break; } if (e.hash == hash \u0026amp;\u0026amp; ((k = e.key) == key || (key != null \u0026amp;\u0026amp; key.equals(k)))) break; p = e; } } if (e != null) { // existing mapping for key  V oldValue = e.value; if (!onlyIfAbsent || oldValue == null) e.value = value; afterNodeAccess(e); return oldValue; } } ++modCount; if (++size \u0026gt; threshold) resize(); afterNodeInsertion(evict); return null; } "});index.add({'id':73,'href':'/posts/GithubPages/','title':"Github Pages服务",'section':"随笔",'content':"GithubPages #    作为一个程序员需要有一个记录知识点的地方，也需要一个做记录整理自己的知识体系的地方。GithubPages 作为影响力最大的博客网站，当我们需要进行博客搭建的时候，当然是选择他！\n 准备 #    Pages 这是github pages 提供的帮助文档。 我们按照他提供的步骤一步步的搭建好仓库。比如我取名就是bokmark.github.io  主题 这是主题列表。我们使用hugo 来将markdown文件转化为html文件  开始 #    第一步创建hugo的站\nhugo new site mysite\r  然后再选一个好看的theme，我这里推荐我使用的这个主题\ncd mysite\rgit clone https://github.com/jugglerx/hugo-whisper-theme.git themes/hugo-whisper-theme\r  修改config.toml\nbaseURL = \u0026quot;/\u0026quot;\rthemesDir = \u0026quot;themes\u0026quot;\rpublishdir = \u0026quot;docs\u0026quot;\rtheme = \u0026quot;hugo-whisper-theme\u0026quot;\r这里面最重要的是 publishdir = \u0026quot;docs\u0026quot;\n  创建你要的页面\nhugo new about.md\r// 会在content页面 创建about.md 文件\rhugo new notes/other/GithubPages.md\r// 会在 content/notes/other 目录下创建 GithubPages.md\r  运行\nhugo\r// 如果想要在本地看一下效果可以这样\rhugo server\r// localhost:1313\r这时候在docs文档下面将会生成我们需要的html文件\n  上传 将整个库上传到github，包括docs文件夹。你可以使用git命令 也可以用github desktop 都可以。\n  修改pages settings\n   来到你的仓库( https://github.com/{username}/{username}.github.io )的settings页面。 找到GitHub Pages栏 找到 Source 栏 select folder 选择docs 点击save   查看效果 https://{username}.github.io\n  亲测有效哦，毕竟你都看到这个页面了。\n  "});index.add({'id':74,'href':'/docs/arch/jetpack/startup/','title':"StartUp",'section':"Jetpack",'content':"StartUp 初始化组件 #    G oogle 官方解释\n 这是官方对于startup这个库的解释。\n App startup 库 提供了 一个直截了当、高性能的方式去初始化你的应用。第三方库和app的开发者都可以使用app startup这个库以数据流的方式去显示的安排启动的各个步骤。\napp startup这个库允许你只创建一个contentprovider 去初始化你的各个 initializer，这将有助与提升你的app启动时间。\n 从这段话中，我们可以看到几个重要的点。\n contentprovider 数据流的方式，显示的安排各个启动的步骤  配置 #  配置在你的app或者library的moudle中的build.gradle 中\ndependencies { implementation \u0026#34;androidx.startup:startup-runtime:1.0.0-alpha02\u0026#34; } 注册初始化组件 #  定义了一个默认的content provider，所有的 组件都由这个content provider的create 里面创建流程。 如果想要自动化的创建组件，需要在manifest中显示的写入你的组件。\n组件的创建 #  实现 Initializer\u0026lt;T\u0026gt; 接口。该接口有如下两个方法：\n T create(Context) 返回创建好的实例 dependencies() 创建该组件之前需要创建的其他组件。   以workmanager举例说明\n// Initializes WorkManager. class WorkManagerInitializer implements Initializer\u0026lt;WorkManager\u0026gt; { @Override public WorkManager create(Context context) { Configuration configuration = Configuration.Builder().build(); WorkManager.initialize(context, configuration); return WorkManager.getInstance(context); } @Override public List\u0026lt;Class\u0026lt;Initializer\u0026lt;?\u0026gt;\u0026gt;\u0026gt; dependencies() { // No dependencies on other libraries.  return emptyList(); } }  这个例子中间，我们可以看到由于不需要依赖与别的组件，dependencies 直接返回一个空的list\n 有依赖的组件的创建 #  // Initializes ExampleLogger. class ExampleLoggerInitializer implements Initializer\u0026lt;ExampleLogger\u0026gt; { @Override public ExampleLogger create(Context context) { // WorkManager.getInstance() is non-null only after  // WorkManager is initialized.  return ExampleLogger(WorkManager.getInstance(context)); } @Override public List\u0026lt;Class\u0026lt;Initializer\u0026lt;?\u0026gt;\u0026gt;\u0026gt; dependencies() { // Defines a dependency on WorkManagerInitializer so it can be  // initialized after WorkManager is initialized.  return Arrays.asList(WorkManagerInitializer.class); } } 这里在ExampleLogger 的create期间，workmanager已经创建好了，在这里可以直接是使用。\nmanifest的规范 #  startup 库依赖与InitializationProvider\n\u0026lt;provider android:name=\u0026#34;androidx.startup.InitializationProvider\u0026#34; android:authorities=\u0026#34;${applicationId}.androidx-startup\u0026#34; android:exported=\u0026#34;false\u0026#34; tools:node=\u0026#34;merge\u0026#34;\u0026gt; \u0026lt;!-- This entry makes ExampleLoggerInitializer discoverable. --\u0026gt; \u0026lt;meta-data android:name=\u0026#34;com.example.ExampleLoggerInitializer\u0026#34; android:value=\u0026#34;androidx.startup\u0026#34; /\u0026gt; \u0026lt;/provider\u0026gt; 再在provider的metadata中定义好自己的Initializer。就会自动注册组件。\nstartup的另一种用法 #  首先在xml中这样定义\n\u0026lt;provider android:name=\u0026#34;androidx.startup.InitializationProvider\u0026#34; android:authorities=\u0026#34;${applicationId}.androidx-startup\u0026#34; tools:node=\u0026#34;remove\u0026#34; /\u0026gt; 其次 调用这个方法，将会开始注册组件，而不会自动注册，同理，由于 workmangerinitializer是ExampleLoggerInitializer 的依赖，所以这里会自动的创建workmangerinitializer\nAppInitializer.getInstance(context) .initializeComponent(ExampleLoggerInitializer.class);  这次解析我们从 定义在 manifest中的 InitializationProvider 入手\n@RestrictTo(RestrictTo.Scope.LIBRARY) public final class InitializationProvider extends ContentProvider { @Override public boolean onCreate() { Context context = getContext(); if (context != null) { AppInitializer.getInstance(context).discoverAndInitialize(); } else { throw new StartupException(\u0026#34;Context cannot be null\u0026#34;); } return true; } @Nullable @Override public Cursor query( @NonNull Uri uri, @Nullable String[] projection, @Nullable String selection, @Nullable String[] selectionArgs, @Nullable String sortOrder) { throw new IllegalStateException(\u0026#34;Not allowed.\u0026#34;); } @Nullable @Override public String getType(@NonNull Uri uri) { throw new IllegalStateException(\u0026#34;Not allowed.\u0026#34;); } @Nullable @Override public Uri insert(@NonNull Uri uri, @Nullable ContentValues values) { throw new IllegalStateException(\u0026#34;Not allowed.\u0026#34;); } @Override public int delete( @NonNull Uri uri, @Nullable String selection, @Nullable String[] selectionArgs) { throw new IllegalStateException(\u0026#34;Not allowed.\u0026#34;); } @Override public int update( @NonNull Uri uri, @Nullable ContentValues values, @Nullable String selection, @Nullable String[] selectionArgs) { throw new IllegalStateException(\u0026#34;Not allowed.\u0026#34;); } } 这个provider 也很简单 关键的代码都在 AppInitializer.getInstance(context).discoverAndInitialize(); 这一句。\nvoid discoverAndInitialize() { try { Trace.beginSection(SECTION_NAME); ComponentName provider = new ComponentName(mContext.getPackageName(), InitializationProvider.class.getName()); ProviderInfo providerInfo = mContext.getPackageManager() .getProviderInfo(provider, GET_META_DATA); Bundle metadata = providerInfo.metaData; String startup = mContext.getString(R.string.androidx_startup); if (metadata != null) { Set\u0026lt;Class\u0026lt;?\u0026gt;\u0026gt; initializing = new HashSet\u0026lt;\u0026gt;(); Set\u0026lt;String\u0026gt; keys = metadata.keySet(); for (String key : keys) { String value = metadata.getString(key, null); if (startup.equals(value)) { Class\u0026lt;?\u0026gt; clazz = Class.forName(key); if (Initializer.class.isAssignableFrom(clazz)) { Class\u0026lt;? extends Initializer\u0026lt;?\u0026gt;\u0026gt; component = (Class\u0026lt;? extends Initializer\u0026lt;?\u0026gt;\u0026gt;) clazz; mDiscovered.add(component); if (StartupLogger.DEBUG) { StartupLogger.i(String.format(\u0026#34;Discovered %s\u0026#34;, key)); } doInitialize(component, initializing); } } } } } catch (PackageManager.NameNotFoundException | ClassNotFoundException exception) { throw new StartupException(exception); } finally { Trace.endSection(); } }  这个方法，首先第一步 获取定义在 provider 里面的 metadata。 第二步就是便利 metadata 获取所有value为 R.string.androidx_startup 的key值。 第三步 通过name 获取class 执行 doInitialize(component, initializing);  \u0026lt;T\u0026gt; T doInitialize( @NonNull Class\u0026lt;? extends Initializer\u0026lt;?\u0026gt;\u0026gt; component, @NonNull Set\u0026lt;Class\u0026lt;?\u0026gt;\u0026gt; initializing) { synchronized (sLock) { boolean isTracingEnabled = Trace.isEnabled(); try { if (isTracingEnabled) { // Use the simpleName here because section names would get too big otherwise.  Trace.beginSection(component.getSimpleName()); } if (initializing.contains(component)) { String message = String.format( \u0026#34;Cannot initialize %s. Cycle detected.\u0026#34;, component.getName() ); throw new IllegalStateException(message); } Object result; if (!mInitialized.containsKey(component)) { initializing.add(component); try { Object instance = component.getDeclaredConstructor().newInstance(); Initializer\u0026lt;?\u0026gt; initializer = (Initializer\u0026lt;?\u0026gt;) instance; List\u0026lt;Class\u0026lt;? extends Initializer\u0026lt;?\u0026gt;\u0026gt;\u0026gt; dependencies = initializer.dependencies(); if (!dependencies.isEmpty()) { for (Class\u0026lt;? extends Initializer\u0026lt;?\u0026gt;\u0026gt; clazz : dependencies) { if (!mInitialized.containsKey(clazz)) { doInitialize(clazz, initializing); } } } if (StartupLogger.DEBUG) { StartupLogger.i(String.format(\u0026#34;Initializing %s\u0026#34;, component.getName())); } result = initializer.create(mContext); if (StartupLogger.DEBUG) { StartupLogger.i(String.format(\u0026#34;Initialized %s\u0026#34;, component.getName())); } initializing.remove(component); mInitialized.put(component, result); } catch (Throwable throwable) { throw new StartupException(throwable); } } else { result = mInitialized.get(component); } return (T) result; } finally { Trace.endSection(); } } } 从这个方法中可以看到这里面的逻辑是\n 判断是否有依赖，如果有首先创建依赖，并且调用create 如果没有则创建当前的实例，并且调用create 判断去重，避免重复创建。  不自动加载组件的逻辑 #  AppInitializer.getInstance(context) .initializeComponent(ExampleLoggerInitializer.class); ###### public \u0026lt;T\u0026gt; T initializeComponent(@NonNull Class\u0026lt;? extends Initializer\u0026lt;T\u0026gt;\u0026gt; component) { return doInitialize(component, new HashSet\u0026lt;Class\u0026lt;?\u0026gt;\u0026gt;()); } 这里的逻辑就是不自动冲xml中读取自动创建， 改为手动调用doInitialize ，内部逻辑是一样。 是不是很简单。\n总结 #  结合content provider的特性，我们很容易可以知道 这些创建的组件调用u会在 application 的oncreatae之前调用，但是content provider的oncreate 也是在主线程调用，还是会占用主线程的资源。 综合来说，startup还是以解偶 启动流程，规范化启动流程为主。而独立模块化的启动组件，也方便各个击破地提高我们的启动速度。\n"});index.add({'id':75,'href':'/docs/arch/design_pattern/DecoratorPattern/','title':"装饰器模式",'section':"设计模式",'content':"装饰器模式 #  设计模式总体介绍 #  参考文档： #  装饰器模式（Decorator Pattern）允许向一个现有的对象添加新的功能，同时又不改变其结构。这种类型的设计模式属于结构型模式，它是作为现有的类的一个包装。 这种模式创建了一个装饰类，用来包装原有的类，并在保持类方法签名完整性的前提下，提供了额外的功能。\n意图：动态地给一个对象添加一些额外的职责。就增加功能来说，装饰器模式相比生成子类更为灵活。\n主要解决：一般的，我们为了扩展一个类经常使用继承方式实现，由于继承为类引入静态特征，并且随着扩展功能的增多，子类会很膨胀。\n何时使用：在不想增加很多子类的情况下扩展类。\n如何解决：将具体功能职责划分，同时继承装饰者模式。\n关键代码： 1、Component 类充当抽象角色，不应该具体实现。 2、修饰类引用和继承 Component 类，具体扩展类重写父类方法。\n应用实例： 1、孙悟空有 72 变，当他变成\u0026quot;庙宇\u0026quot;后，他的根本还是一只猴子，但是他又有了庙宇的功能。 2、不论一幅画有没有画框都可以挂在墙上，但是通常都是有画框的，并且实际上是画框被挂在墙上。在挂在墙上之前，画可以被蒙上玻璃，装到框子里；这时画、玻璃和画框形成了一个物体。\n优点：装饰类和被装饰类可以独立发展，不会相互耦合，装饰模式是继承的一个替代模式，装饰模式可以动态扩展一个实现类的功能。\n缺点：多层装饰比较复杂。\n使用场景： 1、扩展一个类的功能。 2、动态增加功能，动态撤销。\n注意事项：可代替继承。\n我们的介绍 #  为了 在保持方法签名完整的前提下，提供了额外的功能，进而设计的一种模式。通过注入不同的具体装饰类，来实现功能的动态添加或删除。 主要是为了避免继承所带来的子类膨胀化。可以使功能的添加或删除更灵活动态。\n举个现有的栗子 #    其他例子：Java 中的 Stream\n android Context中的装饰者模式（变种装饰类）\n mermaid.initialize({ \"flowchart\": { \"useMaxWidth\":true }, \"theme\": \"default\" } ) classDiagram Context 该模式的子模块以及详解 #   Component 抽象组件：栗子中的（Context） ConcreteComponent 具体组件：栗子中的（ContextImpl、MockContext） Decorator 抽象装饰类：栗子中的（ContextWrapper） ConcreteDecorator 具体装饰类：（Application、Activity、Service）  允许向一个现有的对象（Context），又不修改他的结构， 添加一个新功能。这种模式创建了一个装饰类（ContextWrapper），用来包装原有的类（ContextImpl），并且在 保持类方法签名完整的情况下，添加了新功能。\n"});})();